-- Poems batch 33
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('cd937294-eecd-48b6-8227-5b08a6cd7e26','送秦鍊師歸岑公山','李羣玉','唐','唐诗','tang','','[]','紫泥飛詔下金鑾，列象分明世仰觀。',64,'全唐诗/poet.tang.31000.json','["紫泥飛詔下金鑾，列象分明世仰觀。", "北省諫書藏舊草，南宮郎署握新蘭。", "春歸鳳沼恩波暖，曉入鴛行瑞氣寒。", "偏是此生棲息者，滿衣零淚一時乾。"]'),
('4baf12f7-1ea4-4604-a08d-11fd7d2839cc','潯陽觀水','李羣玉','唐','唐诗','tang','','[]','朝宗漢水接陽臺，唅呀填坑吼作雷。',64,'全唐诗/poet.tang.31000.json','["朝宗漢水接陽臺，唅呀填坑吼作雷。", "莫見九江平穩去，還從三峽嶮巇來。", "南經夢澤寬浮日，西出岷山劣泛盃。", "直至滄溟涵貯盡，深沈不動浸昭回。"]'),
('8a222a87-220e-4be0-881b-dd2695fcba14','謫仙吟贈趙道士','李羣玉','唐','唐诗','tang','','[]','汗漫東遊黃鶴雛，縉雲仙子住清都。',64,'全唐诗/poet.tang.31000.json','["汗漫東遊黃鶴雛，縉雲仙子住清都。", "三元麟鳳推高座，六甲風雷閟小壺。", "日月暗資靈壽藥，山河直擬化生符。", "若爲失意居蓬島，鼇足塵飛桑樹枯。"]'),
('6824739f-7e79-4d97-a371-8f29efe5b481','長沙陪裴大夫夜讌','李羣玉','唐','唐诗','tang','','[]','東山夜讌酒成河，銀燭熒煌照綺羅。',64,'全唐诗/poet.tang.31000.json','["東山夜讌酒成河，銀燭熒煌照綺羅。", "四面雨聲籠笑語，滿堂香氣泛笙歌。", "泠泠玉漏初三滴，灩灩金觴已半酡。", "共向柏臺窺雅量，澄陂萬頃見天和。"]'),
('88c87eb3-db03-4964-a90e-409d03f19031','寶劍','李羣玉','唐','唐诗','tang','','[]','雷煥豐城掘劍池，年深事遠跡依稀。',64,'全唐诗/poet.tang.31000.json','["雷煥豐城掘劍池，年深事遠跡依稀。", "泥沙難掩衝天氣，風雨終思發匣時。", "夜電尚搖池底影，秋蓮空吐鍔邊輝。", "自從星坼中台後，化作雙龍去不歸。"]'),
('7411d647-6070-4373-a7fb-2939d83d830e','人日梅花病中作','李羣玉','唐','唐诗','tang','','[]','去年今日湘南寺，獨把寒梅愁斷腸。',96,'全唐诗/poet.tang.31000.json','["去年今日湘南寺，獨把寒梅愁斷腸。", "今年此日江邊宅，臥見瓊枝低壓墻。", "半落半開臨野岸，團情團思醉韶光。", "玉鱗寂寂飛斜月，素豔亭亭對夕陽。", "已被兒童苦攀折，更遭風雨損馨香。", "洛陽桃李漸撩亂，回首行宮春景長。"]'),
('739004c3-d104-42d6-8880-df4b1e06846f','靜夜相思','李羣玉','唐','唐诗','tang','','[]','山空天籟寂，水榭延輕涼。',24,'全唐诗/poet.tang.31000.json','["山空天籟寂，水榭延輕涼。", "浪定一浦月，藕花閑自香。"]'),
('f5d16486-05b0-4e9b-8720-278020308c16','桂州經佳人故居','李羣玉','唐','唐诗','tang','','[]','桂水依舊綠，佳人本不還。',24,'全唐诗/poet.tang.31000.json','["桂水依舊綠，佳人本不還。", "秖應隨暮雨，飛入九疑山。"]'),
('9d9913da-8d22-4c4c-960a-f7aaad7b5876','放魚','李羣玉','唐','唐诗','tang','','[]','早覓爲龍去，江湖莫漫遊。',24,'全唐诗/poet.tang.31000.json','["早覓爲龍去，江湖莫漫遊。", "須知香餌下，觸口是銛鉤。"]'),
('72cbfe88-6a41-4893-b31a-7c10562da7cb','蓮葉','李羣玉','唐','唐诗','tang','','[]','根是泥中玉，心承露下珠。',24,'全唐诗/poet.tang.31000.json','["根是泥中玉，心承露下珠。", "在君塘下種，埋沒任春蒲。"]'),
('d99fa5d6-52e1-4439-a71b-0996478b330d','客愁二首 一','李羣玉','唐','唐诗','tang','','[]','客愁看柳色，日日逐春深。',24,'全唐诗/poet.tang.31000.json','["客愁看柳色，日日逐春深。", "蕩漾春風起，誰知歷亂心。"]'),
('83f3599b-d26e-4302-acfd-9207b1cbdd14','客愁二首 二','李羣玉','唐','唐诗','tang','','[]','客愁看柳色，日日逐春長。',24,'全唐诗/poet.tang.31000.json','["客愁看柳色，日日逐春長。", "憑送湘流水，綿綿入帝鄉。"]'),
('f6b1b9de-b8e3-4496-8df0-15d420a79b14','洞庭乾二首 一','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','借問蓬萊水，誰逢清淺年。',24,'全唐诗/poet.tang.31000.json','["借問蓬萊水，誰逢清淺年。", "傷心雲夢澤，歲歲作桑田。"]'),
('9f04d2d4-19e8-4852-b15e-aa22b75cbbd2','洞庭乾二首 二','李羣玉','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','朱宮紫貝闕，一旦作沙洲。',24,'全唐诗/poet.tang.31000.json','["朱宮紫貝闕，一旦作沙洲。", "八月還平在，魚蝦不用愁。"]'),
('ac15f80b-4920-42b5-a2c3-75b3b5f151ac','病起別主人','李羣玉','唐','唐诗','tang','','[]','益媿千金少，情將一飯殊。',24,'全唐诗/poet.tang.31000.json','["益媿千金少，情將一飯殊。", "恨無泉客淚，盡泣感恩珠。"]'),
('af7afa4e-f2b4-4640-9508-a6047cd9722a','火爐前坐','李羣玉','唐','唐诗','tang','','[]','孤燈照不寐，風雨滿西林。',24,'全唐诗/poet.tang.31000.json','["孤燈照不寐，風雨滿西林。", "多少關心事，書灰到夜深。"]'),
('10a04c72-d56f-49cf-93c6-0e2c12bb1889','古詞','李羣玉','唐','唐诗','tang','','[]','一合相思淚，臨江灑素秋。',24,'全唐诗/poet.tang.31000.json','["一合相思淚，臨江灑素秋。", "碧波如會意，却與向西流。"]'),
('d5214178-272b-46ae-8be6-ffc3d97a4b7d','嘲賣藥翁','李羣玉','唐','唐诗','tang','','[]','斸盡春山土，辛勤賣藥翁。',24,'全唐诗/poet.tang.31000.json','["斸盡春山土，辛勤賣藥翁。", "莫拋破笠子，留作敗天公。"]'),
('e385e12e-2e03-4a79-aa76-9d5e2f11d87d','傷小女癡兒','李羣玉','唐','唐诗','tang','','[]','哭爾春日短，支頤長歎嗟。',24,'全唐诗/poet.tang.31000.json','["哭爾春日短，支頤長歎嗟。", "不如半死樹，猶吐一枝花。"]'),
('46b87bce-9f05-43e0-8d63-acd775ee20b7','青鷁','李羣玉','唐','唐诗','tang','','[]','獨立蒹葭雨，低飛浦嶼風。',24,'全唐诗/poet.tang.31000.json','["獨立蒹葭雨，低飛浦嶼風。", "須知毛色下，莫入鷺鷥叢。"]'),
('ee747055-e56d-4714-be0e-6331269f8b19','池塘晚景','李羣玉','唐','唐诗','tang','','[]','風荷珠露傾，驚起睡鵁鶄。',24,'全唐诗/poet.tang.31000.json','["風荷珠露傾，驚起睡鵁鶄。", "月落池塘靜，金刀剪一聲。"]'),
('8fb9b5bd-ed67-462a-aede-f214dc819589','投從叔','李羣玉','唐','唐诗','tang','','[]','可惜出羣蹄，毛焦久臥泥。',24,'全唐诗/poet.tang.31000.json','["可惜出羣蹄，毛焦久臥泥。", "孫陽如不顧，騏驥向誰嘶。"]'),
('0771d642-80c9-4362-9bf3-e59cd9324ea0','惱自澄','李羣玉','唐','唐诗','tang','','[]','常聞天女會，玉指散天花。',24,'全唐诗/poet.tang.31000.json','["常聞天女會，玉指散天花。", "莫遣春風裏，紅芳點袈裟。"]'),
('fb2d3b1a-46ce-498c-a63d-7fd672448a5b','讀賈誼傳','李羣玉','唐','唐诗','tang','','[]','卑濕長沙地，空拋出世才。',24,'全唐诗/poet.tang.31000.json','["卑濕長沙地，空拋出世才。", "已齊生死理，服鳥莫爲災。"]'),
('8f57ac36-5458-49cc-8d9d-f1597e0c7f37','寄人','李羣玉','唐','唐诗','tang','','[]','寄語雙蓮子，須知用意深。',24,'全唐诗/poet.tang.31000.json','["寄語雙蓮子，須知用意深。", "莫嫌一點苦，便擬棄蓮心。"]'),
('07c1fba5-be51-4ef5-949a-c1712bd712be','寄韋秀才','李羣玉','唐','唐诗','tang','','[]','荆臺蘭渚客，寥落共含情。',24,'全唐诗/poet.tang.31000.json','["荆臺蘭渚客，寥落共含情。", "空館相思夜，孤燈照雨聲。"]'),
('766708a2-fc55-49f3-8cc5-9f8ef730b74a','春日寄友','李羣玉','唐','唐诗','tang','','[]','晴氣熏櫻蘂，丰濛雪滿林。',24,'全唐诗/poet.tang.31000.json','["晴氣熏櫻蘂，丰濛雪滿林。", "請君三斗酒，醉臥白羅岑。"]'),
('aaa3fdac-02c3-4b6f-8718-a400e27cbe7c','題竹','李羣玉','唐','唐诗','tang','','[]','一頃含秋綠，森風十萬竿。',24,'全唐诗/poet.tang.31000.json','["一頃含秋綠，森風十萬竿。", "氣吹朱夏轉，聲掃碧霄寒。"]'),
('e0936193-9114-4045-96e0-08db30333b89','懷初公','李羣玉','唐','唐诗','tang','','[]','不見休上人，空傷碧雲思。',24,'全唐诗/poet.tang.31000.json','["不見休上人，空傷碧雲思。", "何處開寶書，秋風海光寺。"]'),
('28bb464f-138f-4a2f-a9cf-880500a87b8f','龍安寺佳人阿最歌八首 一','李羣玉','唐','唐诗','tang','','[]','團團明月面，冉冉柳枝腰。',24,'全唐诗/poet.tang.31000.json','["團團明月面，冉冉柳枝腰。", "未入鴛鴦被，心長似火燒。"]'),
('bca7f346-2676-471e-8cbf-54ebd1e5bc69','龍安寺佳人阿最歌八首 二','李羣玉','唐','唐诗','tang','','[]','見面知何益，聞名憶轉深。',24,'全唐诗/poet.tang.31000.json','["見面知何益，聞名憶轉深。", "拳攣荷葉子，未得展蓮心。"]'),
('5d870d6a-5c6d-4d69-8d2f-2185d27d7823','龍安寺佳人阿最歌八首 三','李羣玉','唐','唐诗','tang','','[]','欲摘不得摘，如看波上花。',24,'全唐诗/poet.tang.31000.json','["欲摘不得摘，如看波上花。", "若敎親玉樹，情願作蒹葭。"]'),
('8d0e691d-fa6a-405d-97b3-b2df98d97781','龍安寺佳人阿最歌八首 四','李羣玉','唐','唐诗','tang','','[]','門路穿茶焙，房門映竹煙。',24,'全唐诗/poet.tang.31000.json','["門路穿茶焙，房門映竹煙。", "會須隨鹿女，乞火到窗前。"]'),
('7fa773e5-b506-488f-9af3-a44fa661548e','龍安寺佳人阿最歌八首 五','李羣玉','唐','唐诗','tang','','[]','不是求心印，都緣愛綠珠。',24,'全唐诗/poet.tang.31000.json','["不是求心印，都緣愛綠珠。", "何須同泰寺，然後始爲奴。"]'),
('3fb103e2-ffc8-46cf-abce-7c01b1914995','龍安寺佳人阿最歌八首 六','李羣玉','唐','唐诗','tang','','[]','既爲金界客，任改淨人名。',24,'全唐诗/poet.tang.31000.json','["既爲金界客，任改淨人名。", "願掃琉璃地，燒香過一生。"]'),
('d5af8d80-5f6d-4102-af34-a2a35c04a4d7','龍安寺佳人阿最歌八首 七','李羣玉','唐','唐诗','tang','','[]','素腕撩金索，輕紅約翠紗。',24,'全唐诗/poet.tang.31000.json','["素腕撩金索，輕紅約翠紗。", "不如欄下水，終日見桃花。"]'),
('05f17d75-b14d-4add-9665-f131f3b92360','龍安寺佳人阿最歌八首 八','李羣玉','唐','唐诗','tang','','[]','第一龍宮女，相憐是阿誰。',24,'全唐诗/poet.tang.31000.json','["第一龍宮女，相憐是阿誰。", "好魚輸獺盡，白鷺鎮長飢。"]'),
('c1e68a1e-2c93-44d9-bad8-bdc890570384','野鴨','李羣玉','唐','唐诗','tang','','[]','鸂鶒借毛衣，喧呼鷹隼稀。',24,'全唐诗/poet.tang.31000.json','["鸂鶒借毛衣，喧呼鷹隼稀。", "雲披菱藻地，任汝作羣飛。"]'),
('44eedc5c-b0c5-4759-a3d4-58fa27af680c','題二妃廟','李羣玉','唐','唐诗','tang','','[]','黃陵廟前春已空，子規啼血滴松風。',32,'全唐诗/poet.tang.31000.json','["黃陵廟前春已空，子規啼血滴松風。", "不知精爽歸何處，疑是行雲秋色中。"]'),
('adbaedb4-8f65-468c-9547-4bfa518e00ab','寄友二首 一','李羣玉','唐','唐诗','tang','','[]','野水晴山雪後時，獨行邨落更相思。',32,'全唐诗/poet.tang.31000.json','["野水晴山雪後時，獨行邨落更相思。", "無因一向溪頭醉，處處寒梅映酒旗。"]'),
('fea210a9-5e66-40e3-bbe4-8f9ad61ecad9','寄友二首 二','李羣玉','唐','唐诗','tang','','[]','花落輕寒酒熟遲，醉眠不及落花期。',32,'全唐诗/poet.tang.31000.json','["花落輕寒酒熟遲，醉眠不及落花期。", "愁人相憶春山暮，煙樹蒼蒼播穀時。"]'),
('cead8470-e404-4ef4-83b3-363b5a09d97d','桃源','李羣玉','唐','唐诗','tang','','[]','我到瞿真上升處，山川四望使人愁。',32,'全唐诗/poet.tang.31000.json','["我到瞿真上升處，山川四望使人愁。", "紫雲白鶴去不返，唯有桃花溪水流。"]'),
('bd8d0264-c581-4c1e-a36a-1b400f2c8b96','題王侍御宅','李羣玉','唐','唐诗','tang','','[]','門向滄江碧岫開，地多鷗鷺少塵埃。',32,'全唐诗/poet.tang.31000.json','["門向滄江碧岫開，地多鷗鷺少塵埃。", "綠陰十里灘聲裏，閑自王家看竹來。"]'),
('f789edfc-d0c8-4fc6-8ce2-303634a41b2b','聞湘南從叔朝覲','李羣玉','唐','唐诗','tang','','[]','長沙地窄卻回時，舟檝駸駸向鳳池。',32,'全唐诗/poet.tang.31000.json','["長沙地窄卻回時，舟檝駸駸向鳳池。", "爲報湘川神女道，莫敎雲雨濕旌旗。"]'),
('d4d3006b-209d-4b08-81ab-6b0d1fe78356','漢陽太白樓','李羣玉','唐','唐诗','tang','','[]','江上層樓翠靄間，滿簾春水滿窗山。',32,'全唐诗/poet.tang.31000.json','["江上層樓翠靄間，滿簾春水滿窗山。", "青楓綠草將愁去，遠入吳雲暝不還。"]'),
('19e1d2fe-25f0-468c-a99d-3676b0e85b7b','送客','李羣玉','唐','唐诗','tang','','[]','沅水羅文海燕回，柳條牽恨到荆臺。',32,'全唐诗/poet.tang.31000.json','["沅水羅文海燕回，柳條牽恨到荆臺。", "定知行路春愁裏，故郢城邊見落梅。"]'),
('c617ef23-009a-4afd-93af-9cfb04a308bc','醴陵道中','李羣玉','唐','唐诗','tang','','[]','別酒離亭十里強，半醒半醉引愁長。',32,'全唐诗/poet.tang.31000.json','["別酒離亭十里強，半醒半醉引愁長。", "無端寂寂春山路，雪打溪梅狼籍香。"]'),
('7ba6e44a-1e34-4636-96c2-7811995f33c8','校書叔遺暑服','李羣玉','唐','唐诗','tang','','[]','翠雲箱裏疊樬櫳，楚葛湘紗淨似空。',32,'全唐诗/poet.tang.31000.json','["翠雲箱裏疊樬櫳，楚葛湘紗淨似空。", "便著清江明月夜，輕涼與挂一身風。"]'),
