('bc79dedd-27d1-492a-bdc6-9bc4216502df','勸人廬山讀書','李羣玉','唐','唐诗','tang','','["\u5e90\u5c71"]','憐君少雋利如鋒，氣爽神清刻骨聰。',32,'全唐诗/poet.tang.31000.json','["憐君少雋利如鋒，氣爽神清刻骨聰。", "片玉若磨唯轉瑩，莫辭雲水入廬峰。"]'),
('d1ac0fdd-9aed-47f0-a20e-8d0351163b8f','言懷','李羣玉','唐','唐诗','tang','','[]','白鶴高飛不逐羣，嵇康琴酒鮑昭文。',32,'全唐诗/poet.tang.31000.json','["白鶴高飛不逐羣，嵇康琴酒鮑昭文。", "此身未有棲歸處，天下人間一片雲。"]'),
('fab4fec6-1b28-408f-af4e-e1f6add145d1','聞笛','李羣玉','唐','唐诗','tang','','[]','冉冉生山草何異，截而吹之動天地。',32,'全唐诗/poet.tang.31000.json','["冉冉生山草何異，截而吹之動天地。", "望鄉臺上望鄉時，不獨落梅兼落淚。"]'),
('4d45675d-2a28-4f84-9529-1467a01a3b1a','曉讌','李羣玉','唐','唐诗','tang','','[]','金波西傾銀漢落，綠樹含煙倚朱閣。',32,'全唐诗/poet.tang.31000.json','["金波西傾銀漢落，綠樹含煙倚朱閣。", "曉華朧𦝰聞調笙，一點殘燈隔羅幕。"]'),
('af881535-706e-4360-afc1-6fb96c6f8207','將遊荆州投魏中丞','李羣玉','唐','唐诗','tang','','[]','貧埋病壓老巑岏，拂拭菱花不喜看。',32,'全唐诗/poet.tang.31000.json','["貧埋病壓老巑岏，拂拭菱花不喜看。", "又恐無人肯青眼，事須憑仗小還丹。"]'),
('b1d0e493-7d09-4a82-a6a7-ab00c2e0504a','二辛夷','李羣玉','唐','唐诗','tang','','[]','狂吟亂舞雙白鶴，霜翎玉羽紛紛落。',32,'全唐诗/poet.tang.31000.json','["狂吟亂舞雙白鶴，霜翎玉羽紛紛落。", "空庭向晚春雨微，却斂寒香抱瑤萼。"]'),
('255ef1e3-d565-4f7f-bc9e-d9c0e8044747','題龍潭西齋','李羣玉','唐','唐诗','tang','','[]','寂寞幽齋暝煙起，滿徑西風落松子。',32,'全唐诗/poet.tang.31000.json','["寂寞幽齋暝煙起，滿徑西風落松子。", "遠公一去兜率宮，唯有面前虎溪水。"]'),
('c0ecdd7d-ee70-4a78-b723-a3227049a555','中秋寄南海梁侍御','李羣玉','唐','唐诗','tang','','[]','海靜天高景氣殊，鯨晴失彩蚌潛珠。',32,'全唐诗/poet.tang.31000.json','["海靜天高景氣殊，鯨晴失彩蚌潛珠。", "不知今夜越臺上，望見瀛洲方丈無。"]'),
('76ee291c-342b-4be9-8f7c-acbf3ab50f09','戲贈姬人','李羣玉','唐','唐诗','tang','','[]','骰子巡拋裹手拈，無因得見玉纖纖。',32,'全唐诗/poet.tang.31000.json','["骰子巡拋裹手拈，無因得見玉纖纖。", "但知謔道金釵落，圖向人前露指尖。"]'),
('bd2be2cf-de96-4c81-85fd-1bc41b535f83','大庾山嶺別友人','李羣玉','唐','唐诗','tang','','[]','篔簹無子鴛雛飢，毛彩凋摧不得歸。',32,'全唐诗/poet.tang.31000.json','["篔簹無子鴛雛飢，毛彩凋摧不得歸。", "誰念火雲千嶂裏，低身猶傍鷓鴣飛。"]'),
('2850efd7-f2ea-4bdf-867b-e3b6e2058500','石門戍','李羣玉','唐','唐诗','tang','','[]','到此空思吳隱之，潮痕草蔓上幽碑。',32,'全唐诗/poet.tang.31000.json','["到此空思吳隱之，潮痕草蔓上幽碑。", "人來皆望珠璣去，誰詠貪泉四句詩。"]'),
('0d8861fe-bc1e-41ec-a389-19700e369916','文殊院避暑','李羣玉','唐','唐诗','tang','','[]','赤日黃埃滿世間，松聲入耳即心閑。',32,'全唐诗/poet.tang.31000.json','["赤日黃埃滿世間，松聲入耳即心閑。", "願尋五百仙人去，一世清涼住雪山。"]'),
('51d544b4-79b1-47e4-bbab-24fe8a162607','南莊春晚二首 一','李羣玉','唐','唐诗','tang','','[]','連雲草映一條陂，鸂鶒雙雙帶水飛。',32,'全唐诗/poet.tang.31000.json','["連雲草映一條陂，鸂鶒雙雙帶水飛。", "南邨小路桃花落，細雨斜風獨自歸。"]'),
('70ab4197-b7c0-4e9c-b735-ece3e3c3e27d','南莊春晚二首 二','李羣玉','唐','唐诗','tang','','[]','草暖沙長望去舟，微茫煙浪向巴丘。',32,'全唐诗/poet.tang.31000.json','["草暖沙長望去舟，微茫煙浪向巴丘。", "沅江寂寂春歸盡，水綠蘋香人自愁。"]'),
('a4c96091-a834-43b8-b4a0-1a427c720e28','湘妃廟','李羣玉','唐','唐诗','tang','','[]','少將風月怨平湖，見盡扶桑水到枯。',32,'全唐诗/poet.tang.31000.json','["少將風月怨平湖，見盡扶桑水到枯。", "相約杏花壇上去，畫欄紅紫鬬樗蒲。"]'),
('5874f656-3ae8-4c95-8e4f-883f9ed24e1d','古意','賈島','唐','唐诗','tang','','[]','碌碌復碌碌，百年雙轉轂。',48,'全唐诗/poet.tang.31000.json','["碌碌復碌碌，百年雙轉轂。", "志士終夜心，良馬白日足。", "俱爲不等閑，誰是知音目。", "眼中兩行淚，曾弔三獻玉。"]'),
('6829baaa-cb45-4864-a26b-fb27b73b6e34','望山','賈島','唐','唐诗','tang','','["\u548f\u7269", "\u6292\u60c5", "\u63cf\u5199\u5c71", "\u548f\u7269\u8bd7", "\u5199\u5c71"]','南山三十里，不見踰一旬。',96,'全唐诗/poet.tang.31000.json','["南山三十里，不見踰一旬。", "冒雨時立望，望之如朋親。", "虬龍一掬波，洗蕩千萬春。", "日日雨不斷，愁殺望山人。", "天事不可長，勁風來如奔。", "陰霪一以掃，浩翠寫國門。", "長安百萬家，家家張屏新。", "誰家最好山，我願爲其鄰。"]'),
('e2020472-81e6-49ed-a08d-900b97932629','北嶽廟','賈島','唐','唐诗','tang','','["\u6052\u5c71"]','天地有五嶽，恒嶽居其北。',60,'全唐诗/poet.tang.31000.json','["天地有五嶽，恒嶽居其北。", "巖巒疊萬重，詭怪浩難測。", "人來不敢入，祠宇白日黑。", "有時起霖雨，一灑天地德。", "神兮安在哉，永康我王國。"]'),
('68ed6810-ae39-431b-bea7-ef0e053d9c1a','朝飢','賈島','唐','唐诗','tang','','[]','市中有樵山，此舍朝無煙。',60,'全唐诗/poet.tang.31000.json','["市中有樵山，此舍朝無煙。", "井底有甘泉，釜中乃空然。", "我要見白日，雪來塞青天。", "坐聞西牀琴，凍折兩三弦。", "飢莫詣他門，古人有拙言。"]'),
('82b5da8e-c04b-47b1-81e9-663364734624','哭盧仝','賈島','唐','唐诗','tang','','[]','賢人無官死，不親者亦悲。',108,'全唐诗/poet.tang.31000.json','["賢人無官死，不親者亦悲。", "空令古鬼哭，更得新鄰比。", "平生四十年，惟著白布衣。", "天子未辟召，地府誰來追。", "長安有交友，託孤遽棄移。", "塚側誌石短，文字行參差。", "無錢買松栽，自生蒿草枝。", "在日贈我文，淚流把讀時。", "從茲加敬重，深藏恐失遺。"]'),
('ef5f6c59-7460-402d-a2e6-fb8214ea5332','劍客','賈島','唐','唐诗','tang','','[]','十年磨一劍，霜刃未曾試。',24,'全唐诗/poet.tang.31000.json','["十年磨一劍，霜刃未曾試。", "今日把似君，誰爲不平事。"]'),
('372910ce-ef22-4847-b33e-0874e43f5cef','口號','賈島','唐','唐诗','tang','','[]','中夜忽自起，汲此百尺泉。',24,'全唐诗/poet.tang.31000.json','["中夜忽自起，汲此百尺泉。", "林木含白露，星斗在青天。"]'),
('23b57c5e-8bce-4540-ad71-3a36e5dec7e1','寄遠','賈島','唐','唐诗','tang','','[]','別腸多鬱紆，豈能肥肌膚。',96,'全唐诗/poet.tang.31000.json','["別腸多鬱紆，豈能肥肌膚。", "始知相結密，不及相結疎。", "疎別恨應少，密離恨難袪。", "門前南流水，中有北飛魚。", "魚飛向北海，可以寄遠書。", "不惜寄遠書，故人今在無。", "況此數尺身，阻彼萬里途。", "自非日月光，難以知子軀。"]'),
('f760d47a-e3b6-4519-94c6-08108c244783','齋中','賈島','唐','唐诗','tang','','[]','眈靜非謬爲，本性實疎索。',84,'全唐诗/poet.tang.31000.json','["眈靜非謬爲，本性實疎索。", "齋中一就枕，不覺白日落。", "低扉礙軒轡，寡德謝接諾。", "叢菊在牆陰，秋窮未開萼。", "所餐類病馬，動影似移嶽。", "欲駐迫逃衰，豈殊亂綆縛。", "已見飽時雨，應豐蔬與藥。"]'),
('16690f49-2754-48fa-8f6a-1212f1720f1b','感秋','賈島','唐','唐诗','tang','','[]','商氣颯已來，歲華又虛擲。',96,'全唐诗/poet.tang.31000.json','["商氣颯已來，歲華又虛擲。", "朝雲藏奇峰，暮雨灑疎滴。", "幾蜩嘿涼葉，數蛩思陰壁。", "落日空館中，歸心遠山碧。", "昔人多秋感，今人何異昔。", "四序馳百年，玄髮坐成白。", "喧喧徇聲利，擾擾同轍迹。", "儻無世上懷，去偃松下石。"]'),
('e785508d-0bf8-42c0-aa33-e6542a46894e','翫月','賈島','唐','唐诗','tang','','[]','寒月破東北，賈生立西南。',228,'全唐诗/poet.tang.31000.json','["寒月破東北，賈生立西南。", "西南立倚何，立倚青青杉。", "近月有數星，星名未詳諳。", "但愛杉倚月，我倚杉爲三。", "月乃不上杉，上杉難相參。", "眙𥈭子細視，睛瞳桂枝劖。", "目常有熱疾，久視無煩炎。", "以手捫衣裳，零露已濡霑。", "久立雙足凍，時向股䏶淹。", "立久病足折，兀然黐膠黏。", "他人應已睡，轉喜此景恬。", "此景亦胡及，而我苦淫耽。", "無異市井人，見金不知廉。", "不知此夜中，幾人同無厭。", "待得上頂看，未擬歸枕函。", "強步望寢齋，步步情不堪。", "步到竹叢西，東望如隔簾。", "却坐竹叢外，清思刮幽潛。", "量知愛月人，身願化爲蟾。"]'),
('18c0623d-3c84-4a97-ae20-5246611b1483','辭二知己','賈島','唐','唐诗','tang','','[]','一雙千歲鶴，立別孤翔鴻。',72,'全唐诗/poet.tang.31000.json','["一雙千歲鶴，立別孤翔鴻。", "波島忽已暮，海雨寒濛濛。", "離人聞美彈，亦與哀彈同。", "況茲切切弄，繞彼行行躬。", "雲飛北嶽碧，火息西山紅。", "何以代遠誠，折芳臘雪中。"]'),
('c60a6229-3bf1-400e-8b56-1d307998456d','義雀行和朱評事','賈島','唐','唐诗','tang','','["\u9ec4\u6cb3"]','玄鳥雄雌俱，春雷驚蟄餘。',84,'全唐诗/poet.tang.31000.json','["玄鳥雄雌俱，春雷驚蟄餘。", "口銜黃河泥，空即翔天隅。", "一夕皆莫歸，嘵嘵遺衆雛。", "雙雀抱仁義，哺食勞劬劬。", "雛既邐迤飛，雲間聲相呼。", "燕雀雖微類，感媿誠不殊。", "禽賢難自彰，幸得主人書。"]'),
('a07e44fe-2a73-40af-a53a-e735eb124928','宿懸泉驛','賈島','唐','唐诗','tang','','[]','曉行瀝水樓，暮到懸泉驛。',24,'全唐诗/poet.tang.31000.json','["曉行瀝水樓，暮到懸泉驛。", "林月值雲遮，山燈照愁寂。"]'),
('4399b22a-5a04-43fd-8113-952d04674b0f','辯士','賈島','唐','唐诗','tang','','[]','辯士多毀訾，不聞談己非。',60,'全唐诗/poet.tang.31000.json','["辯士多毀訾，不聞談己非。", "猛虎恣殺暴，未嘗齧妻兒。", "此理天所感，所感當問誰。", "求食飼雛禽，吐出美言詞。", "善哉君子人，揚光掩瑕玼。"]'),
('0ff43d2f-dc93-4f57-9e7b-8a323caed335','不欺','賈島','唐','唐诗','tang','','[]','上不欺星辰，下不欺鬼神。',60,'全唐诗/poet.tang.31000.json','["上不欺星辰，下不欺鬼神。", "知心兩如此，然後何所陳。", "食魚味在鮮，食蓼味在辛。", "掘井須到流，結交須到頭。", "此語誠不謬，敵君三萬秋。"]'),
('054711fb-3baf-435e-83aa-549d8b007e4d','絕句','賈島','唐','唐诗','tang','','[]','海底有明月，圓於天上輪。',24,'全唐诗/poet.tang.31000.json','["海底有明月，圓於天上輪。", "得之一寸光，可買千里春。"]'),
('4d804d6e-6b8d-420f-a6f4-77ea407f0921','寓興','賈島','唐','唐诗','tang','','[]','莫居暗室中，開目閉目同。',48,'全唐诗/poet.tang.31000.json','["莫居暗室中，開目閉目同。", "莫趨碧霄路，容飛不容步。", "暗室未可居，碧霄未可趨。", "勸君跨仙鶴，日下雲爲衢。"]'),
('d4788fcc-0b63-4571-9b26-8d44760906ac','遊仙','賈島','唐','唐诗','tang','','[]','借得孤鶴騎，高近金烏飛。',60,'全唐诗/poet.tang.31000.json','["借得孤鶴騎，高近金烏飛。", "掬河洗老貌，照月生光輝。", "天中鶴路直，天盡鶴一息。", "歸來不騎鶴，身自有羽翼。", "若人無仙骨，芝朮徒煩食。"]'),
('d3be4f4c-15ed-4f6e-bc54-2a01224d69e6','枕上吟','賈島','唐','唐诗','tang','','[]','夜長憶白日，枕上吟千詩。',36,'全唐诗/poet.tang.31000.json','["夜長憶白日，枕上吟千詩。", "何當苦寒氣，忽被東風吹。", "冰開魚龍別，天波殊路岐。"]'),
('6bc2bc36-c403-417a-8c3a-bbc37ecd73e1','雙魚謠','賈島','唐','唐诗','tang','','[]','天河墮雙魴，飛我庭中央。',48,'全唐诗/poet.tang.31000.json','["天河墮雙魴，飛我庭中央。", "掌握尺餘雪，劈開腸有璜。", "見令饞舌短，烹遶鄰舍香。", "一得古詩字，與玉含異藏。"]'),
('d0a83246-7f4c-4814-8775-19c704132fa9','易水懷古','賈島','唐','唐诗','tang','','[]','荆卿重虛死，節烈書前史。',48,'全唐诗/poet.tang.31000.json','["荆卿重虛死，節烈書前史。", "我歎方寸心，誰論一時事。", "至今易水橋，寒風兮蕭蕭。", "易水流得盡，荆卿名不消。"]'),
('fe2946f9-e59c-4f30-8dba-1cfbc3608040','早起','賈島','唐','唐诗','tang','','[]','北客入西京，北鴈再離北。',72,'全唐诗/poet.tang.31000.json','["北客入西京，北鴈再離北。", "秋寢獨前興，天梭星落織。", "耽翫餘恬爽，顧盼輕痾力。", "旅途少顏盡，明鏡勸仙食。", "出門路縱橫，張家路最直。", "昨夜夢見書，張家廳上壁。"]'),
('b064ae34-c624-432b-8860-19fbb721b895','客喜','賈島','唐','唐诗','tang','','[]','客喜非實喜，客悲非實悲。',72,'全唐诗/poet.tang.31000.json','["客喜非實喜，客悲非實悲。", "百迴信到家，未當身一歸。", "未歸長嗟愁，嗟愁填中懷。", "開口吐愁聲，還却入耳來。", "常恐淚滴多，自損兩目輝。", "鬢邊雖有絲，不堪織寒衣。"]'),
('e4375fad-c184-471a-a680-192fb44c6c7b','延壽里精舍寓居','賈島','唐','唐诗','tang','','[]','旅託避華館，荒樓遂愚慵。',84,'全唐诗/poet.tang.31000.json','["旅託避華館，荒樓遂愚慵。", "短庭無繁植，珍果春亦濃。", "側廬廢扃樞，纖魄時臥逢。", "耳目乃鄽井，肺肝即巖峰。", "汲泉飲酌餘，見我閑靜容。", "霜蹊猶舒英，寒蝶斷來踪。", "雙履與誰逐，一尋青瘦筇。"]'),
('9dba77fb-923f-404d-af54-fe891d8bb01a','贈智朗禪師','賈島','唐','唐诗','tang','','[]','上人分明見，玉兔潭底沒。',84,'全唐诗/poet.tang.31000.json','["上人分明見，玉兔潭底沒。", "上人光慘貌，古來恨峭發。", "涕辭孔顏廟，笑訪禪寂室。", "步隨青山影，坐學白塔骨。", "解聽無弄琴，不禮有身佛。", "欲問師何之，忽與我相別。", "率賦贈遠言，言慙非子曰。"]'),
('3d58e148-6a3d-4502-b039-d4a7a5d7fdff','送沈秀才下第東歸','賈島','唐','唐诗','tang','','[]','曲言惡者誰，悅耳如彈絲。',108,'全唐诗/poet.tang.31000.json','["曲言惡者誰，悅耳如彈絲。", "直言好者誰，刺耳如長錐。", "沈生才俊秀，心腸無邪欺。", "君子忌苟合，擇交如求師。", "毀出疾夫口，騰入禮部闈。", "下第子不恥，遺才人恥之。", "東歸家室遠，掉轡時參差。", "浙雲近吳見，汴柳接楚垂。", "明年春光別，回首不復疑。"]'),
('d5be80e6-185d-4338-a834-976dfb2f5f47','酬棲上人','賈島','唐','唐诗','tang','','[]','夜久城館閑，情幽出在山。',72,'全唐诗/poet.tang.31000.json','["夜久城館閑，情幽出在山。", "新月有微輝，朗朗空庭間。", "處世雖識機，伊余多掩關。", "松姿度臘見，籬藥知春還。", "靜覽冰雪詞，厚爲酬贈顏。", "東林有躑躅，脫屣期共攀。"]'),
('2204bcb6-175b-46ba-a5f1-60e7e86f526d','冬月長安雨中見終南雪','賈島','唐','唐诗','tang','','[]','秋節新已盡，雨疎露山雪。',60,'全唐诗/poet.tang.31000.json','["秋節新已盡，雨疎露山雪。", "西峰稍覺明，殘滴猶未絕。", "氣侵瀑布水，凍著白雲穴。", "今朝灞滻鴈，何夕瀟湘月。", "想彼石房人，對雪扉不閉。"]'),
('12e1e859-e9f2-4aa8-b5b0-6625e5085283','寄孟協律','賈島','唐','唐诗','tang','','[]','我有弔古泣，不泣向路岐。',84,'全唐诗/poet.tang.31000.json','["我有弔古泣，不泣向路岐。", "揮淚灑暮天，滴著桂樹枝。", "別後冬節至，離心北風吹。", "坐孤雪扉夕，泉落石橋時。", "不驚猛虎嘯，難辱君子詞。", "欲酬空覺老，無以堪遠持。", "岧嶤倚角窗，王屋懸清思。"]'),
('5cd16646-c3ab-4c85-a297-53c2706d4d58','和劉涵','賈島','唐','唐诗','tang','','[]','京官始云滿，野人依舊閑。',84,'全唐诗/poet.tang.31000.json','["京官始云滿，野人依舊閑。", "閉扉一畝居，中有古風還。", "市井日已午，幽窗夢南山。", "喬木覆北齋，有鳥鳴其間。", "前日遠嶽僧，來時與開關。", "新題驚我瘦，窺鏡見醜顏。", "陶情惜清澹，此意復誰攀。"]'),
('9e9c2fe8-a393-40f1-9f7c-2f4e95d4f5a9','明月山懷獨孤崇魚琢','賈島','唐','唐诗','tang','','[]','明月長在目，明月長在心。',108,'全唐诗/poet.tang.31000.json','["明月長在目，明月長在心。", "在心復在目，何得稀去尋。", "試望明月人，孟夏樹蔽岑。", "想彼嘆此懷，樂喧忘幽林。", "鄉本北嶽外，悔恨東夷深。", "願縮地脈還，豈待天恩臨。", "非不渴隱秀，却嫌他事侵。", "或云岳樓鐘，來繞草堂吟。", "當從令伊後，再往步柏林。"]'),
('78d98cda-00dd-48ca-b377-4dccad7e184f','投張太祝','賈島','唐','唐诗','tang','','[]','風骨高更老，向春初陽葩。',98,'全唐诗/poet.tang.31000.json','["風骨高更老，向春初陽葩。", "[泠泠]月下韻，一一落海涯。", "有子不敢和，一聽千嘆嗟。", "身臥東北泥，魂挂西南霞。", "手把一枝栗，往輕覺程賒。", "水天朔方色，暖日嵩根花。", "達閑幽棲山，遣尋種藥家。", "欲買雙瓊瑤，慙無一木瓜。"]'),
('958692bc-c547-4dbb-b773-912121e27a7f','詠韓氏二子','賈島','唐','唐诗','tang','','[]','千巖一尺璧，八月十五夕。',24,'全唐诗/poet.tang.31000.json','["千巖一尺璧，八月十五夕。", "清露墮桂花，白鳥舞虛碧。"]'),
('29474401-25a5-4f15-8f30-bd1bbc899557','送別','賈島','唐','唐诗','tang','','[]','丈夫未得意，行行且低眉。',24,'全唐诗/poet.tang.31000.json','["丈夫未得意，行行且低眉。", "素琴彈復彈，會有知音知。"]'),
('1cfd0726-3105-41c1-ab25-aef335f3a82a','攜新文詣張籍韓愈途中成','賈島','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','袖有新成詩，欲見張韓老。',72,'全唐诗/poet.tang.31000.json','["袖有新成詩，欲見張韓老。", "青竹未生翼，一步萬里道。", "仰望青冥天，雲雪壓我腦。", "失却終南山，惆悵滿懷抱。", "安得西北風，身願變蓬草。", "地祇聞此語，突出驚我倒。"]'),
('2498e5d9-766c-4015-8cb9-5883cd6b143e','上谷送客遊江湖','賈島','唐','唐诗','tang','','[]','莫歎迢遰分，何殊咫尺別。',24,'全唐诗/poet.tang.31000.json','["莫歎迢遰分，何殊咫尺別。", "江樓到夜登，還見南臺月。"]'),
('a2624bfa-bfb4-4294-bdab-e5054184bee9','重酬姚少府','賈島','唐','唐诗','tang','','[]','隙月斜枕旁，諷詠夏貽什。',144,'全唐诗/poet.tang.31000.json','["隙月斜枕旁，諷詠夏貽什。", "如今何時節，蟲虺亦已蟄。", "答遲禮涉傲，抱疾思加澀。", "僕本胡爲者，銜肩貢客集。", "茫然九州內，譬如一錐立。", "欺暗少此懷，自明曾瀝泣。", "量無趫勇士，誠欲戈矛戢。", "原閣期躋攀，潭舫偶俱入。", "深齋竹木合，畢夕風雨急。", "俸利沐均分，價稱煩噓噏。", "百篇見刪罷，一命嗟未及。", "滄浪愚將還，知音激所習。"]'),
('b76e800b-6bd5-433a-9384-edbfb139d31e','投孟郊','賈島','唐','唐诗','tang','','[]','月中有孤芳，天下聆薰風。',192,'全唐诗/poet.tang.31000.json','["月中有孤芳，天下聆薰風。", "江南有高唱，海北初來通。", "容飄清冷餘，自蘊襟抱中。", "止息乃流溢，推尋却冥濛。", "我知雪山子，謁彼偈句空。", "必竟獲所實，爾焉遂深衷。", "錄之孤燈前，猶恨百首終。", "一吟動狂機，萬疾辭頑躬。", "生平面未交，永夕夢輒同。", "敘詰誰君師，詎言無吾宗。", "余求履其跡，君曰可但攻。", "啜波腸易飽，揖險神難從。", "前歲曾入洛，差池阻從龍。", "萍家復從趙，雲思長縈縈。", "嵩海每可詣，長途追再窮。", "願傾肺腸事，盡入焦梧桐。"]'),
('7105487f-ef6b-465d-913f-97f57b5e45e8','代邊將','賈島','唐','唐诗','tang','','[]','持戈簇邊日，戰罷浮雲收。',48,'全唐诗/poet.tang.31000.json','["持戈簇邊日，戰罷浮雲收。", "露草泣寒霽，夜泉鳴隴頭。", "三尺握中鐵，氣衝星斗牛。", "報國不拘貴，憤將平虜讎。"]'),
('944615b0-d7de-4fc2-bb6d-49236d59de4e','寄劉棲楚','賈島','唐','唐诗','tang','','[]','趨走與偃臥，去就自殊分。',72,'全唐诗/poet.tang.31000.json','["趨走與偃臥，去就自殊分。", "當窗一重樹，上有萬里雲。", "離披不相顧，髣髴類人羣。", "友生去更遠，來書絕如焚。", "蟬吟我爲聽，我歌蟬豈聞。", "歲暮儻旋歸，晤言桂氛氳。"]'),
('30c5344b-c451-4045-9051-ef99599bc78e','寄丘儒','賈島','唐','唐诗','tang','','[]','地近輕數見，地遠重一面。',96,'全唐诗/poet.tang.31000.json','["地近輕數見，地遠重一面。", "一面如何重，重甚珍寶片。", "自經失歡笑，幾度騰霜霰。", "此心鎮懸懸，天象固迴轉。", "長安秋風高，子在東甸縣。", "儀形信寂蔑，風雨豈乖間。", "憑人報消息，何易憑筆硯。", "俱不盡我心，終須對君宴。"]'),
('3cd115ca-3719-420a-b44c-f7f48505ae30','送陳商','賈島','唐','唐诗','tang','','[]','古道長荆棘，新岐路交橫。',96,'全唐诗/poet.tang.31000.json','["古道長荆棘，新岐路交橫。", "君於荒榛中，尋得古轍行。", "足踏聖人路，貌端禪士形。", "我曾接夜談，似聽講一經。", "聯翩曾數舉，昨登高第名。", "釜底絕煙火，曉行皇帝京。", "上客遠府遊，主人須目明。", "青雲別青山，何日復可升。"]'),
('997c1a22-0cda-46b8-914e-f3cee4341d1a','送張校書季霞','賈島','唐','唐诗','tang','','[]','從京去容州，馬在船上多。',108,'全唐诗/poet.tang.31000.json','["從京去容州，馬在船上多。", "容州幾千里，直傍青天涯。", "掌記試校書，未稱高詞華。", "義往不可屈，出家如入家。", "城市七月初，熱與夏未差。", "餞君到野地，秋涼滿山坡。", "南境異北候，風起無塵沙。", "秦吟宿楚澤，海酒落桂花。", "暫醉即還醒，彼土生桂茶。"]'),
('e19a7c36-f220-4788-88b4-6ddb93d4414a','寄友人','賈島','唐','唐诗','tang','','[]','同人半年別，一別寂來音。',72,'全唐诗/poet.tang.31000.json','["同人半年別，一別寂來音。", "賴有別時文，相思時一吟。", "我常倦投跡，君亦知此衿。", "筆硯且勿棄，蘇張曾陸沈。", "但存舌在口，當冀身遂心。", "君看明月夜，松桂寒森森。"]'),
('039ffb7a-91b1-4ec7-965f-104fb9b217da','答王參','賈島','唐','唐诗','tang','','[]','寸晷不相待，四時互如競。',72,'全唐诗/poet.tang.31000.json','["寸晷不相待，四時互如競。", "客思先覺秋，蟲聲苦知暝。", "霜松積舊翠，露月團如鏡。", "詩負屬景同，琴孤坐堂聽。", "相期黃菊節，別約紅桃徑。", "每把式微篇，臨風一長詠。"]'),
('efbe4455-a579-48b3-83b6-bf4260a904c5','延康吟','賈島','唐','唐诗','tang','','[]','寄居延壽里，爲與延康鄰。',48,'全唐诗/poet.tang.31000.json','["寄居延壽里，爲與延康鄰。", "不愛延康里，愛此里中人。", "人非十年故，人非九族親。", "人有不朽語，得之煙山春。"]'),
('90ee4e7c-bff8-4c8e-98e8-1e5daa0f5797','戲贈友人','賈島','唐','唐诗','tang','','[]','一日不作詩，心源如廢井。',50,'全唐诗/poet.tang.31000.json','["一日不作詩，心源如廢井。", "筆硯爲轆轤，吟詠作縻綆。", "朝來重汲引，依舊得清[冷]。", "書贈同懷人，詞中多苦辛。"]'),
('070c4620-5a89-4fb0-86c4-548df280b9f6','寓興','賈島','唐','唐诗','tang','','[]','真集道方至，貌殊妬還多。',96,'全唐诗/poet.tang.31000.json','["真集道方至，貌殊妬還多。", "山泉入城池，自然生渾波。", "今時出古言，在衆翻爲訛。", "有琴含正韻，知音者如何。", "一生足感激，世言忽嵯峨。", "不得市井味，思響吾巖阿。", "浮華豈我事，日月徒蹉跎。", "曠哉潁陽風，千載無其他。"]'),
('5eb962dd-8122-42d4-bf21-2f02542a1f85','懷鄭從志','賈島','唐','唐诗','tang','','[]','西風吹陰雲，雨雪半夜收。',72,'全唐诗/poet.tang.31000.json','["西風吹陰雲，雨雪半夜收。", "忽憶天涯人，起看斗與牛。", "故人別二年，我意如百秋。", "音信兩杳杳，誰云昔綢繆。", "平明一封書，寄向東北舟。", "翩翩春歸鳥，會自爲匹儔。"]'),
('2177b201-7397-4ea2-b7da-fb81d844ea4d','易州登龍興寺樓望郡北高峰','賈島','唐','唐诗','tang','','[]','郡北最高峰，巉巖絕雲路。',48,'全唐诗/poet.tang.31000.json','["郡北最高峰，巉巖絕雲路。", "朝來上樓望，稍覺得幽趣。", "朦朧碧煙裏，羣嶺若相附。", "何時一登陟，萬物皆下顧。"]'),
('0fcd232e-4138-41fc-a236-4ccc563e6655','送鄭山人遊江湖','賈島','唐','唐诗','tang','','[]','南遊衡嶽上，東往天台裏。',24,'全唐诗/poet.tang.31000.json','["南遊衡嶽上，東往天台裏。", "足躡華頂峰，目觀滄海水。"]'),
('b600f2d2-8c3f-4499-9406-173baa538e6d','就峰公宿','賈島','唐','唐诗','tang','','[]','河出鳥宿後，螢火白露中。',48,'全唐诗/poet.tang.31000.json','["河出鳥宿後，螢火白露中。", "上人坐不倚，共我論量空。", "殘月華晻曖，遠水響玲瓏。", "爾時無了夢，茲宵方未窮。"]'),
('5f5dd2d2-6572-483d-94b1-166ef926ec96','劉景陽東齋','賈島','唐','唐诗','tang','','[]','松陰連竹影，中有蕪苔井。',48,'全唐诗/poet.tang.31000.json','["松陰連竹影，中有蕪苔井。", "清風此地多，白日空自永。", "景陽公幹孫，詩句得真景。", "勸我不須歸，月出東齋靜。"]'),
('a6718251-5934-4db9-ae50-edf26f8b0ea8','對菊','賈島','唐','唐诗','tang','','[]','九日不出門，十日見黃菊。',24,'全唐诗/poet.tang.31000.json','["九日不出門，十日見黃菊。", "灼灼尚繁英，美人無消息。"]'),
('9dfdc12c-f5ab-4677-9af5-30a800451058','送集文上人遊方','賈島','唐','唐诗','tang','','[]','來從道陵井，雙木溪邊會。',36,'全唐诗/poet.tang.31000.json','["來從道陵井，雙木溪邊會。", "分首芳草時，遠意青天外。", "此遊詣幾嶽，嵩華衡恒泰。"]'),
('ef56cd70-b969-45d4-87fd-520c076bb796','題岸上人郡內閑居','賈島','唐','唐诗','tang','','[]','靜向方寸求，不居山嶂幽。',60,'全唐诗/poet.tang.31000.json','["靜向方寸求，不居山嶂幽。", "池開菡萏香，門閉莓苔秋。", "金玉重四句，粃糠輕九流。", "鑪煙上喬木，鐘磬下危樓。", "手種一株松，貞心與師儔。"]'),
('4a7074e5-711f-4cd2-b687-fe64aefeea06','遊子','賈島','唐','唐诗','tang','','[]','遊子喜鄉遠，非吾憶歸廬。',48,'全唐诗/poet.tang.31000.json','["遊子喜鄉遠，非吾憶歸廬。", "誰知奔他山，自欲早旋車。", "朝賞暮已足，圖歸願無餘。", "當期附鵬翼，未偶方躊躇。"]'),
('938a360a-c268-446c-a15c-ca5711218465','寄山中王參','賈島','唐','唐诗','tang','','[]','我看嶽西雲，君看嶽北月。',48,'全唐诗/poet.tang.31000.json','["我看嶽西雲，君看嶽北月。", "長懷燕城南，相送十里別。", "別來千餘日，日日憶不歇。", "遠寄一紙書，數字論白髮。"]'),
('68829c20-1e3c-4ae7-8238-15237574912a','送汲鵬','賈島','唐','唐诗','tang','','[]','淮南臥理後，復逢君姓汲。',48,'全唐诗/poet.tang.31000.json','["淮南臥理後，復逢君姓汲。", "文采非尋常，志願期卓立。", "深江東泛舟，夕陽眺原隰。", "夏夜言詩會，往往追不及。"]'),
('a0cf3541-5073-4f4f-917f-9a0a67b75566','寄令狐相公','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','策杖馳山驛，逢人問梓州。',24,'全唐诗/poet.tang.31000.json','["策杖馳山驛，逢人問梓州。", "長江那可到，行客替生愁。"]'),
('38a5fd17-055c-404e-8ac0-1aa49efcfc15','哭柏巖和尚','賈島','唐','唐诗','tang','','[]','苔覆石床新，師曾占幾春。',48,'全唐诗/poet.tang.31000.json','["苔覆石床新，師曾占幾春。", "寫留行道影，焚却坐禪身。", "塔院關松雪，經房鎖隙塵。", "自嫌雙淚下，不是解空人。"]'),
('545013fe-bf41-4ae5-aa62-74e0c42db6c9','山中道士','賈島','唐','唐诗','tang','','[]','頭髮梳千下，休糧帶瘦容。',48,'全唐诗/poet.tang.31000.json','["頭髮梳千下，休糧帶瘦容。", "養雛成大鶴，種子作高松。", "白石通宵煮，寒泉盡日舂。", "不曾離隱處，那得世人逢。"]'),
('b78fb422-a1bc-4c84-a1fa-30da6ebd6290','就可公宿','賈島','唐','唐诗','tang','','[]','十里尋幽寺，寒流數派分。',48,'全唐诗/poet.tang.31000.json','["十里尋幽寺，寒流數派分。", "僧同雪夜坐，鴈向草堂聞。", "靜語終燈焰，餘生許嶠雲。", "由來多抱疾，聲不達明君。"]'),
('4d86aee8-14b4-45d2-8eee-e5df6c26a3b1','旅遊','賈島','唐','唐诗','tang','','[]','此心非一事，書札若爲傳。',48,'全唐诗/poet.tang.31000.json','["此心非一事，書札若爲傳。", "舊國別多日，故人無少年。", "空巢霜葉落，疎牖水螢穿。", "留得林僧宿，中宵坐默然。"]'),
('82a0c154-0605-4418-a0f0-3960655a5cfa','送鄒明府遊靈武','賈島','唐','唐诗','tang','','["\u54c1\u8d28", "\u9001\u522b", "\u5199\u4eba"]','曾宰西畿縣，三年馬不肥。',48,'全唐诗/poet.tang.31000.json','["曾宰西畿縣，三年馬不肥。", "債多平劍與，官滿載書歸。", "邊雪藏行徑，林風透臥衣。", "靈州聽曉角，客館未開扉。"]'),
('45adb6be-0d14-4946-9a26-040534f936be','題皇甫荀藍田廳','賈島','唐','唐诗','tang','','[]','任官經一年，縣與玉峰連。',48,'全唐诗/poet.tang.31000.json','["任官經一年，縣與玉峰連。", "竹籠拾山果，瓦瓶擔石泉。", "客歸秋雨後，印鎖暮鐘前。", "久別丹陽浦，時時夢釣船。"]'),
('ba2d62b4-30f4-47f9-b06a-3dda46ec4c1e','贈王將軍','賈島','唐','唐诗','tang','','[]','宿衛爐煙近，除書墨未乾。',48,'全唐诗/poet.tang.31000.json','["宿衛爐煙近，除書墨未乾。", "馬曾金鏃中，身有寶刀瘢。", "父子同時捷，君王畫陣看。", "何當爲外帥，白日出長安。"]'),
('c95bbf5c-9b61-4570-a7db-e786a36b4861','下第','賈島','唐','唐诗','tang','','[]','下第只空囊，如何住帝鄉。',48,'全唐诗/poet.tang.31000.json','["下第只空囊，如何住帝鄉。", "杏園啼百舌，誰醉在花傍。", "淚落故山遠，病來春草長。", "知音逢豈易，孤棹負三湘。"]'),
('b7530421-4251-4597-a3fd-7f5d713e9aa0','寄賀蘭朋吉','賈島','唐','唐诗','tang','','[]','往往東林下，花香似火焚。',96,'全唐诗/poet.tang.31000.json','["往往東林下，花香似火焚。", "故園從小別，夜雨近秋聞。", "野菜連寒水，枯株簇古墳。", "泛舟同遠客，尋寺入幽雲。", "斜日扉多掩，荒田徑細分。", "相思蟬幾處，偶坐蝶成羣。", "會宿曾論道，登高省議文。", "苦吟遙可想，邊葉向紛紛。"]'),
('1e96e000-b517-48c8-a957-bc9394dd7fcf','憶吳處士','賈島','唐','唐诗','tang','','[]','半夜長安雨，燈前越客吟。',48,'全唐诗/poet.tang.31000.json','["半夜長安雨，燈前越客吟。", "孤舟行一月，萬水與千岑。", "島嶼夏雲起，汀洲芳草深。", "何當折松葉，拂石剡溪陰。"]'),
('ee09c928-2f1a-47b2-96da-2e2ba808c8f1','哭孟郊','賈島','唐','唐诗','tang','','[]','身死聲名在，多應萬古傳。',48,'全唐诗/poet.tang.31000.json','["身死聲名在，多應萬古傳。", "寡妻無子息，破宅帶林泉。", "塚近登山道，詩隨過海船。", "故人相弔後，斜日下寒天。"]'),
('0f44531a-aa6d-4d1f-8233-baf9b01a7413','送崔定','賈島','唐','唐诗','tang','','[]','未知遊子意，何不避炎蒸？',48,'全唐诗/poet.tang.31000.json','["未知遊子意，何不避炎蒸？", "幾日到漢水，新蟬鳴杜陵。", "秋江待得月，夜語恨無僧。", "巴峽吟過否，連天十二層。"]'),
('b16538c8-f5e1-40c8-8dc9-3652646ca912','寄白閣默公','賈島','唐','唐诗','tang','','[]','已知歸白閣，山遠晚晴看。',48,'全唐诗/poet.tang.31000.json','["已知歸白閣，山遠晚晴看。", "石室人心靜，冰潭月影殘。", "微雲分片滅，古木落薪乾。", "後夜誰聞磬，西峰絕頂寒。"]'),
('1a9c99a9-6234-4b26-88ab-65cfa279db37','雨後宿劉司馬池上','賈島','唐','唐诗','tang','','[]','藍溪秋漱玉，此地漲清澄。',48,'全唐诗/poet.tang.31000.json','["藍溪秋漱玉，此地漲清澄。", "蘆葦聲兼雨，芰荷香遶燈。", "岸頭秦古道，亭面漢荒陵。", "靜想泉根本，幽崖落幾層。"]'),
('c6c2f2c1-10ce-4b51-b7c9-b79747ee7aea','送朱可久歸越中','賈島','唐','唐诗','tang','','[]','石頭城下泊，北固暝鐘初。',48,'全唐诗/poet.tang.31000.json','["石頭城下泊，北固暝鐘初。", "汀鷺潮衝起，船窗月過虛。", "吳山侵越衆，隋柳入唐疎。", "日欲躬調膳，辟來何府書。"]'),
('877224c7-59e3-4b74-898e-8ccc947b4be6','送田卓入華山','賈島','唐','唐诗','tang','','[]','幽深足暮蟬，驚覺石床眠。',48,'全唐诗/poet.tang.31000.json','["幽深足暮蟬，驚覺石床眠。", "瀑布五千仞，草堂瀑布邊。", "壇松涓滴露，嶽月泬寥天。", "鶴過君須看，上頭應有仙。"]'),
('dcf47c93-2a6a-4ca1-a66d-e7e6954b4f0e','送董正字常州覲省','賈島','唐','唐诗','tang','','[]','相逐一行鴻，何時出磧中？',48,'全唐诗/poet.tang.31000.json','["相逐一行鴻，何時出磧中？", "江流翻白浪，木葉落青楓。", "輕檝浮吳國，繁霜下楚空。", "春來懽侍阻，正字在東宮。"]'),
('1163584a-72ee-4aea-bb6c-4f961a6b65dc','酬姚少府','賈島','唐','唐诗','tang','','[]','梅樹與山木，俱應搖落初。',48,'全唐诗/poet.tang.31000.json','["梅樹與山木，俱應搖落初。", "柴門掩寒雨，蟲響出秋蔬。", "枯槁彰清鏡，孱愚友道書。", "刊文非不朽，君子自相於。"]'),
('520cffaf-ac95-4ead-ac6c-270a257614ff','送無可上人','賈島','唐','唐诗','tang','','["\u6292\u60c5", "\u8d60\u522b", "\u79cb\u5929", "\u5b64\u5bc2"]','圭峰霽色新，送此草堂人。',48,'全唐诗/poet.tang.31000.json','["圭峰霽色新，送此草堂人。", "麈尾同離寺，蛩鳴暫別親。", "獨行潭底影，數息樹邊身。", "終有煙霞約，天台作近鄰。"]'),
('475f81aa-cfd7-4d6b-9ba7-03376f000cab','送李騎曹','賈島','唐','唐诗','tang','','[]','歸騎雙旌遠，懽生此別中。',48,'全唐诗/poet.tang.31000.json','["歸騎雙旌遠，懽生此別中。", "蕭關分磧路，嘶馬背寒鴻。", "朔色晴天北，河源落日東。", "賀蘭山頂草，時動捲帆風。"]'),
('eadab97a-5345-4046-96da-d092c663ca3f','送烏行中石淙別業','賈島','唐','唐诗','tang','','[]','寒水長繩汲，丁泠數滴翻。',48,'全唐诗/poet.tang.31000.json','["寒水長繩汲，丁泠數滴翻。", "草通石淙脈，硯帶海潮痕。", "嶽色何曾遠，蟬聲尚未繁。", "勞思當此夕，苗稼在西原。"]'),
('47d92e0a-8fd7-4951-bd59-33134742bd11','送覺興上人歸中條山兼謁河中李司空','賈島','唐','唐诗','tang','','[]','又憶西巖寺，秦原草白時。',48,'全唐诗/poet.tang.31000.json','["又憶西巖寺，秦原草白時。", "山尋樵徑上，人到雪房遲。", "暮磬潭泉凍，荒林野燒移。", "聞師新譯偈，說擬對旌麾。"]'),
('9ab3a0ff-5a99-44fd-bf3e-f06a29d2a0cb','寄無可上人','賈島','唐','唐诗','tang','','[]','僻寺多高樹，涼天憶重遊。',48,'全唐诗/poet.tang.31000.json','["僻寺多高樹，涼天憶重遊。", "磬過溝水盡，月入草堂秋。", "穴蟻苔痕靜，藏蟬柏葉稠。", "名山思徧往，早晚到嵩丘。"]'),
('27bb97a5-6af3-4284-a86a-edfc8d90e65e','南池','賈島','唐','唐诗','tang','','[]','蕭條微雨絕，荒岸抱清源。',48,'全唐诗/poet.tang.31000.json','["蕭條微雨絕，荒岸抱清源。", "入舫山侵塞，分泉稻接村。", "秋聲依樹色，月影在蒲根。", "淹泊方難遂，他宵關夢魂。"]'),
('d0689c43-8cc5-41b4-bee3-9f6308c1346f','寄龍池寺貞空二上人','賈島','唐','唐诗','tang','','[]','受請終南住，俱妨去石橋。',48,'全唐诗/poet.tang.31000.json','["受請終南住，俱妨去石橋。", "林中秋信絕，峰頂夜禪遙。", "寒草煙藏虎，高松月照鵰。", "霜天期到寺，寺置即前朝。"]'),
('54d59a13-1244-4185-b60c-4d154417e3ce','送貞空二上人','賈島','唐','唐诗','tang','','[]','林下中餐後，天涯欲去時。',48,'全唐诗/poet.tang.31000.json','["林下中餐後，天涯欲去時。", "衡陽過有伴，夢澤出應遲。", "石磬疎寒韻，銅瓶結夜澌。", "殷勤訝此別，且未定歸期。"]'),
('fa82d5d0-1912-4895-a206-9c96ac130b1e','送裴校書','賈島','唐','唐诗','tang','','[]','拜官從祕省，署職在藩維。',48,'全唐诗/poet.tang.31000.json','["拜官從祕省，署職在藩維。", "多故長疎索，高秋遠別離。", "天寒泗上醉，夜靜岳陽碁。", "使府臨南海，帆飛到不遲。"]'),
('86c5d034-0007-4cf0-9767-95a934c7a3ed','昇道精舍南臺對月寄姚合','賈島','唐','唐诗','tang','','[]','月向南臺見，秋霖洗滌餘。',50,'全唐诗/poet.tang.31000.json','["月向南臺見，秋霖洗滌餘。", "出逢危葉落，靜看衆峰疎。", "[冷]露常時有，禪窗此夜虛。", "相思聊悵望，潤氣徧衣初。"]'),
('8726f662-01ec-4acc-8edd-186797b7a81a','即事','賈島','唐','唐诗','tang','','[]','索莫對孤燈，陰雲積幾層。',84,'全唐诗/poet.tang.31000.json','["索莫對孤燈，陰雲積幾層。", "自嗟憐十上，誰肯待三徵。", "心被通人見，文叨大匠稱。", "悲秋秦塞草，懷古漢家陵。", "城靜高崖樹，漏多幽沼冰。", "過聲沙島鷺，絕行石菴僧。", "豈謂舊廬在，誰言歸未曾。"]'),
('98e803f0-7681-439a-b725-abf4636ca6a1','黃子陂上韓吏部','賈島','唐','唐诗','tang','','[]','石樓云一別，二十二三春。',96,'全唐诗/poet.tang.31000.json','["石樓云一別，二十二三春。", "相逐升堂者，幾爲埋骨人。", "涕流聞度瘴，病起喜還秦。", "曾是令勤道，非惟卹在迍。", "疎衣蕉縷細，爽味茗芽新。", "鐘絕滴殘雨，螢多無近鄰。", "溪潭承到數，位秩見辭頻。", "若箇山招隱，機忘任此身。"]'),
('1743caa3-080c-47ad-ace6-827aa47a0385','投李益','賈島','唐','唐诗','tang','','[]','四十歸燕字，千年外始吟。',24,'全唐诗/poet.tang.31000.json','["四十歸燕字，千年外始吟。", "已將書北嶽，不用比南金。"]'),
('c94bedaa-949f-4c8d-b08e-b4ed20427ffd','弔孟協律','賈島','唐','唐诗','tang','','[]','才行古人齊，生前品位低。',48,'全唐诗/poet.tang.31000.json','["才行古人齊，生前品位低。", "葬時貧賣馬，遠日哭惟妻。", "孤塚北邙外，空齋中嶽西。", "集詩應萬首，物象徧曾題。"]'),
('9498e20a-e4c1-407c-8e26-ce64e03797dc','送人適越','賈島','唐','唐诗','tang','','[]','高城滿夕陽，何事欲霑裳。',48,'全唐诗/poet.tang.31000.json','["高城滿夕陽，何事欲霑裳。", "遷客蓬蒿暮，遊人道路長。", "晴湖勝鏡碧，寒柳似金黃。", "若有相思夢，殷勤載八行。"]'),
('72cda914-6b8f-416a-bd38-f47ca67f1c39','送僧遊衡嶽','賈島','唐','唐诗','tang','','[]','心知衡嶽路，不怕去人稀。',48,'全唐诗/poet.tang.31000.json','["心知衡嶽路，不怕去人稀。", "船裏猶鳴磬，溪頭自曝衣。", "有家從小別，無寺不言歸。", "料得逢寒住，當禪雪滿扉。"]'),
('5202208a-d7c1-4f14-b4c8-da431d8569a8','送路','賈島','唐','唐诗','tang','','[]','別我就蓬蒿，日斜飛伯勞。',48,'全唐诗/poet.tang.31000.json','["別我就蓬蒿，日斜飛伯勞。", "龍門流水急，嵩岳片雲高。", "歎命無知己，梳頭落白毛。", "從軍當此去，風起廣陵濤。"]'),
('84edfc9b-e4cf-4fa5-9855-456303efeee2','洛陽道中寄弟','賈島','唐','唐诗','tang','','[]','趨走迫流年，慙經此路偏。',48,'全唐诗/poet.tang.31000.json','["趨走迫流年，慙經此路偏。", "密雲埋二室，積雪度三川。", "生類梗萍泛，悲無金石堅。", "翻鴻有歸翼，極目仰聯翩。"]'),
('52be87fc-2013-4cad-a6ba-c210115f6fd0','登江亭晚望','賈島','唐','唐诗','tang','','[]','浩渺浸雲根，煙嵐沒遠村。',48,'全唐诗/poet.tang.31000.json','["浩渺浸雲根，煙嵐沒遠村。", "鳥歸沙有跡，帆過浪無痕。", "望水知柔性，看山欲倦魂。", "縱情猶未已，迴馬欲黃昏。"]'),
('3d647571-a2ad-4007-b3f5-826171647db8','送耿處士','賈島','唐','唐诗','tang','','[]','一瓶離別酒，未盡即言行。',48,'全唐诗/poet.tang.31000.json','["一瓶離別酒，未盡即言行。", "萬水千山路，孤舟幾月程。", "川原秋色靜，蘆葦晚風鳴。", "迢遰不歸客，人傳虛隱名。"]'),
('652003fa-7b9b-4cb7-b507-985c3a2d9089','過唐校書書齋','賈島','唐','唐诗','tang','','[]','池滿風吹竹，時時得爽神。',48,'全唐诗/poet.tang.31000.json','["池滿風吹竹，時時得爽神。", "聲齊雛鳥語，畫卷老僧真。", "月出行幾步，花開到四鄰。", "江湖心自切，未可挂頭巾。"]'),
('80711255-f575-4d15-ba78-04a36e2d7c12','送杜秀才東遊','賈島','唐','唐诗','tang','','[]','東遊誰見待，盡室寄長安。',48,'全唐诗/poet.tang.31000.json','["東遊誰見待，盡室寄長安。", "別後葉頻落，去程山已寒。", "大河風色度，曠野燒煙殘。", "匣有青銅鏡，時將照鬢看。"]'),
('c9caf782-4bac-45c2-8205-3ec69dcb948c','送天台僧','賈島','唐','唐诗','tang','','["\u9001\u522b", "\u5199\u4eba"]','遠夢歸華頂，扁舟背岳陽。',48,'全唐诗/poet.tang.31000.json','["遠夢歸華頂，扁舟背岳陽。", "寒蔬修淨食，夜浪動禪床。", "鴈過孤峰曉，猨啼一樹霜。", "身心無別念，餘習在詩章。"]'),
('8c7f373b-10ed-48ac-bd37-620690935386','懷紫閣隱者','賈島','唐','唐诗','tang','','[]','寂寥思隱者，孤燭坐秋霖。',48,'全唐诗/poet.tang.31000.json','["寂寥思隱者，孤燭坐秋霖。", "梨栗猨喜熟，雲山僧說深。", "寄書應不到，結伴擬同尋。", "廢寢方終夕，迢迢紫閣心。"]'),
('7e2be323-14cf-47fc-8c8d-c43e3d036fc8','雨夜同厲玄懷皇甫荀','賈島','唐','唐诗','tang','','[]','桐竹遶庭匝，雨多風更吹。',48,'全唐诗/poet.tang.31000.json','["桐竹遶庭匝，雨多風更吹。", "還如舊山夜，臥聽瀑泉時。", "磧鴈來期近，秋鐘到夢遲。", "溝西吟苦客，中夕話兼思。"]'),
('aa1f13cf-fc73-4c9f-942d-6c87d8a76f09','秋暮','賈島','唐','唐诗','tang','','[]','北門楊柳葉，不覺已繽紛。',48,'全唐诗/poet.tang.31000.json','["北門楊柳葉，不覺已繽紛。", "值鶴因臨水，迎僧忽背雲。", "白鬚相並出，清淚兩行分。", "默默空朝夕，苦吟誰喜聞。"]'),
('a495857d-bd17-446a-80cb-50eed7ff7c6c','哭胡遇','賈島','唐','唐诗','tang','','[]','夭壽知齊理，何曾免歎嗟。',48,'全唐诗/poet.tang.31000.json','["夭壽知齊理，何曾免歎嗟。", "祭迴收朔雪，弔後折寒花。", "野水秋吟斷，空山暮影斜。", "弟兄相識徧，猶得到君家。"]'),
('e53611cf-b7d8-403a-bc3f-e1f29977fbee','送丹師歸閩中','賈島','唐','唐诗','tang','','[]','波濤路杳然，衰柳落陽蟬。',48,'全唐诗/poet.tang.31000.json','["波濤路杳然，衰柳落陽蟬。", "行李經雷電，禪前漱島泉。", "歸林久別寺，過越未離船。", "自說從今去，身應老海邊。"]'),
('24be512b-9298-4f49-bc63-cd643f3cc05b','送安南惟鑒法師','賈島','唐','唐诗','tang','','[]','講經春殿裏，花遶御牀飛。',48,'全唐诗/poet.tang.31000.json','["講經春殿裏，花遶御牀飛。", "南海幾迴渡，舊山臨老歸。", "潮搖蠻草落，月溼島松微。", "空水既如彼，往來消息稀。"]'),
('b07455d5-c662-4c95-ae96-d4d106a43db0','題李凝幽居','賈島','唐','唐诗','tang','','[]','閑居少鄰並，草徑入荒園。',48,'全唐诗/poet.tang.31000.json','["閑居少鄰並，草徑入荒園。", "鳥宿池邊樹，僧敲月下門。", "過橋分野色，移石動雲根。", "暫去還來此，幽期不負言。"]'),
('aa02218e-77f2-4a1a-b14d-6df92ca49d68','送韓湘','賈島','唐','唐诗','tang','','[]','挂席從古路，長風起廣津。',72,'全唐诗/poet.tang.31000.json','["挂席從古路，長風起廣津。", "楚城花未發，上苑蝶來新。", "半沒湖波月，初生島草春。", "孤霞臨石鏡，極浦映村神。", "細響吟乾葦，餘馨動遠蘋。", "欲憑將一札，寄與沃洲人。"]'),
('7ce72d5e-b764-409b-8886-ebc4263fe5f0','寄董武','賈島','唐','唐诗','tang','','[]','雖同一城裏，少省得從容。',48,'全唐诗/poet.tang.31000.json','["雖同一城裏，少省得從容。", "門掩園林僻，日高巾幘慵。", "孤鴻來半夜，積雪在諸峰。", "正憶毗陵客，聲聲隔水鐘。"]'),
('16b5ba16-e3ab-4278-85a7-e0fa89c05a95','宿贇上人房','賈島','唐','唐诗','tang','','[]','堦前多是竹，閑地擬栽松。',48,'全唐诗/poet.tang.31000.json','["堦前多是竹，閑地擬栽松。", "朱點草書疏，雪平麻履蹤。", "御溝寒夜雨，宮寺靜時鐘。", "此時無他事，來尋不厭重。"]'),
('645e508e-1b7d-4d83-bef0-36e0717a84f5','訪李甘原居','賈島','唐','唐诗','tang','','[]','原西居處靜，門對曲江開。',48,'全唐诗/poet.tang.31000.json','["原西居處靜，門對曲江開。", "石縫銜枯草，查根上淨苔。", "翠微泉夜落，紫閣鳥時來。", "仍憶尋淇岸，同行採蕨回。"]'),
('baee2bfa-ce98-4977-87d4-efe149414075','題山寺井','賈島','唐','唐诗','tang','','[]','沈沈百尺餘，功就豈斯須。',48,'全唐诗/poet.tang.31000.json','["沈沈百尺餘，功就豈斯須。", "汲早僧出定，鑿新蟲自無。", "藏源重嶂底，澄翳大空隅。", "此地如經劫，涼潭會共枯。"]'),
('0a5e1618-f686-49a6-a7b0-1968961d8126','僻居無可上人相訪','賈島','唐','唐诗','tang','','[]','自從居此地，少有事相關。',48,'全唐诗/poet.tang.31000.json','["自從居此地，少有事相關。", "積雨荒鄰圃，秋池照遠山。", "硯中枯葉落，枕上斷雲閑。", "野客將禪子，依依偏往還。"]'),
('ef3783fc-5ab0-47a9-9cf2-6636673b4c0d','送李餘及第歸蜀','賈島','唐','唐诗','tang','','[]','知音伸久屈，覲省去光輝。',48,'全唐诗/poet.tang.31000.json','["知音伸久屈，覲省去光輝。", "津渡逢清夜，途程盡翠微。", "雲當绵竹疊，鳥離錦江飛。", "肯寄書來否，原居出亦稀。"]'),
('a5bb58de-5bb7-44eb-b7c8-0ffd78d41fe4','荒齋','賈島','唐','唐诗','tang','','[]','草合徑微微，終南對掩扉。',48,'全唐诗/poet.tang.31000.json','["草合徑微微，終南對掩扉。", "晚涼疎雨絕，初曉遠山稀。", "落葉無青地，閑身著白衣。", "朴愚猶本性，不是學忘機。"]'),
('d8a64073-762b-49e0-88ce-10fcc94fd36b','夜喜賀蘭三見訪','賈島','唐','唐诗','tang','','[]','漏鐘仍夜淺，時節欲秋分。',48,'全唐诗/poet.tang.31000.json','["漏鐘仍夜淺，時節欲秋分。", "泉聒棲松鶴，風除翳月雲。", "踏苔行引興，枕石臥論文。", "即此尋常靜，來多秖是君。"]'),
('1d577b03-e57f-49b2-8a4a-d31a424e863f','題青龍寺鏡公房','賈島','唐','唐诗','tang','','[]','一夕曾留宿，終南搖落時。',48,'全唐诗/poet.tang.31000.json','["一夕曾留宿，終南搖落時。", "孤燈岡舍掩，殘磬雪風吹。", "樹老因寒折，泉深出井遲。", "疎慵豈有事，多失上方期。"]'),
('6c861994-a47a-445b-a47b-e16ae0094027','送陳判官赴綏德','賈島','唐','唐诗','tang','','[]','將軍邀入幕，束帶便離家。',48,'全唐诗/poet.tang.31000.json','["將軍邀入幕，束帶便離家。", "身暖蕉衣窄，天寒磧日斜。", "火燒岡斷葦，風卷雪平沙。", "絲竹豐州有，春來秖欠花。"]'),
('4cbb5fb8-d224-4d6f-a0ad-ef81d3424aba','送唐環歸敷水莊','賈島','唐','唐诗','tang','','[]','毛女峰當戶，日高頭未梳。',48,'全唐诗/poet.tang.31000.json','["毛女峰當戶，日高頭未梳。", "地侵山影掃，葉帶露痕書。", "松徑僧尋藥，沙泉鶴見魚。", "一川風景好，恨不有吾廬。"]'),
('e7a92e56-f5a9-4b2c-81f3-e8bf88210878','原東居喜唐溫琪頻至','賈島','唐','唐诗','tang','','[]','曲江春草生，紫閣雪分明。',48,'全唐诗/poet.tang.31000.json','["曲江春草生，紫閣雪分明。", "汲井嘗泉味，聽鐘問寺名。", "墨研秋日雨，茶試老僧鐺。", "地近勞頻訪，烏紗出送迎。"]'),
('23818817-a8c2-4a52-a995-0f84dd5b548e','送敭法師','賈島','唐','唐诗','tang','','[]','度歲不相見，嚴冬始出關。',48,'全唐诗/poet.tang.31000.json','["度歲不相見，嚴冬始出關。", "孤煙寒色樹，高雪夕陽山。", "瀑布寺應到，牡丹房甚閑。", "南朝遺跡在，此去幾時還。"]'),
('848c0ab5-600d-4e80-8b02-db52bf525cbe','寄錢庶子','賈島','唐','唐诗','tang','','[]','曲江春水滿，北岸掩柴關。',48,'全唐诗/poet.tang.31000.json','["曲江春水滿，北岸掩柴關。", "秖有僧鄰舍，全無物映山。", "樹陰終日掃，藥債隔年還。", "猶記聽琴夜，寒燈竹屋間。"]'),
('5df71537-93fd-43c0-be60-4bef5bf1910a','原上秋居','賈島','唐','唐诗','tang','','[]','關西又落木，心事復如何。',48,'全唐诗/poet.tang.31000.json','["關西又落木，心事復如何。", "歲月辭山久，秋霖入夜多。", "鳥從井口出，人自洛陽過。", "倚杖聊閑望，田家未翦禾。"]'),
('e1743d87-b29d-448f-b00d-60a242f8a1fa','夏夜','賈島','唐','唐诗','tang','','[]','原寺偏鄰近，開門物景澄。',48,'全唐诗/poet.tang.31000.json','["原寺偏鄰近，開門物景澄。", "磬通多葉罅，月離片雲稜。", "寄宿山中鳥，相尋海畔僧。", "唯愁秋色至，乍可在炎蒸。"]'),
('944a04d7-eac2-4092-9258-12a275a3b530','冬夜','賈島','唐','唐诗','tang','','[]','羈旅復經冬，瓢空盎亦空。',48,'全唐诗/poet.tang.31000.json','["羈旅復經冬，瓢空盎亦空。", "淚流寒枕上，跡絕舊山中。", "淩結浮萍水，雪和衰柳風。", "曙光雞未報，嘹唳兩三鴻。"]'),
('fa55078f-c074-4710-b32d-dc9968a3765e','送厲宗上人','賈島','唐','唐诗','tang','','[]','擁策背岷峨，終南雨雪和。',48,'全唐诗/poet.tang.31000.json','["擁策背岷峨，終南雨雪和。", "漱泉秋鶴至，禪樹夜猨過。", "高頂白雲盡，前山黃葉多。", "曾吟廬嶽上，月動九江波。"]'),
('76b51be2-877b-40c3-b694-344892b49348','寄李存穆','賈島','唐','唐诗','tang','','[]','聞道船中病，似憂親弟兄。',48,'全唐诗/poet.tang.31000.json','["聞道船中病，似憂親弟兄。", "信來從水路，身去到柴城。", "久別長鬚鬢，相思書姓名。", "忽然消息絕，頻夢却還京。"]'),
('eeb1d5e4-aee8-4d9e-a49f-d52160c74058','贈無懷禪師','賈島','唐','唐诗','tang','','[]','身從劫劫修，果以此生周。',48,'全唐诗/poet.tang.31000.json','["身從劫劫修，果以此生周。", "禪定石床暖，月移山樹秋。", "捧盂觀宿飯，敲磬過清流。", "不掩玄關路，敎人問白頭。"]'),
('ab87d158-11a5-4d10-92bc-14d33eb4a530','寄武功姚主簿','賈島','唐','唐诗','tang','','[]','居枕江沱北，情懸渭曲西。',120,'全唐诗/poet.tang.31000.json','["居枕江沱北，情懸渭曲西。", "數宵曾夢見，幾處得書披。", "驛路穿荒坂，公田帶淤泥。", "靜棊功奧妙，閑作韻清淒。", "鋤草留叢藥，尋山上石梯。", "客迴河水漲，風起夕陽低。", "空地苔連井，孤村火隔溪。", "卷簾黃葉落，鎖印子規啼。", "隴色澄秋月，邊聲入戰鼙。", "會須過縣去，況是屢招攜。"]'),
('e26074a2-a61a-4b6b-8d63-fd329f3e52b5','題劉華書齋','賈島','唐','唐诗','tang','','[]','白石床無塵，青松樹有鱗。',96,'全唐诗/poet.tang.31000.json','["白石床無塵，青松樹有鱗。", "一鶯啼帶雨，兩樹合從春。", "荒榭苔膠砌，幽叢果墮榛。", "偶來疎或數，當暑夕勝晨。", "露滴星河水，巢重草木薪。", "終南同往意，趙北獨遊身。", "渡葉司天漏，驚蛩遠地人。", "機清公幹族，也莫臥漳濱。"]'),
('c720ab58-0a69-4033-a325-fc1c1105680f','送盧秀才遊潞府','賈島','唐','唐诗','tang','','[]','雨餘滋潤在，風不起塵沙。',48,'全唐诗/poet.tang.31000.json','["雨餘滋潤在，風不起塵沙。", "邊日寡文思，送君吟月華。", "過山干相府，臨水宿僧家。", "能賦焉長屈，芳春宴杏花。"]'),
('93bad2e8-a7c3-44d5-aec1-5a0664e90905','送南康姚明府','賈島','唐','唐诗','tang','','[]','銅章美少年，小邑在南天。',48,'全唐诗/poet.tang.31000.json','["銅章美少年，小邑在南天。", "版籍多遷客，封疆接洞田。", "靜江鳴野鼓，發纜帶村煙。", "却笑陶元亮，何須憶醉眠。"]'),
('abc7de1d-6726-441e-8282-a2d58e6558bf','送友人棄官遊江左','賈島','唐','唐诗','tang','','[]','羨君休作尉，萬事且全身。',48,'全唐诗/poet.tang.31000.json','["羨君休作尉，萬事且全身。", "寰海多虞日，江湖獨往人。", "姓名何處變，鷗鳥幾時親。", "別後吳中使，應須訪子真。"]'),
('f2cabd75-5b60-47d9-868b-7de24329db65','雨中懷友人','賈島','唐','唐诗','tang','','[]','對雨思君子，嘗茶近竹幽。',24,'全唐诗/poet.tang.31000.json','["對雨思君子，嘗茶近竹幽。", "儒家鄰古寺，不到又逢秋。"]'),
('69f5ea03-9eef-4394-aa3d-031520ed58c4','寄遠','賈島','唐','唐诗','tang','','[]','家住錦水上，身征遼海邊。',24,'全唐诗/poet.tang.31000.json','["家住錦水上，身征遼海邊。", "十書九不到，一到忽經年。"]'),
('b137d820-afec-45b7-b5b7-634540fe1dd7','南齋','賈島','唐','唐诗','tang','','[]','獨自南齋臥，神閑景亦空。',48,'全唐诗/poet.tang.31000.json','["獨自南齋臥，神閑景亦空。", "有山來枕上，無事到心中。", "簾卷侵牀月，屏遮入座風。", "望春春未至，應在海門東。"]'),
('22f719b3-cded-4cc2-992e-9da94308eab5','早春題友人湖上新居二首 一','賈島','唐','唐诗','tang','','[]','近得雲中路，門長侵早開。',48,'全唐诗/poet.tang.31000.json','["近得雲中路，門長侵早開。", "到時猶有雪，行處已無苔。", "勸酒客初醉，留茶僧未來。", "每逢晴暖日，惟見乞花栽。"]'),
('9687e261-4583-4bd7-b9db-664755939a85','早春題友人湖上新居二首 二','賈島','唐','唐诗','tang','','[]','門不當官道，行人到亦稀。',48,'全唐诗/poet.tang.31000.json','["門不當官道，行人到亦稀。", "故從餐後出，多是夜深歸。", "開篋收詩卷，掃牀移臥衣。", "幾時同買宅，相送有柴扉。"]'),
('d1c41f4d-5352-4782-b5e6-09279f6337b6','送雍陶入蜀','賈島','唐','唐诗','tang','','[]','江山事若諳，那肯滯雲南。',48,'全唐诗/poet.tang.31000.json','["江山事若諳，那肯滯雲南。", "草色分危磴，杉陰近古潭。", "日斜襃谷鳥，夏淺巂州蠶。", "吾自疑雙鬢，相逢更不堪。"]'),
('6f9f439a-bd51-46c5-8788-5aaad8d7f456','張郎中過原東居','賈島','唐','唐诗','tang','','[]','年長惟添嬾，經旬止掩關。',48,'全唐诗/poet.tang.31000.json','["年長惟添嬾，經旬止掩關。", "高人餐藥後，下馬此林間。", "對坐天將暮，同來客亦閑。", "幾時能重至，水味似深山。"]'),
('db84e11f-1ab6-4997-963b-3b9bde8ec214','荅王建祕書','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','人皆聞蟋蟀，我獨恨蹉跎。',48,'全唐诗/poet.tang.31000.json','["人皆聞蟋蟀，我獨恨蹉跎。", "白髮無心鑷，青山去意多。", "信來漳浦岸，期負洞庭波。", "時掃高槐影，朝迴或恐過。"]'),
('627003df-142e-4868-afdf-a90dcc4a9112','送李餘往湖南','賈島','唐','唐诗','tang','','[]','昔去候溫涼，秋山滿楚鄉。',48,'全唐诗/poet.tang.31000.json','["昔去候溫涼，秋山滿楚鄉。", "今來從辟命，春物徧涔陽。", "岳石挂海雪，野楓堆渚檣。", "若尋吾祖宅，寂寞在瀟湘。"]'),
('2a91950e-3ffc-4b62-abd5-51d113aeeacd','偶作','賈島','唐','唐诗','tang','','[]','野步隨吾意，那知是與非。',48,'全唐诗/poet.tang.31000.json','["野步隨吾意，那知是與非。", "稔年時雨足，閏月暮蟬稀。", "獨樹依岡老，遙峰出草微。", "園林自有主，宿鳥且同歸。"]'),
('55a5663c-3a12-431d-9ef0-df39bcf59f5c','過雍秀才居','賈島','唐','唐诗','tang','','[]','夏木鳥巢邊，終南嶺色鮮。',48,'全唐诗/poet.tang.31000.json','["夏木鳥巢邊，終南嶺色鮮。", "就涼安坐石，煮茗汲鄰泉。", "鐘遠清霄半，蜩稀暑雨前。", "幽齋如葺罷，約我一來眠。"]'),
('b1bd198b-bb8c-4d32-b8ad-8a2db6a44474','寄顧非熊','賈島','唐','唐诗','tang','','[]','知君歸有處，山水亦難齊。',48,'全唐诗/poet.tang.31000.json','["知君歸有處，山水亦難齊。", "猶去瀟湘遠，不聞猨狖啼。", "穴通茆嶺下，潮滿石頭西。", "獨立生遙思，秋原日漸低。"]'),
('4e81417d-ccba-45dd-b919-e887cf3214da','送神邈法師','賈島','唐','唐诗','tang','','[]','柳絮落濛濛，西州道路中。',48,'全唐诗/poet.tang.31000.json','["柳絮落濛濛，西州道路中。", "相逢春忽盡，獨去講初終。", "行疾遙山雨，眠遲後夜風。", "繞房三兩樹，迴日葉應紅。"]'),
('6a5e3a51-9b38-48b8-b104-bc93f03ca835','送慈恩寺霄韻法師謁太原李司空','賈島','唐','唐诗','tang','','[]','何故謁司空，雲山知幾重。',48,'全唐诗/poet.tang.31000.json','["何故謁司空，雲山知幾重。", "磧遙來鴈盡，雪急去僧逢。", "清磬先寒角，禪燈徹曉烽。", "舊房閑片石，倚著最高松。"]'),
('884df2cf-2a30-431b-a705-2bf9cb4e9b43','送知興上人','賈島','唐','唐诗','tang','','[]','久住巴興寺，如今始拂衣。',48,'全唐诗/poet.tang.31000.json','["久住巴興寺，如今始拂衣。", "欲臨秋水別，不向故園歸。", "錫挂天涯樹，房開嶽頂扉。", "下看千里曉，霜海日生微。"]'),
('db690a9f-422e-458d-8965-75710332aec8','送惠雅法師歸玉泉','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','秖到瀟湘水，洞庭湖未遊。',48,'全唐诗/poet.tang.31000.json','["秖到瀟湘水，洞庭湖未遊。", "飲泉看月別，下峽聽猨愁。", "講不停雷雨，吟當近海流。", "降霜歸楚夕，星冷玉泉秋。"]'),
('58d0214a-58d8-4066-a12f-50ff7e4aae1f','憶江上吳處士','賈島','唐','唐诗','tang','','["\u601d\u5ff5", "\u9001\u522b"]','閩國揚帆去，蟾蜍虧復團。',48,'全唐诗/poet.tang.31000.json','["閩國揚帆去，蟾蜍虧復團。", "秋風生渭水，落葉滿長安。", "此地聚會夕，當時雷雨寒。", "蘭橈殊未返，消息海雲端。"]'),
('5720cc78-ffca-417f-901c-d8d0d96e246f','題張博士新居','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','青楓何不種，林在洞庭村。',48,'全唐诗/poet.tang.31000.json','["青楓何不種，林在洞庭村。", "應爲三湘遠，難移萬里根。", "斗牛初過伏，菡萏欲香門。", "舊即湖山隱，新廬葺此原。"]'),
('062dcf86-1663-4038-bba4-39fa6a727333','石門陂留辭從叔謩','賈島','唐','唐诗','tang','','[]','幽鳥飛不遠，此行千里間。',48,'全唐诗/poet.tang.31000.json','["幽鳥飛不遠，此行千里間。", "寒衝陂水霧，醉下菊花山。", "有恥長爲客，無成又入關。", "何時臨澗柳，吾黨共來攀。"]'),
('81002d91-a8d2-4ff6-b9ae-1a550d1816d5','送朱兵曹迴越','賈島','唐','唐诗','tang','','[]','星彩練中見，澄江豈有泥。',48,'全唐诗/poet.tang.31000.json','["星彩練中見，澄江豈有泥。", "潮生垂釣罷，楚盡去檣西。", "磧鳥辭沙至，山鼯隔水啼。", "會稽半侵海，濤白禹祠溪。"]'),
('efbc18ca-6bc1-4795-b085-f81e15a7900d','懷博陵故人','賈島','唐','唐诗','tang','','[]','孤城易水頭，不忘舊交遊。',48,'全唐诗/poet.tang.31000.json','["孤城易水頭，不忘舊交遊。", "雪壓圍碁石，風吹飲酒樓。", "路遙千萬里，人別十三秋。", "吟苦相思處，天寒水急流。"]'),
('fd4d3717-2301-4efe-b7a6-4a6ed76265dc','夕思','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','秋宵已難曙，漏向二更分。',48,'全唐诗/poet.tang.31000.json','["秋宵已難曙，漏向二更分。", "我憶山水坐，蟲當寂寞聞。", "洞庭風落木，天姥月離雲。", "會自東浮去，將何欲致君。"]'),
('e9b2ca48-2430-4305-8939-85b07e358354','寄河中楊少尹','賈島','唐','唐诗','tang','','[]','非惟咎曩時，投刺詣門遲。',48,'全唐诗/poet.tang.31000.json','["非惟咎曩時，投刺詣門遲。", "悵望三秋後，參差萬里期。", "禹留疏鑿跡，舜在寂寥祠。", "此到杳難共，迴風逐所思。"]'),
('db04d535-fcaf-4283-84f3-923b59fa56d5','孟融逸人','賈島','唐','唐诗','tang','','[]','孟君臨水居，不食水中魚。',48,'全唐诗/poet.tang.31000.json','["孟君臨水居，不食水中魚。", "衣褐唯麤帛，筐箱秖素書。", "樹林幽鳥戀，世界此心疎。", "擬棹孤舟去，何峰又結廬。"]'),
('0ccf240f-d51f-45cf-8bb7-71e6f52ed204','晚晴見終南諸峰','賈島','唐','唐诗','tang','','[]','秦分積多峰，連巴勢不窮。',48,'全唐诗/poet.tang.31000.json','["秦分積多峰，連巴勢不窮。", "半旬藏雨裏，此日到窗中。", "圓魄將昇兔，高空欲呌鴻。", "故山思不見，碣石泬寥東。"]'),
('a7292b3b-e11b-41d6-8587-19ad5f2071cc','宿池上','賈島','唐','唐诗','tang','','[]','泉來從絕壑，亭敞在中流。',48,'全唐诗/poet.tang.31000.json','["泉來從絕壑，亭敞在中流。", "竹密無空岸，松長可絆舟。", "蟪蛄潭上夜，河漢島前秋。", "異夕期深漲，攜琴却此遊。"]'),
('24855878-b6e3-4668-b0e9-a1617a1035b5','喜姚郎中自杭州迴','賈島','唐','唐诗','tang','','[]','路多楓樹林，累日泊清陰。',48,'全唐诗/poet.tang.31000.json','["路多楓樹林，累日泊清陰。", "來去泛流水，翛然適此心。", "一披江上作，三起月中吟。", "東省期司諫，雲門悔不尋。"]'),
('31216179-278b-4adf-9701-b7854e4b2bf7','送鄭長史之嶺南','賈島','唐','唐诗','tang','','[]','雲林頗重疊，岑渚復幽奇。',48,'全唐诗/poet.tang.31000.json','["雲林頗重疊，岑渚復幽奇。", "汨水斜陽岸，騷人正則祠。", "蒼梧多蟋蟀，白露溼江蘺。", "擢第榮南去，晨昏近九疑。"]'),
('f36b88fe-f2d5-4118-8d1a-ab6393795640','送李溟謁宥州李權使君','賈島','唐','唐诗','tang','','[]','英雄典宥州，迢遰苦吟遊。',48,'全唐诗/poet.tang.31000.json','["英雄典宥州，迢遰苦吟遊。", "風宿驪山下，月斜灞水流。", "去時初落葉，回日定非秋。", "太守攜才子，看鵬百尺樓。"]'),
('d2f984cd-59fc-402d-b3ee-306841c379c6','永福湖和楊鄭州','賈島','唐','唐诗','tang','','[]','積水還平岸，春來引鄭溪。',48,'全唐诗/poet.tang.31000.json','["積水還平岸，春來引鄭溪。", "舊渠通郭下，新堰絕湖西。", "嵩少分明對，瀟湘闊狹齊。", "客遊隨庶子，孤嶼草萋萋。"]'),
('b7d85fdc-f5fe-4302-88d6-05f3959a1d52','題長江','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','言心俱好靜，廨署落暉空。',48,'全唐诗/poet.tang.31000.json','["言心俱好靜，廨署落暉空。", "歸吏封宵鑰，行蛇入古桐。", "長江頻雨後，明月衆星中。", "若任遷人去，西溪與剡通。"]'),
('ad218733-8a82-47b0-b8e8-fbdd98eb021f','泥陽館','賈島','唐','唐诗','tang','','[]','客愁何併起，暮送故人回。',48,'全唐诗/poet.tang.31000.json','["客愁何併起，暮送故人回。", "廢館秋螢出，空城寒雨來。", "夕陽飄白露，樹影掃青苔。", "獨坐離容慘，孤燈照不開。"]'),
('1318ca07-1acc-4acf-96aa-37646370a216','送徐員外赴河中','賈島','唐','唐诗','tang','','[]','原野正蕭瑟，中間分散情。',48,'全唐诗/poet.tang.31000.json','["原野正蕭瑟，中間分散情。", "吏從甘扈罷，詔許朔方行。", "邊日沈殘角，河關截夜城。", "雲居閑獨往，長老出房迎。"]'),
('6c24590f-6d3e-44fb-bf97-a20026e4f025','送賀蘭上人','賈島','唐','唐诗','tang','','[]','野僧來別我，略坐傍泉沙。',48,'全唐诗/poet.tang.31000.json','["野僧來別我，略坐傍泉沙。", "遠道擎空鉢，深山蹋落花。", "無師禪自解，有格句堪誇。", "此去非緣事，孤雲不定家。"]'),
('fafa5158-c354-41b6-82c0-5fcfc1453c0e','送令狐綯相公','賈島','唐','唐诗','tang','','[]','梁園趨戟節，海草幾枯春。',218,'全唐诗/poet.tang.31000.json','["梁園趨戟節，海草幾枯春。", "風水難遭便，差池未振鱗。", "姓名猶語及，門館阻何因。", "苦擬修文卷，重擎獻匠人。", "吟看青島處，朝退赤墀晨。", "根愛杉栽活，枝憐雪霰新。", "綴篇嗟調逸，不知揣才貧。", "早晚還霖雨，滂沱洗月輪。", "揠苗方滅裂，成器待陶鈞。", "困坂思迴顧，迷邦輙問津。", "數行望外札，絕句握中珍。", "是日榮遊汴，當時怯往陳。", "鴻舂乖漢爵，[楨]病臥漳濱。", "嶽整五千仞，雲惟一片身。", "故山離未死，秋水宿經旬。", "下第能無恧，高科恐有神。", "罷耕田料廢，省釣岸應榛。", "慷慨知音在，誰能淚墮巾。"]'),
('62ba41c5-bab9-4c53-9365-3e237fc04bd0','寄滄州李尚書','賈島','唐','唐诗','tang','','[]','滄溟深絕闊，西岸郭東門。',168,'全唐诗/poet.tang.31000.json','["滄溟深絕闊，西岸郭東門。", "弋者羅夷鳥，桴人思嶠猨。", "威稜高臘冽，煦育極春溫。", "陂淀封疆內，蒹葭壁壘根。", "搖鞞邊地脈，愁箭虎狼魂。", "水縣賣紗市，鹽田煮海村。", "枝條分御葉，家世食唐恩。", "武可縱橫講，功從戰伐論。", "天涯生月片，嶼頂湧泉源。", "非是泥池物，方因雷雨尊。", "沈謀藏未露，隣境帖無喧。", "青塚驕回鶻，蕭關陷吐蕃。", "何時霖歲旱，早晚雪邦冤。", "迢遰瞻旌纛，浮陽寄詠言。"]'),
('ea5a87a1-3fab-45e8-a21e-c438cb012a37','逢舊識','賈島','唐','唐诗','tang','','["\u9ec4\u6cb3"]','幾歲阻干戈，今朝勸酒歌。',48,'全唐诗/poet.tang.31000.json','["幾歲阻干戈，今朝勸酒歌。", "羨君無白髮，走馬過黃河。", "舊宅兵燒盡，新宮日奏多。", "妖星還有角，數尺鐵重磨。"]'),
('0c2c0218-03e1-42d3-a86c-f2b1ac3d467f','崇聖寺斌公房','賈島','唐','唐诗','tang','','["\u8861\u5c71"]','近來惟一食，樹下掩禪扉。',48,'全唐诗/poet.tang.31000.json','["近來惟一食，樹下掩禪扉。", "落日寒山磬，多年壞衲衣。", "白鬚長更剃，青靄遠還歸。", "仍說遊南嶽，經行是息機。"]'),
('a5450ffc-ebde-4d1f-a940-a8b81683af2c','送李傅侍郎劒南行營','賈島','唐','唐诗','tang','','[]','走馬從邊事，新恩受外臺。',72,'全唐诗/poet.tang.31000.json','["走馬從邊事，新恩受外臺。", "勇看雙節出，期破八蠻回。", "許國家無戀，盤江棧不摧。", "移軍刁斗逐，報捷劒門開。", "角咽狝猴呌，鼙乾霹靂來。", "去年新甸邑，猶滯佐時才。"]'),
('670e4ce9-a5c1-4837-bf41-995146437875','別徐明府','賈島','唐','唐诗','tang','','[]','抱琴非本意，生事偶相縈。',72,'全唐诗/poet.tang.31000.json','["抱琴非本意，生事偶相縈。", "口尚袁安節，身無子賤名。", "地寒春雪盛，山淺夕風輕。", "百戰餘荒野，千夫漸耦耕。", "一杯宜獨夜，孤客戀交情。", "明日疲驂去，蕭條過古城。"]'),
('8823fad8-5ca4-4069-abe9-597843ef2156','岐下送友人歸襄陽','賈島','唐','唐诗','tang','','[]','蹉跎隨汎梗，羈旅到西州。',48,'全唐诗/poet.tang.31000.json','["蹉跎隨汎梗，羈旅到西州。", "舉翮籠中鳥，知心海上鷗。", "山光分首暮，草色向家秋。", "若更登高峴，看碑定淚流。"]'),
('ebc61db7-860f-47c8-ad8c-774fe47bb64d','送友人遊蜀','賈島','唐','唐诗','tang','','[]','萬岑深積翠，路向此中難。',48,'全唐诗/poet.tang.31000.json','["萬岑深積翠，路向此中難。", "欲暮多羈思，因高莫遠看。", "卓家人寂寞，揚子業凋殘。", "唯有岷江水，悠悠帶月寒。"]'),
('a6f71377-9740-43c2-9af4-1a3f4ec769b3','送鄭少府','賈島','唐','唐诗','tang','','[]','江岸一相見，空令惜此分。',48,'全唐诗/poet.tang.31000.json','["江岸一相見，空令惜此分。", "夕陽行帶月，酌水少留君。", "野地初燒草，荒山過雪雲。", "明年還調集，蟬可在家聞。"]'),
('53c2e176-93bf-4947-b39c-95240a6ce3a8','子規','賈島','唐','唐诗','tang','','[]','遊魂自相呌，寧復記前身。',48,'全唐诗/poet.tang.31000.json','["遊魂自相呌，寧復記前身。", "飛過隣家月，聲連野路春。", "夢邊催曉急，愁處送風頻。", "自有霑花血，相和雨滴新。"]'),
('84e8c04b-98e5-4bf2-9705-08919322d7f2','送僧歸天台','賈島','唐','唐诗','tang','','[]','辭秦經越過，歸寺海西峯。',48,'全唐诗/poet.tang.31000.json','["辭秦經越過，歸寺海西峯。", "石磵雙流水，山門九里松。", "曾聞清禁漏，却聽赤城鐘。", "妙宇研磨講，應齊智者蹤。"]'),
('1d70c7b3-ad88-433f-921c-a518dc0dbe35','讓糺曹上樂使君','賈島','唐','唐诗','tang','','[]','戰戰復兢兢，猶如履薄冰。',48,'全唐诗/poet.tang.31000.json','["戰戰復兢兢，猶如履薄冰。", "雖然叨一掾，還似說三乘。", "瓶汲南溪水，書來北嶽僧。", "戇愚兼抱疾，權紀不相應。"]'),
('f3cecd71-644c-41d6-936a-c2e3fae71858','贈友人','賈島','唐','唐诗','tang','','[]','五字詩成卷，清新韻具偕。',48,'全唐诗/poet.tang.31000.json','["五字詩成卷，清新韻具偕。", "不同狂客醉，自伴律僧齋。", "春別和花樹，秋辭帶月淮。", "却歸登第日，名近榜頭排。"]'),
('7cf12aa9-4b6d-4fce-9bf9-1f58827b7c97','送雍陶及第歸成都寧親','賈島','唐','唐诗','tang','','[]','不唯詩著籍，兼又賦知名。',96,'全唐诗/poet.tang.31000.json','["不唯詩著籍，兼又賦知名。", "議論於題稱，春秋對問精。", "半應陰隲與，全賴有司平。", "歸去峯巒衆，別來松桂生。", "漲江流水品，當道白雲坑。", "勿以攻文捷，而將學劒輕。", "製衣新濯錦，開醞舊燒罌。", "同日昇科士，誰同膝下榮。"]'),
('82fd3e95-ed55-42d1-9a70-5da5adb3fa4f','謝令狐綯相公賜衣九事','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','長江飛鳥外，主簿跨驢歸。',48,'全唐诗/poet.tang.31000.json','["長江飛鳥外，主簿跨驢歸。", "逐客寒前夜，元戎予厚衣。", "雪來松更綠，霜降月彌輝。", "即日調殷鼎，朝分是與非。"]'),
('cd828556-fd5c-4116-8159-18007ef65bd7','送金州鑒周上人','賈島','唐','唐诗','tang','','[]','地必尋天目，溪仍住若耶。',48,'全唐诗/poet.tang.31000.json','["地必尋天目，溪仍住若耶。", "帆隨風便發，月不要雲遮。", "極浦浮霜雁，迴潮落海查。", "峨嵋省春上，立雪指流沙。"]'),
('adfd453a-0bec-446d-b8a2-91ea9f2e0681','送譚遠上人','賈島','唐','唐诗','tang','','[]','下視白雲時，山房蓋樹皮。',48,'全唐诗/poet.tang.31000.json','["下視白雲時，山房蓋樹皮。", "垂枝松落子，側頂鶴聽棋。", "清淨從沙劫，中終未日欹。", "金光明本行，同侍出峨嵋。"]'),
('b608f6d0-1b8d-4266-b907-12af4b907f34','新年','賈島','唐','唐诗','tang','','["\u5fe7\u56fd\u5fe7\u6c11", "\u8282\u65e5", "\u6292\u6000", "\u65b0\u5e74"]','嗟以龍鍾身，如何歲復新。',48,'全唐诗/poet.tang.31000.json','["嗟以龍鍾身，如何歲復新。", "石門思隱久，銅鏡強窺頻。", "花發新移樹，心知故國春。", "誰能平此恨，豈是北宗人。"]'),
('b957e2fe-02de-4fb1-bd40-16400e2d58b0','送僧','賈島','唐','唐诗','tang','','[]','出家從丱歲，解論造玄門。',48,'全唐诗/poet.tang.31000.json','["出家從丱歲，解論造玄門。", "不惜揮談柄，誰能聽至言。", "中時山果熟，後夏竹陰繁。", "此去逢何日，峨嵋曉復昏。"]'),
('4e9ca82f-2295-4e31-b500-0e38da48f5da','送姚杭州','賈島','唐','唐诗','tang','','[]','白雲峯下城，日夕白雲生。',48,'全唐诗/poet.tang.31000.json','["白雲峯下城，日夕白雲生。", "人老江波釣，田侵海樹耕。", "吳山鍾入越，蓮葉吹搖旌。", "詩異石門思，濤來向越迎。"]'),
('8e8f7ff8-9aad-45e3-ab83-99fcecdb1783','夜集田卿宅','賈島','唐','唐诗','tang','','[]','朗詠高齋下，如將古調彈。',48,'全唐诗/poet.tang.31000.json','["朗詠高齋下，如將古調彈。", "翻鴻向桂水，來雪渡桑乾。", "滴滴玉漏曙，翛翛竹籟殘。", "曩年曾宿此，亦值五陵寒。"]'),
('83f1e49f-39e4-4f77-b193-a5a4fe83b4cb','寄山友長孫棲嶠','賈島','唐','唐诗','tang','','[]','此時氣蕭颯，琴院可應關。',48,'全唐诗/poet.tang.31000.json','["此時氣蕭颯，琴院可應關。", "鶴似君無事，風吹雨遍山。", "松生青石上，泉落白雲間。", "有徑連高頂，心期相與還。"]'),
('57b35d65-a22c-4bf3-b5f8-7bfab1a519fe','詶厲玄','賈島','唐','唐诗','tang','','[]','我來從北鄙，子省涉西陵。',48,'全唐诗/poet.tang.31000.json','["我來從北鄙，子省涉西陵。", "白髮初相識，秋山擬共登。", "鄰居帝城雨，會宿御溝冰。", "未報見貽作，耿然中夜興。"]'),
('6a43cbc2-0caa-4019-8750-5ebbe6ad196b','送劉式洛中覲省','賈島','唐','唐诗','tang','','[]','晴峯三十六，侍立上春臺。',48,'全唐诗/poet.tang.31000.json','["晴峯三十六，侍立上春臺。", "同宿別離恨，共看星月迴。", "野鶯臨苑語，河櫂歷江來。", "便寄相思札，緘封花下開。"]'),
('77efa3f1-80d9-44c9-a795-42b9d984cd66','送空公往金州','賈島','唐','唐诗','tang','','[]','七百里山水，手中楖栗麤。',48,'全唐诗/poet.tang.31000.json','["七百里山水，手中楖栗麤。", "松生師坐石，潭滌祖傳盂。", "長擬老嶽嶠，又聞思海湖。", "惠能同俗姓，不是嶺南盧。"]'),
('d4b6f017-0f4f-4acd-a552-20d568b43af8','贈紹明上人','賈島','唐','唐诗','tang','','[]','未住青雲室，中秋獨往年。',48,'全唐诗/poet.tang.31000.json','["未住青雲室，中秋獨往年。", "上方嵩若寺，下視雨和烟。", "祖豈無言去，心因斷臂傳。", "不知能已後，更有幾燈然。"]'),
('6b39d37a-34ac-4bf2-a592-8de3df388685','贈弘泉上人','賈島','唐','唐诗','tang','','[]','洗足下藍嶺，古師精進同。',48,'全唐诗/poet.tang.31000.json','["洗足下藍嶺，古師精進同。", "心知溪卉長，居此玉林空。", "西殿宵燈磬，東林曙雨風。", "舊峯鄰太白，石座雨苔濛。"]'),
('02198763-6d7a-456f-85a6-840183fa7932','送宣皎上人遊太白','賈島','唐','唐诗','tang','','[]','剃髮鬢無雪，去年三十三。',48,'全唐诗/poet.tang.31000.json','["剃髮鬢無雪，去年三十三。", "山過春草寺，磬度落花潭。", "得句才鄰約，論宗意在南。", "峯靈疑懶下，蒼翠太虛參。"]'),
('ee996d66-0273-4fe5-afaf-a802a82aaaee','病起','賈島','唐','唐诗','tang','','[]','高丘歸未得，空自責遲迴。',48,'全唐诗/poet.tang.31000.json','["高丘歸未得，空自責遲迴。", "身事豈能遂，蘭花又已開。", "病令新作少，雨阻故人來。", "燈下南華卷，袪愁當酒杯。"]'),
('2babaa7e-6311-4c0a-b5c7-35823d1e80e2','送殷侍御赴同州','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','馮翊蒲西郡，沙岡擁地形。',48,'全唐诗/poet.tang.31000.json','["馮翊蒲西郡，沙岡擁地形。", "中條全離嶽，清渭半和涇。", "夜暮眠明月，秋深至洞庭。", "猶來交辟士，事別偃林扃。"]'),
('49467b77-e3c1-4922-bb03-adf64c8b0a34','送沈鶴','賈島','唐','唐诗','tang','','[]','家楚壻於秦，攜妻去養親。',48,'全唐诗/poet.tang.31000.json','["家楚壻於秦，攜妻去養親。", "陸行千里外，風卷一帆新。", "夜泊疏山雨，秋吟搗藥輪。", "蕪城登眺作，才動廣陵人。"]'),
('f194e7dc-9789-4c14-803c-c5d625fbba8d','秋夜仰懷錢孟二公琴客會','賈島','唐','唐诗','tang','','[]','月色四時好，秋光君子知。',48,'全唐诗/poet.tang.31000.json','["月色四時好，秋光君子知。", "南山昨夜雨，爲我寫清規。", "獨鶴聳寒骨，高杉韻細颸。", "仙家縹緲弄，髣髴此中期。"]'),
('4afc801c-9158-4928-930e-545d534a986f','贈李金州','賈島','唐','唐诗','tang','','[]','綺里祠前後，山程踐白雲。',48,'全唐诗/poet.tang.31000.json','["綺里祠前後，山程踐白雲。", "泝流隨大斾，登岸見全軍。", "曉角吹人夢，秋風卷雁羣。", "霧開方露日，漢水底沙分。"]'),
('ed4aaa57-199d-4d4e-a754-5600a559610f','酬姚合校書','賈島','唐','唐诗','tang','','[]','因貧行遠道，得見舊交遊。',48,'全唐诗/poet.tang.31000.json','["因貧行遠道，得見舊交遊。", "美酒易傾盡，好詩難卒酬。", "公堂朝共到，私第夜相留。", "不覺入關晚，別來林木秋。"]'),
('266532ab-b212-4e5c-afc0-9ea092589c38','送獨孤馬二秀才居明月山讀書','賈島','唐','唐诗','tang','','[]','濯志俱高潔，儒科慕冉顏。',48,'全唐诗/poet.tang.31000.json','["濯志俱高潔，儒科慕冉顏。", "家辭臨水郡，雨到讀書山。", "棲鳥椶花上，聲鐘礫閣間。", "寂寥窗戶外，時見一舟還。"]'),
('5d7c4f65-58ea-4f21-854b-499ab7540559','病蟬','賈島','唐','唐诗','tang','','[]','病蟬飛不得，向我掌中行。',48,'全唐诗/poet.tang.31000.json','["病蟬飛不得，向我掌中行。", "拆翼猶能薄，酸吟尚極清。", "露華凝在腹，塵點誤侵睛。", "黃雀幷鳶鳥，俱懷害爾情。"]'),
('2cdf47f1-8f58-4758-be40-1d0a5048ae69','青門里作','賈島','唐','唐诗','tang','','[]','燕存鴻已過，海內幾人愁。',48,'全唐诗/poet.tang.31000.json','["燕存鴻已過，海內幾人愁。", "欲問南宗理，將歸北嶽修。", "若無攀桂分，秖是臥雲休。", "泉樹一爲別，依稀三十秋。"]'),
('b4d8cc57-2f58-402b-9ec2-ef93cec8aafa','盧秀才南臺','賈島','唐','唐诗','tang','','[]','居在青門里，臺當千萬岑。',48,'全唐诗/poet.tang.31000.json','["居在青門里，臺當千萬岑。", "下因岡助勢，上有樹交陰。", "陵遠根纔近，空長畔可尋。", "新晴登嘯處，驚起宿枝禽。"]'),
('9872a085-af71-44ea-b8fd-d81f508497d1','寄李輈侍郎','賈島','唐','唐诗','tang','','[]','終過盟津書，分明夢不虛。',144,'全唐诗/poet.tang.31000.json','["終過盟津書，分明夢不虛。", "人從清渭別，地隔太行餘。", "賓幕誰嫌靜，公門但晏如。", "櫑鞞乾霹靂，斜漢溼蟾蜍。", "追琢垂今後，敦龐得古初。", "井臺憐操築，漳岸想丕疏。", "亦冀鏗珉珮，終當直石渠。", "此身多抱疾，幽里近營居。", "憶漱蘇門澗，經浮楚澤瀦。", "松栽侵古影，葷斷尚芹葅。", "語嘿曾延接，心源離滓淤。", "誰言姓琴氏，獨跨角生魚。"]'),
('a3add393-cedc-4577-b5db-e7785019a281','寄令狐綯相公','賈島','唐','唐诗','tang','','[]','驢駿勝羸馬，東川路匪賒。',144,'全唐诗/poet.tang.31000.json','["驢駿勝羸馬，東川路匪賒。", "一緘論賈誼，三蜀寄嚴家。", "澄徹霜江水，分明露石沙。", "話言聲及政，棧閣谷離斜。", "自著衣偏暖，誰憂雪六花。", "裹裳留闊襆，防患與通茶。", "山館中宵起，星河殘月華。", "雙僮前日雇，數口向天涯。", "良樂知騏驥，張雷驗鏌鋣。", "謙光賢將相，別紙聖龍蛇。", "豈有斯言玷，應無白璧瑕。", "不妨圓魄裏，人亦指蝦蟇。"]'),
('c3475054-935b-47c0-aac8-d770f46d7e92','再投李益常侍','賈島','唐','唐诗','tang','','[]','何處初投刺，當時赴尹京。',72,'全唐诗/poet.tang.31000.json','["何處初投刺，當時赴尹京。", "淹留花柳變，然諾肺腸傾。", "避暑蟬移樹，高眠雁過城。", "人家嵩嶽色，公府洛河聲。", "聯句逢秋盡，嘗茶見月生。", "新衣裁白苧，思從曲江行。"]'),
('75da8f5c-0f91-4d83-851e-3f74b34e1eff','積雪','賈島','唐','唐诗','tang','','[]','昔屬時霖滯，今逢臘雪多。',84,'全唐诗/poet.tang.31000.json','["昔屬時霖滯，今逢臘雪多。", "南猜飄桂渚，北訝雨交河。", "盡滅平蕪色，彌重古木柯。", "空中離白氣，島外下滄波。", "隱者迷樵道，朝人冷玉珂。", "夕繁仍晝密，漏間復鐘和。", "想積高嵩頂，新秋皎月過。"]'),
('7c84b0f3-ef7a-4a2b-bf4d-03572a6c79f9','過楊道士居','賈島','唐','唐诗','tang','','[]','先生修道處，茆屋遠囂氛。',48,'全唐诗/poet.tang.31000.json','["先生修道處，茆屋遠囂氛。", "叩齒坐明月，搘頤望白雲。", "精神含藥色，衣服帶霞紋。", "無話瀛洲路，多年別少君。"]'),
('ef6d055e-823a-4744-875e-26aff4ed8998','贈僧','賈島','唐','唐诗','tang','','[]','亂山秋木穴，裏有靈蛇藏。',48,'全唐诗/poet.tang.31000.json','["亂山秋木穴，裏有靈蛇藏。", "鐵錫挂臨海，石樓聞異香。", "出塵頭未白，入定衲凝霜。", "莫話五湖事，令人心欲狂。"]'),
('2b81132b-59bb-49ec-babf-894ade00e4d8','送友人遊塞','賈島','唐','唐诗','tang','','[]','飄蓬多塞下，君見益潸然。',48,'全唐诗/poet.tang.31000.json','["飄蓬多塞下，君見益潸然。", "逈磧沙銜日，長河水接天。", "夜泉行客火，曉戍向京煙。", "少結相思恨，佳期芳草前。"]'),
('929b8cd3-572f-4f0f-a6ea-f6bdbf9484d9','思遊邊友人','賈島','唐','唐诗','tang','','[]','凝愁對孤燭，昨日飲離杯。',48,'全唐诗/poet.tang.31000.json','["凝愁對孤燭，昨日飲離杯。", "葉下故人去，天中新雁來。", "連沙秋草薄，帶雪暮山開。", "苑北紅塵道，何時見遠迴。"]'),
('e344072f-9493-4281-afcd-6a496f21fe20','秋暮寄友人','賈島','唐','唐诗','tang','','[]','寥落關河暮，霜風樹葉低。',48,'全唐诗/poet.tang.31000.json','["寥落關河暮，霜風樹葉低。", "遠天垂地外，寒日下峯西。", "有志煙霞切，無家歲月迷。", "清宵話白閣，已負十年棲。"]'),
('8448fb5d-ae18-4d13-9a21-ca15afb2b3ab','寄令狐綯相公','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','官高頻敕授，老免把犁鋤。',48,'全唐诗/poet.tang.31000.json','["官高頻敕授，老免把犁鋤。", "一主長江印，三封東省書。", "不無濠上思，唯食圃中蔬。", "夢幻將泡影，浮生事只如。"]'),
('1ce6b4d1-a880-40df-8da8-e49bec9cc5e7','和孟逸人林下道情','賈島','唐','唐诗','tang','','[]','四氣相陶鑄，中庸道豈銷。',48,'全唐诗/poet.tang.31000.json','["四氣相陶鑄，中庸道豈銷。", "夏雲生此日，春色盡今朝。", "陋巷貧無悶，毘耶疾未調。", "已栽天末柏，合抱豈非遙。"]'),
('26cba10d-6dde-447b-8f06-29c68533fe98','宿姚少府北齋','賈島','唐','唐诗','tang','','[]','石溪同夜泛，復此北齋期。',48,'全唐诗/poet.tang.31000.json','["石溪同夜泛，復此北齋期。", "鳥絕吏歸後，蛩鳴客臥時。", "鏁城涼雨細，開印曙鐘遲。", "憶此漳川岸，如今是別離。"]'),
('d897d962-5d51-46cc-9155-e505580398fe','雪晴晚望','賈島','唐','唐诗','tang','','["\u5199\u96ea", "\u5199\u666f", "\u6292\u60c5", "\u96ea"]','倚杖望晴雪，溪雲幾萬重。',48,'全唐诗/poet.tang.31000.json','["倚杖望晴雪，溪雲幾萬重。", "樵人歸白屋，寒日下危峯。", "野火燒岡草，斷煙生石松。", "却回山寺路，聞打暮天鐘。"]'),
('7f24bfcb-5619-43b3-8879-620f5a73e545','送崔嶠遊瀟湘','賈島','唐','唐诗','tang','','[]','功烈尚書孫，琢磨風雅言。',48,'全唐诗/poet.tang.31000.json','["功烈尚書孫，琢磨風雅言。", "渡河山鑿處，陟峴漢灘喧。", "夢想吟天目，宵同話石門。", "楓林葉欲下，極浦月清暾。"]'),
('53765d53-3bc1-4ed5-8fc4-452473913b3b','寄朱錫珪','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','遠泊與誰同，來從古木中。',48,'全唐诗/poet.tang.31000.json','["遠泊與誰同，來從古木中。", "長江人釣月，曠野火燒風。", "夢澤吞楚大，閩山阨海叢。", "此時檣底水，濤起屈原通。"]'),
('6a781aac-8711-4ca6-a54d-b3e8693e8f55','馬戴居華山因寄','賈島','唐','唐诗','tang','','[]','玉女洗頭盆，孤高不可言。',48,'全唐诗/poet.tang.31000.json','["玉女洗頭盆，孤高不可言。", "瀑流蓮嶽頂，河注華山根。", "絕雀林藏鶻，無人境有猨。", "秋蟾纔過雨，石上古松門。"]'),
('d307d844-01a2-472e-baf5-8ea7f7fda096','寄胡遇','賈島','唐','唐诗','tang','','[]','一自殘春別，經炎復到涼。',48,'全唐诗/poet.tang.31000.json','["一自殘春別，經炎復到涼。", "螢從枯樹出，蛩入破堦藏。", "落葉書勝紙，閑砧坐當林。", "東門因送客，相訪也何妨。"]'),
('65326ea9-c944-4a08-9102-1adabbab4647','送李戎扶侍往壽安','賈島','唐','唐诗','tang','','[]','二千餘里路，一半是波濤。',48,'全唐诗/poet.tang.31000.json','["二千餘里路，一半是波濤。", "未曉著衣起，出城逢日高。", "關山多寇盜，扶侍帶弓刀。", "臨別不揮淚，誰知心鬱陶。"]'),
('c7a27559-ee67-48d9-a98c-2444d05a5245','送孫逸人','賈島','唐','唐诗','tang','','[]','衣屨猶同俗，妻兒亦宛然。',48,'全唐诗/poet.tang.31000.json','["衣屨猶同俗，妻兒亦宛然。", "不餐能累月，無病已多年。", "是藥皆諳性，令人漸信仙。", "杖頭書數卷，荷入翠微煙。"]'),
('15c4dc01-80ca-489c-b87f-4c02b6231cb8','寄華山僧','賈島','唐','唐诗','tang','','[]','遙知白石室，松柏隱朦朧。',48,'全唐诗/poet.tang.31000.json','["遙知白石室，松柏隱朦朧。", "月落看心次，雲生閉目中。", "五更鐘隔嶽，萬尺水懸空。", "苔蘚嵌巖所，依稀有徑通。"]'),
('812b219c-4999-45e4-9f14-63bee2f7a4c7','送李登少府','賈島','唐','唐诗','tang','','[]','伊陽耽酒尉，朗詠醉醒新。',48,'全唐诗/poet.tang.31000.json','["伊陽耽酒尉，朗詠醉醒新。", "應見嵩山裏，明年躑躅春。", "一千尋樹直，三十六峯鄰。", "流水潺潺處，堅貞玉澗珉。"]'),
('5d50b59a-2afb-46da-a485-39ea3f0a8bc3','易州過郝逸人居','賈島','唐','唐诗','tang','','[]','每逢詞翰客，邀我共尋君。',48,'全唐诗/poet.tang.31000.json','["每逢詞翰客，邀我共尋君。", "果見閑居賦，未曾流俗聞。", "也知鄰市井，宛似出囂氛。", "却笑巢由輩，何須隱白雲。"]'),
('a938c35a-36fb-4b1e-b425-180f1f94a101','詶鄠縣李廓少府見寄','賈島','唐','唐诗','tang','','[]','稍憐公事退，復遇夕陽時。',48,'全唐诗/poet.tang.31000.json','["稍憐公事退，復遇夕陽時。", "北朔霜凝竹，南山水入籬。", "吟懷滄海侶，空問白雲師。", "恨不相從去，心惟野鶴知。"]'),
('41c87e51-e9ce-4968-82c7-f1971c2647b4','淨業寺與前鄠縣李廓少府同宿','賈島','唐','唐诗','tang','','[]','來從城上峯，京寺暮相逢。',48,'全唐诗/poet.tang.31000.json','["來從城上峯，京寺暮相逢。", "往往語復默，微微雨灑松。", "家貧初罷吏，年長畏聞蛩。", "前日獨拘束，披衣起曉鐘。"]'),
('87c03a72-d792-4cdd-8d43-22e777809302','送南卓歸京','賈島','唐','唐诗','tang','','[]','殘春別鏡陂，罷郡未霜髭。',72,'全唐诗/poet.tang.31000.json','["殘春別鏡陂，罷郡未霜髭。", "行李逢炎暑，山泉滿路岐。", "雲藏巢鶴樹，風觸囀鶯枝。", "三省同虛位，雙旌帶去思。", "入城宵夢後，待漏月沈時。", "長策幷忠告，從容寫玉墀。"]'),
('3d2a6786-4683-45f0-81fb-d83cb21c7047','臥疾走筆詶韓愈書問','賈島','唐','唐诗','tang','','[]','一臥三四旬，數書惟獨君。',48,'全唐诗/poet.tang.31000.json','["一臥三四旬，數書惟獨君。", "願爲出海月，不作歸山雲。", "身上衣頻寄，甌中物亦分。", "欲知強健否，病鶴未離羣。"]'),
('c28fa9ab-884d-4058-8e83-354c49e222d6','長孫霞李溟自紫閣白閣二峯見訪','賈島','唐','唐诗','tang','','[]','寂寞吾廬貧，同來二閣人。',48,'全唐诗/poet.tang.31000.json','["寂寞吾廬貧，同來二閣人。", "所論唯野事，招作住雲鄰。", "古寺期秋宿，平林散早春。", "漱流今已矣，巢許豈堯臣。"]'),
('47b3a6a9-7b4c-4201-8e01-5b4794c4d135','送惟一遊清涼寺','賈島','唐','唐诗','tang','','[]','去有巡臺侶，荒溪衆樹分。',48,'全唐诗/poet.tang.31000.json','["去有巡臺侶，荒溪衆樹分。", "瓶殘秦地水，錫入晉山雲。", "秋月離喧見，寒泉出定聞。", "人間臨欲別，旬日雨紛紛。"]'),
('6c1f90ef-c33b-4806-b87c-01faedde8b49','鄭尚書新開涪江二首 一','賈島','唐','唐诗','tang','','[]','岸鑿青山破，江開白浪寒。',48,'全唐诗/poet.tang.31000.json','["岸鑿青山破，江開白浪寒。", "日沈源出海，春至草生灘。", "梓匠防波溢，蓬仙畏水乾。", "從今疏決後，任雨滯峯巒。"]'),
('664671a1-232e-4309-89e1-50dfe57c7493','鄭尚書新開涪江二首 二','賈島','唐','唐诗','tang','','[]','不侵南畝務，已拔北江流。',48,'全唐诗/poet.tang.31000.json','["不侵南畝務，已拔北江流。", "涪水方移岸，潯陽有到舟。", "潭澄初擣藥，波動乍垂鉤。", "山可疏三里，從知歷億秋。"]'),
('d3ae1182-a801-4cb9-aa0f-3c12e6012654','寄喬侍郎','賈島','唐','唐诗','tang','','[]','大寧猶未到，曾渡北浮橋。',48,'全唐诗/poet.tang.31000.json','["大寧猶未到，曾渡北浮橋。", "曉出爬船寺，手擎紫栗條。", "差池不相見，悵望至今朝。", "近日營家計，繩懸一小瓢。"]'),
('74625e13-92fb-4f31-96cd-baa572883e63','送去華法師','賈島','唐','唐诗','tang','','[]','在越居何寺，東南水路歸。',48,'全唐诗/poet.tang.31000.json','["在越居何寺，東南水路歸。", "秋江洗一鉢，寒日曬三衣。", "默聽鴻聲盡，行看葉影飛。", "囊中無寶貨，船戶夜扃稀。"]'),
('3a4829df-0a0d-4e78-9d28-346ffd9ed07d','送蔡京','賈島','唐','唐诗','tang','','["\u6cf0\u5c71"]','躍蹄歸魯日，帶漏別秦星。',48,'全唐诗/poet.tang.31000.json','["躍蹄歸魯日，帶漏別秦星。", "易折芳條桂，難窮邃義經。", "登封多泰嶽，巡狩徧滄溟。", "家在何林下，梁山翠滿庭。"]'),
('924ce680-c634-4699-8864-21c7b1a92684','慈恩寺上座院','賈島','唐','唐诗','tang','','["\u8861\u5c71"]','未委衡山色，何如對塔峯。',48,'全唐诗/poet.tang.31000.json','["未委衡山色，何如對塔峯。", "曩宵曾宿此，今夕值秋濃。", "羽族棲煙竹，寒流帶月鐘。", "井甘源起異，泉湧漬苔封。"]'),
('972dc507-f58c-4a10-9f81-e2c497c34425','題朱慶餘所居','賈島','唐','唐诗','tang','','[]','天寒吟竟曉，古屋瓦生松。',48,'全唐诗/poet.tang.31000.json','["天寒吟竟曉，古屋瓦生松。", "寄信船一隻，隔鄉山萬重。", "樹來沙岸鳥，窗度雪樓鐘。", "每憶江中嶼，更看城上峯。"]'),
('9127714f-a12b-4610-a965-8f82d00e1a07','送黃知新歸安南','賈島','唐','唐诗','tang','','[]','池亭沈飲徧，非獨曲江花。',48,'全唐诗/poet.tang.31000.json','["池亭沈飲徧，非獨曲江花。", "地遠路穿海，春歸冬到家。", "火山難下雪，瘴土不生茶。", "知決移來計，相逢期尚賒。"]'),
('53607c0e-81e8-400d-a768-cecc6c3f2119','贈胡禪歸','賈島','唐','唐诗','tang','','[]','自是根機鈍，非關夏臘深。',48,'全唐诗/poet.tang.31000.json','["自是根機鈍，非關夏臘深。", "秋來江上寺，夜坐嶺南心。", "井鑿山含月，風吹磬出林。", "祖師攜隻履，去路杳難尋。"]'),
('35d68da3-1c96-456e-8dbb-76bd3a2bbe4f','元日女道士受籙','賈島','唐','唐诗','tang','','[]','元日更新夜，齋身稱淨衣。',48,'全唐诗/poet.tang.31000.json','["元日更新夜，齋身稱淨衣。", "數星連斗出，萬里斷雲飛。", "霜下磬聲在，月高壇影微。", "立聽師語了，左肘繫符歸。"]'),
('519c23bf-c0ba-4969-814f-115ffc4e3b80','重與彭兵曹','賈島','唐','唐诗','tang','','[]','故人在城裏，休寄海邊書。',48,'全唐诗/poet.tang.31000.json','["故人在城裏，休寄海邊書。", "漸去老不遠，別來情豈疎。", "硯冰催臘日，山雀到貧居。", "每有平戎計，官家別敕除。"]'),
('9b06de45-88c1-4ba6-b715-cb6eed69c02a','贈莊上人','賈島','唐','唐诗','tang','','[]','不語焚香坐，心知道已成。',48,'全唐诗/poet.tang.31000.json','["不語焚香坐，心知道已成。", "流年衰此世，定力見他生。", "暮雪餘春冷，寒燈續晝明。", "尋常五侯至，敢望下堦迎。"]'),
('f6bc3538-77b3-4cbc-bf01-1672db5a6fb8','落第東歸逢僧伯陽','賈島','唐','唐诗','tang','','[]','相逢須語笑，人世別離頻。',96,'全唐诗/poet.tang.31000.json','["相逢須語笑，人世別離頻。", "曉至長侵月，思鄉動隔春。", "見僧心暫靜，從俗事多迍。", "宇宙詩名小，山河客路新。", "翠桐猶入爨，清鏡未辭塵。", "逸足思奔驥，隨羣且退鱗。", "宴乖紅杏寺，愁在綠楊津。", "老病難爲樂，開眉賴故人。"]'),
('2b0d9223-7f7a-43dc-a7f7-074f65f14a50','皇甫主簿期遊山不及赴','賈島','唐','唐诗','tang','','[]','休官匹馬在，新意入山中。',48,'全唐诗/poet.tang.31000.json','["休官匹馬在，新意入山中。", "更住應難遂，前期恨不同。", "集蟬苔樹僻，留客雨堂空。", "深夜誰相訪，惟當清淨翁。"]'),
('1603e614-b7c1-469a-bd5e-60cfb9ee66e4','宿成湘林下','賈島','唐','唐诗','tang','','[]','相訪夕陽時，千株木未衰。',48,'全唐诗/poet.tang.31000.json','["相訪夕陽時，千株木未衰。", "石泉流出谷，山雨滴棲鴟。", "漏向燈聽數，酒因客寢遲。", "今宵不盡興，更有月明期。"]'),
('cbf9bc53-7beb-43b3-a6d9-aefa39a5d817','喜雍陶至','賈島','唐','唐诗','tang','','[]','今朝笑語同，幾日百憂中。',48,'全唐诗/poet.tang.31000.json','["今朝笑語同，幾日百憂中。", "鳥度劒門靜，蠻歸瀘水空。", "步霜吟菊畔，待月坐林東。", "且莫孤此興，勿論窮與通。"]'),
('4d7cc07c-efcc-4c9f-b7ea-7c42cb14849b','酬胡遇','賈島','唐','唐诗','tang','','[]','麗句傳人口，科名立可圖。',48,'全唐诗/poet.tang.31000.json','["麗句傳人口，科名立可圖。", "移居見山燒，買樹帶巢烏。", "遊遠風濤急，吟清雪月孤。", "却思初識面，仍未有多鬚。"]'),
('3da8fb0a-9cd6-4c16-b725-d333312b9d09','宿慈恩寺郁公房','賈島','唐','唐诗','tang','','[]','病身來寄宿，自掃一牀閑。',48,'全唐诗/poet.tang.31000.json','["病身來寄宿，自掃一牀閑。", "反照臨江磬，新秋過雨山。", "竹陰移冷月，荷氣帶禪關。", "獨住天台意，方從內請還。"]'),
('6dec54f3-9937-42b2-957a-b75fd837aa09','送褚山人歸日本','賈島','唐','唐诗','tang','','[]','懸帆待秋水，去入杳冥間。',48,'全唐诗/poet.tang.31000.json','["懸帆待秋水，去入杳冥間。", "東海幾年別，中華此日還。", "岸遙生白髮，波盡露青山。", "隔水相思在，無書也是閑。"]'),
('4bc9e121-f932-49f0-9043-04f7341f479c','寄韓湘','賈島','唐','唐诗','tang','','[]','過嶺行多少，潮州漲滿川。',48,'全唐诗/poet.tang.31000.json','["過嶺行多少，潮州漲滿川。", "花開南去後，水凍北歸前。", "望鷺吟登閣，聽猨淚滴船。", "相思堪面話，不著尺書傳。"]'),
('8885fe11-cf97-4267-bb7b-d457859c3b04','雨夜寄馬戴','賈島','唐','唐诗','tang','','[]','芳林杏花樹，花落子西東。',48,'全唐诗/poet.tang.31000.json','["芳林杏花樹，花落子西東。", "今夕曲江雨，寒催朔北風。", "鄉書滄海絕，隱路翠微通。", "寂寂相思際，孤釭殘漏中。"]'),
('381c42eb-dc7a-40e4-abf5-a87f9828712e','喜無可上人遊山回','賈島','唐','唐诗','tang','','[]','一食復何如，尋山無定居。',48,'全唐诗/poet.tang.31000.json','["一食復何如，尋山無定居。", "相逢新夏滿，不見半年餘。", "聽話龍潭雪，休傳鳥道書。", "別來還似舊，白髮日高梳。"]'),
('be4e7fdb-daac-43a9-891d-987d0947dfbf','寄毘陵徹公','賈島','唐','唐诗','tang','','[]','身依吳寺老，黃葉幾迴看。',48,'全唐诗/poet.tang.31000.json','["身依吳寺老，黃葉幾迴看。", "早講林霜在，孤禪隙月殘。", "井通潮浪遠，鐘與角聲寒。", "已有南遊約，誰言禮謁難。"]'),
('16a94311-5fda-45a5-a594-242ad23b4748','送韋瓊校書','賈島','唐','唐诗','tang','','[]','賓佐兼歸覲，此行江漢心。',48,'全唐诗/poet.tang.31000.json','["賓佐兼歸覲，此行江漢心。", "別離從闕下，道路向山陰。", "孤嶼消寒沫，空城滴夜霖。", "若邪溪畔寺，秋色共誰尋。"]'),
('4133e659-3ad8-4fef-92c5-c0f4fac5c387','寄劉侍御','賈島','唐','唐诗','tang','','[]','衣多苔蘚痕，猶擬更趨門。',48,'全唐诗/poet.tang.31000.json','["衣多苔蘚痕，猶擬更趨門。", "自夏雖無病，經秋不過原。", "積泉留岱鳥，疊岫隔巴猨。", "琴月西齋集，如今豈復言。"]'),
('23b194b4-a3d3-4d88-b41f-d0e34503bb81','送穆少府知眉州','賈島','唐','唐诗','tang','','[]','劒門倚青漢，君昔未曾過。',48,'全唐诗/poet.tang.31000.json','["劒門倚青漢，君昔未曾過。", "日暮行人少，山深異鳥多。", "猨啼和峽雨，棧盡到江波。", "一路白雲裏，飛泉灑薜蘿。"]'),
('e8f0cbc6-63ed-431c-963a-9a97f83e4bd1','二月晦日留別鄠中友人','賈島','唐','唐诗','tang','','[]','立馬柳花裏，別君當酒酣。',48,'全唐诗/poet.tang.31000.json','["立馬柳花裏，別君當酒酣。", "春風漸向北，雲雁不飛南。", "明曉日初一，今年月又三。", "鞭羸去暮色，遠嶽起煙嵐。"]'),
('82528aeb-1624-44c2-8460-669f4a9d1dff','送李校書赴吉期','賈島','唐','唐诗','tang','','[]','筮算重重吉，良期詎可遷。',48,'全唐诗/poet.tang.31000.json','["筮算重重吉，良期詎可遷。", "不同牛女夜，是配鳳凰年。", "佩玉春風裏，題章蠟燭前。", "詩書與箴訓，夫哲又妻賢。"]'),
('0dec7640-c4d5-480c-85c8-31ad8ebccda1','宿孤館','賈島','唐','唐诗','tang','','[]','落日投村戍，愁生爲客途。',48,'全唐诗/poet.tang.31000.json','["落日投村戍，愁生爲客途。", "寒山晴後綠，秋月夜來孤。", "橘樹千株在，漁家一半無。", "自知風水靜，舟繫岸邊蘆。"]'),
('39599798-21e2-4df5-bddb-1b244bd5af89','哭宗密禪師','賈島','唐','唐诗','tang','','[]','鳥道雪岑巔，師亡誰去禪。',48,'全唐诗/poet.tang.31000.json','["鳥道雪岑巔，師亡誰去禪。", "几塵增滅後，樹色改生前。", "層塔當松吹，殘蹤傍野泉。", "唯嗟聽經虎，時到壞菴邊。"]'),
('54d324bf-a9cb-4156-9cb9-b32aef00ea68','宿山寺','賈島','唐','唐诗','tang','','["\u6292\u60c5", "\u5bfa\u5e99", "\u5199\u666f"]','衆岫聳寒色，精廬向此分。',48,'全唐诗/poet.tang.31000.json','["衆岫聳寒色，精廬向此分。", "流星透疎木，走月逆行雲。", "絕頂人來少，高松鶴不羣。", "一僧年八十，世事未曾聞。"]'),
('e94507f7-8771-470a-83b3-12c63a5a5c41','送友人如邊','賈島','唐','唐诗','tang','','[]','去日重陽後，前程菊正芳。',48,'全唐诗/poet.tang.31000.json','["去日重陽後，前程菊正芳。", "行車輾秋嶽，落葉墜寒霜。", "雲入漢天白，風高磧色黃。", "蒲輪待恐晚，求薦向諸方。"]'),
('443f86fe-9ab9-4376-b0ab-0a80736e6021','題竹谷上人院','賈島','唐','唐诗','tang','','[]','禪庭高鳥道，迴望極川原。',48,'全唐诗/poet.tang.31000.json','["禪庭高鳥道，迴望極川原。", "樵徑連峯頂，石泉通竹根。", "木深猶積雪，山淺未聞猨。", "欲別塵中苦，願師貽一言。"]'),
('b06330d8-6ac1-4917-8670-a06cbc629315','京北原作','賈島','唐','唐诗','tang','','[]','登原見城闕，策蹇思炎天。',48,'全唐诗/poet.tang.31000.json','["登原見城闕，策蹇思炎天。", "日午路中客，槐花風處蟬。", "遠山秦木上，清渭漢陵前。", "何事居人世，皆從名利牽。"]'),
('5af9d4ac-16d1-4fe2-82a3-56a8cf5d4c96','寄江上人','賈島','唐','唐诗','tang','','[]','紫閣舊房在，新家中嶽東。',48,'全唐诗/poet.tang.31000.json','["紫閣舊房在，新家中嶽東。", "煙波千里隔，消息一朝通。", "寒日汀洲路，秋晴島嶼風。", "分明杜陵葉，別後兩經紅。"]'),
('4b7df15c-0382-4925-a6f2-f04a44bf03d4','送僧歸太白山','賈島','唐','唐诗','tang','','[]','堅冰連夏處，太白接青天。',48,'全唐诗/poet.tang.31000.json','["堅冰連夏處，太白接青天。", "雲塞石房路，峯明雨外巔。", "夜禪臨虎穴，寒漱撇龍泉。", "後會不期日，相逢應信緣。"]'),
('6530401f-631b-426e-9abd-4b7403e0b69d','暮過山村','賈島','唐','唐诗','tang','','[]','數里聞寒水，山家少四鄰。',48,'全唐诗/poet.tang.31000.json','["數里聞寒水，山家少四鄰。", "怪禽啼曠野，落日恐行人。", "初月未終夕，邊烽不過秦。", "蕭條桑柘外，煙火漸相親。"]'),
('69f4cf11-aa0b-43da-ba43-574faecb4f97','鷺鷥','賈島','唐','唐诗','tang','','[]','求魚未得食，沙岸往來行。',48,'全唐诗/poet.tang.31000.json','["求魚未得食，沙岸往來行。", "島月獨棲影，暮天寒過聲。", "墮巢因木折，失侶遇弦驚。", "頻向煙霄望，吾知爾去程。"]'),
('1aa6a5d2-d9c1-432c-bd71-9a6c4804c963','內道場僧弘紹','賈島','唐','唐诗','tang','','[]','麟德燃香請，長安春幾回。',48,'全唐诗/poet.tang.31000.json','["麟德燃香請，長安春幾回。", "夜閑同像寂，晝定爲吾開。", "講罷松根老，經浮海水來。", "六年雙足履，只步院中苔。"]'),
('53c3bf2e-7797-466f-ae05-def157c59a6d','蔣亭和蔡湘州','賈島','唐','唐诗','tang','','[]','蔣宅爲亭榭，蔡城東郭門。',48,'全唐诗/poet.tang.31000.json','["蔣宅爲亭榭，蔡城東郭門。", "潭連秦相井，松老漢朝根。", "已積蒼苔徧，何曾舊徑存。", "高齋無事後，時復一攜尊。"]'),
('0e5da35a-a97a-42ca-8ca5-8494952ded7f','光州王建使君水亭作','賈島','唐','唐诗','tang','','[]','楚水臨軒積，澄鮮一畝餘。',48,'全唐诗/poet.tang.31000.json','["楚水臨軒積，澄鮮一畝餘。", "柳根連岸盡，荷葉出萍初。", "極浦清相似，幽禽到不虛。", "夕陽庭際眺，槐雨滴疎疎。"]'),
('edbd6e1a-a7f7-4d2d-a65d-de9edd6a443f','留別光州王使君建','賈島','唐','唐诗','tang','','[]','杜陵千里外，期在末秋歸。',48,'全唐诗/poet.tang.31000.json','["杜陵千里外，期在末秋歸。", "既見林花落，須防木葉飛。", "楚從何地盡，淮隔數峯微。", "迴首餘霞失，斜陽照客衣。"]'),
('4c420df8-b8d3-4f50-ba05-b1c71c5898d3','宿姚合宅寄張司業籍','賈島','唐','唐诗','tang','','[]','閑宵因集會，柱史話先生。',48,'全唐诗/poet.tang.31000.json','["閑宵因集會，柱史話先生。", "身愛無一事，心期往四明。", "松枝影搖動，石磬響寒清。", "誰伴南齋宿，月高霜滿城。"]'),
('36f0b26f-4ce1-4088-b232-24d7d8ee9912','哭張籍','賈島','唐','唐诗','tang','','[]','精靈歸恍惚，石磬韻曾聞。',48,'全唐诗/poet.tang.31000.json','["精靈歸恍惚，石磬韻曾聞。", "即日是前古，誰人耕此墳。", "舊遊孤櫂遠，故域九江分。", "本欲蓬瀛去，餐芝御白雲。"]'),
('01b75e5e-2cb4-45dd-90df-90dd1d4761c5','靈準上人院','賈島','唐','唐诗','tang','','[]','掩扉當太白，臘數等松椿。',48,'全唐诗/poet.tang.31000.json','["掩扉當太白，臘數等松椿。", "禁漏來遙夜，山泉落近鄰。", "經聲終卷曉，草色幾芽春。", "海內知名士，交遊準上人。"]'),
('f74cbbed-a885-4613-b7b0-8a23ab34a20e','寄柳舍人宗元','賈島','唐','唐诗','tang','','[]','格與功俱造，何人意不降。',48,'全唐诗/poet.tang.31000.json','["格與功俱造，何人意不降。", "一宵三夢柳，孤泊九秋江。", "擢第名重列，沖天字幾雙。", "誓爲仙者僕，側執馭風幢。"]'),
('0a83207b-e8dd-4245-adb9-a6005f2dc5df','送玄巖上人歸西蜀','賈島','唐','唐诗','tang','','[]','玉壘山中寺，幽深勝概多。',48,'全唐诗/poet.tang.31000.json','["玉壘山中寺，幽深勝概多。", "藥成彭祖擣，頂受七輪摩。", "去臘催今夏，流光等逝波。", "會當依糞掃，五嶽徧頭陀。"]'),
('2fd67561-debc-4c38-9e15-d8d3bb72dbec','寄宋州田中丞','賈島','唐','唐诗','tang','','[]','古郡近南徐，關河萬里餘。',48,'全唐诗/poet.tang.31000.json','["古郡近南徐，關河萬里餘。", "相思深夜後，未荅去秋書。", "自別知音少，難忘識面初。", "舊山期已久，門掩數畦蔬。"]'),
('b4764556-41b7-4093-aebb-b4141332c3b5','送朱休歸劒南','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','劒南歸受賀，太學賦聲雄。',48,'全唐诗/poet.tang.31000.json','["劒南歸受賀，太學賦聲雄。", "山路長江岸，朝陽十月中。", "芽新抽雪茗，枝重集猨楓。", "卓氏琴臺廢，深蕪想徑通。"]'),
('15ba07c8-5a9f-4f8a-b11c-1beed25a1460','寄長武朱尚書','賈島','唐','唐诗','tang','','[]','不日即登壇，槍旗一萬竿。',48,'全唐诗/poet.tang.31000.json','["不日即登壇，槍旗一萬竿。", "角吹邊月沒，鼓絕爆雷殘。", "中國今如此，西荒可取難。", "白衣思請謁，徒步在長安。"]'),
('818cb93f-6549-4f55-adc9-23a230235068','送皇甫侍御','賈島','唐','唐诗','tang','','[]','曉鐘催早朝，自是赴嘉招。',48,'全唐诗/poet.tang.31000.json','["曉鐘催早朝，自是赴嘉招。", "舟泊湘江闊，田收楚澤遙。", "雁驚起衰草，猨渴下寒條。", "來使黔南日，時應問寂寥。"]'),
('a4448bd3-4924-4a82-b58a-6532d93002a0','郊居即事','賈島','唐','唐诗','tang','','[]','住此園林久，其如未是家。',48,'全唐诗/poet.tang.31000.json','["住此園林久，其如未是家。", "葉書傳野意，簷溜煮胡茶。", "雨後逢行鷺，更深聽遠蛙。", "自然還往裏，多是愛煙霞。"]'),
('5c303b7c-4c33-4208-821d-8a57ae49c7d9','夜集姚合宅期可公不至','賈島','唐','唐诗','tang','','[]','公堂秋雨夜，已是念園林。',48,'全唐诗/poet.tang.31000.json','["公堂秋雨夜，已是念園林。", "何事疾病日，重論山水心。", "孤燈明臘後，微雪下更深。", "釋子乖來約，泉西寒磬音。"]'),
('dcab20ce-9b61-4b69-9ecb-a648e51baa74','喜李餘自蜀至','賈島','唐','唐诗','tang','','[]','迢遰岷峨外，西南驛路高。',48,'全唐诗/poet.tang.31000.json','["迢遰岷峨外，西南驛路高。", "幾程尋嶮棧，獨宿聽寒濤。", "白鳥飛還立，青猨斷更號。", "往來從此過，詞體近風騷。"]'),
('2137c50c-26f6-4461-8547-7428ecc86434','王侍御南原莊','賈島','唐','唐诗','tang','','[]','買得足雲地，新栽藥數窠。',48,'全唐诗/poet.tang.31000.json','["買得足雲地，新栽藥數窠。", "峰頭盤一徑，原下注雙河。", "春寺閑眠久，晴臺獨上多。", "南齋宿雨後，仍許重來麽。"]'),
('d29114c1-6de0-47b5-89a0-44a3902c1263','送康秀才','賈島','唐','唐诗','tang','','[]','俱爲落第年，相識落花前。',48,'全唐诗/poet.tang.31000.json','["俱爲落第年，相識落花前。", "酒瀉兩三盞，詩吟十數篇。", "行岐逢塞雨，嘶馬上津船。", "樹影高堂下，迴時應有蟬。"]'),
('4dae3361-74c2-4ec2-b55b-ea27029a9082','送僧','賈島','唐','唐诗','tang','','[]','此生披衲過，在世得身閑。',48,'全唐诗/poet.tang.31000.json','["此生披衲過，在世得身閑。", "日午遊都市，天寒往華山。", "言歸文字外，意出有無間。", "仙掌雲邊樹，巢禽時出關。"]'),
('ab67bab7-77e3-46d8-bd48-2bd2f58e76e1','寄魏少府','賈島','唐','唐诗','tang','','[]','來時乖面別，終日使人慙。',48,'全唐诗/poet.tang.31000.json','["來時乖面別，終日使人慙。", "易記卷中句，難忘燈下談。", "溼苔黏樹癭，瀑布濺房庵。", "音信如相惠，移居古井南。"]'),
('6696fd47-adb8-4309-9f4d-23981e95d037','原居即事言懷贈孫員外','賈島','唐','唐诗','tang','','[]','出入土門偏，秋深石色泉。',72,'全唐诗/poet.tang.31000.json','["出入土門偏，秋深石色泉。", "徑通原上草，地接水中蓮。", "採菌依餘枿，拾薪逢刈田。", "鑷撏白髮斷，兵阻尺書傳。", "避路來華省，抄詩上彩牋。", "高齋久不到，猶喜未經年。"]'),
('2b90fd66-eab6-46c7-9469-47c1a317de65','登樓','賈島','唐','唐诗','tang','','[]','秋日登高望，涼風吹海初。',48,'全唐诗/poet.tang.31000.json','["秋日登高望，涼風吹海初。", "山川明已久，河漢沒無餘。", "遠近涯寥敻，高低中太虛。", "賦因王閣筆，思比謝遊疎。"]'),
('fc55c3cf-6402-4a40-90a9-ef27a55cab14','上樂使君救康成公','賈島','唐','唐诗','tang','','[]','曾夢諸侯笑，康囚議脫枷。',24,'全唐诗/poet.tang.31000.json','["曾夢諸侯笑，康囚議脫枷。", "千根池裏藕，一朵火中花。"]'),
('c12b6bbb-2b96-47a1-8edb-1c9a4aa2bb04','[昆]明池泛舟','賈島','唐','唐诗','tang','','[]','一枝青竹榜，泛泛綠萍裏。',24,'全唐诗/poet.tang.31000.json','["一枝青竹榜，泛泛綠萍裏。", "不見釣魚人，漸入秋塘水。"]'),
('de7938d0-3a30-4f1c-b41d-50deffe65172','送僧','賈島','唐','唐诗','tang','','[]','大內曾持論，天南化俗行。',48,'全唐诗/poet.tang.31000.json','["大內曾持論，天南化俗行。", "舊房山雪在，春草岳陽生。", "曉了蓮經義，堪任寶蓋迎。", "王侯皆護法，何寺講鐘鳴。"]'),
('f48a5781-5706-4ab7-a503-1a9c5683d0e3','送劉知新往襄陽','賈島','唐','唐诗','tang','','[]','此別誠堪恨，荆襄是舊游。',48,'全唐诗/poet.tang.31000.json','["此別誠堪恨，荆襄是舊游。", "眼光懸欲落，心緒亂難收。", "花木三層寺，煙波五相樓。", "因君兩地去，長使夢悠悠。"]'),
('66203a48-5628-4a89-98e5-1773d73500f7','寄慈恩寺郁上人','賈島','唐','唐诗','tang','','[]','中秋期夕望，虛室省相容。',48,'全唐诗/poet.tang.31000.json','["中秋期夕望，虛室省相容。", "北斗生清漏，南山出碧重。", "露寒鳩宿竹，鴻過月圓鐘。", "此夜情應切，衡陽舊住峯。"]'),
('2f06fae6-65c7-4788-b168-454604827e92','送饒州張使君','賈島','唐','唐诗','tang','','[]','終南雲雨連城闕，去路西江白浪頭。',64,'全唐诗/poet.tang.31000.json','["終南雲雨連城闕，去路西江白浪頭。", "滁上郡齋離昨日，鄱陽農事勸今秋。", "道心生向前朝寺，文思來因靜夜樓。", "借問泊帆干謁者，誰人曾聽峽猨愁。"]'),
('f6c4710c-1451-4e49-9bdd-71824debf987','觀冬設上東川楊尚書','賈島','唐','唐诗','tang','','[]','匏革奏冬非獨樂，軍城未曉啓重門。',64,'全唐诗/poet.tang.31000.json','["匏革奏冬非獨樂，軍城未曉啓重門。", "何時却入三台貴，此日空知八座尊。", "羅綺舞中收雨點，貔貅閫外卷雲根。", "逐遷屬吏隨賓列，撥櫂扁舟不忘恩。"]'),
('4aa69371-e08d-482d-8c80-bf7835c779f9','巴興作','賈島','唐','唐诗','tang','','[]','三年未省聞鴻呌，九月何曾見草枯。',64,'全唐诗/poet.tang.31000.json','["三年未省聞鴻呌，九月何曾見草枯。", "寒暑氣均思白社，星辰位正憶皇都。", "蘇卿持節終還漢，葛相行師自渡瀘。", "鄉味朔山林果別，北歸期挂海帆孤。"]'),
('632cfbf5-9713-4213-9836-dc982f074042','早蟬','賈島','唐','唐诗','tang','','[]','早蟬孤抱芳槐葉，噪向殘陽意度秋。',64,'全唐诗/poet.tang.31000.json','["早蟬孤抱芳槐葉，噪向殘陽意度秋。", "也任一聲催我老，堪聽兩耳畏吟休。", "得非下第無高韻，須是青山隱白頭。", "若問此心嗟嘆否，天人不可怨而尤。"]'),
('87b172d7-eb10-4fdb-8ff8-de7e578bcf67','投元郎中','賈島','唐','唐诗','tang','','[]','心在瀟湘歸未期，卷中多是得名詩。',64,'全唐诗/poet.tang.31000.json','["心在瀟湘歸未期，卷中多是得名詩。", "高臺聊望清秋色，片水堪留白鷺鷥。", "省宿有時聞急雨，朝迴盡日伴禪師。", "舊文去歲曾將獻，蒙與人來說始知。"]'),
('ea048c96-7ee0-4af8-b89e-d06ecc14d4aa','阮籍嘯臺','賈島','唐','唐诗','tang','','[]','如聞長嘯春風裏，荆棘叢邊訪舊蹤。',32,'全唐诗/poet.tang.32000.json','["如聞長嘯春風裏，荆棘叢邊訪舊蹤。", "地接蘇門山近遠，荒臺突兀抵高峰。"]'),
('bf244021-c3cf-4c94-9a20-db719d7036e9','滕校書使院小池','賈島','唐','唐诗','tang','','[]','小池誰見鑿時初，走水南來十里餘。',32,'全唐诗/poet.tang.32000.json','["小池誰見鑿時初，走水南來十里餘。", "樓上日斜吹暮角，院中人出鎖遊魚。"]'),
('82ed511f-3b9a-4519-b7de-eba88f3a89c8','送陝府王建司馬','賈島','唐','唐诗','tang','','[]','司馬雖然聽曉鐘，尚猶高枕恣疎慵。',64,'全唐诗/poet.tang.32000.json','["司馬雖然聽曉鐘，尚猶高枕恣疎慵。", "請詩僧過三門水，賣藥人歸五老峰。", "移舫綠陰深處息，登樓涼夜此時逢。", "杜陵惆悵臨相餞，未寢月前多屐蹤。"]'),
('5f1960e1-5280-4a75-9521-71557978f7b9','上谷旅夜','賈島','唐','唐诗','tang','','[]','世難那堪恨旅遊，龍鍾更是對窮秋。',64,'全唐诗/poet.tang.32000.json','["世難那堪恨旅遊，龍鍾更是對窮秋。", "故園千里數行淚，鄰杵一聲終夜愁。", "月到寒窗空皓皛，風翻落葉更颼飀。", "此心不向常人說，倚識平津萬戶侯。"]'),
('579805b9-d4c7-4d0f-9b48-165ead38e0c6','寄無得頭陀','賈島','唐','唐诗','tang','','[]','夏臘今應三十餘，不離樹下塚間居。',64,'全唐诗/poet.tang.32000.json','["夏臘今應三十餘，不離樹下塚間居。", "貌堪良匠抽毫寫，行稱高僧續傳書。", "落澗水聲來遠遠，當空月色自如如。", "白衣只在青門裏，心每相親跡且疎。"]'),
('5f309673-cce0-4721-b472-318a1dd75e39','崔卿池上雙白鷺','賈島','唐','唐诗','tang','','[]','鷺雛相逐出深籠，頂各有絲莖數同。',64,'全唐诗/poet.tang.32000.json','["鷺雛相逐出深籠，頂各有絲莖數同。", "灑石多霜移足冷，隔城遠樹挂巢空。", "其如盡在灘聲外，何似雙飛浦色中。", "見此池潭卿自鑿，清泠太液底潛通。"]'),
('2d06bbf3-c860-4af6-a1e9-4213692b9673','送胡道士','賈島','唐','唐诗','tang','','[]','短褐身披滿漬苔，靈溪深處觀門開。',64,'全唐诗/poet.tang.32000.json','["短褐身披滿漬苔，靈溪深處觀門開。", "却從城裏移琴去，許到山中寄藥來。", "臨水古壇秋醮罷，宿杉幽鳥夜飛迴。", "丹梯願逐真人上，日夕歸心白髮催。"]'),
('c8395644-390a-487e-9d7c-8bade82c9940','寄韓潮州愈','賈島','唐','唐诗','tang','','["\u61a7\u61ac", "\u53cb\u60c5"]','此心曾與木蘭舟，直到天南潮水頭。',64,'全唐诗/poet.tang.32000.json','["此心曾與木蘭舟，直到天南潮水頭。", "隔嶺篇章來華岳，出關書信過瀧流。", "峰懸驛路殘雲斷，海浸城根老樹秋。", "一夕瘴煙風卷盡，月明初上浪西樓。"]'),
('5e396e0f-3a6d-4d6b-9a02-2df35747d3a8','詶張籍王建','賈島','唐','唐诗','tang','','[]','疎林荒宅古坡前，久住還因太守憐。',64,'全唐诗/poet.tang.32000.json','["疎林荒宅古坡前，久住還因太守憐。", "漸老更思深處隱，多閑數得上方眠。", "鼠拋貧屋收田日，鴈度寒江擬雪天。", "身是龍鍾應是分，水曹芸閣枉來篇。"]'),
('570100e7-dd0c-4162-9564-6cc67ee6b16a','逢博陵故人彭兵曹','賈島','唐','唐诗','tang','','[]','曲陽分散會京華，見說三年住海涯。',64,'全唐诗/poet.tang.32000.json','["曲陽分散會京華，見說三年住海涯。", "別後解餐蓬虆子，向前未識牡丹花。", "偶逢日者敎求祿，終傍泉聲擬置家。", "蹋雪攜琴相就宿，夜深開戶斗牛斜。"]'),
('22d7340e-94bc-4f5f-a5ad-7d5efb23a72e','贈牛山人','賈島','唐','唐诗','tang','','[]','二十年中餌茯苓，致書半是老君經。',64,'全唐诗/poet.tang.32000.json','["二十年中餌茯苓，致書半是老君經。", "東都舊住商人宅，南國新修道士亭。", "鑿石養蜂休買蜜，坐山秤藥不爭星。", "古來隱者多能卜，欲就先生問丙丁。"]'),
('2e2caaa2-7ac0-45df-b883-7b8de963ccc5','送于中丞使回紇冊立','賈島','唐','唐诗','tang','','[]','君立天驕發使車，冊文字字著金書。',64,'全唐诗/poet.tang.32000.json','["君立天驕發使車，冊文字字著金書。", "漸通青塚鄉山盡，欲達皇情譯語初。", "調角寒城邊色動，下霜秋磧鴈行疎。", "旌旗來往幾多日，應向途中見歲除。"]'),
('fb829964-dd5a-4cf5-8b0b-76da1891e2cd','送劉侍御重使江西','賈島','唐','唐诗','tang','','[]','時當苦熱遠行人，石壁飛泉濺馬身。',64,'全唐诗/poet.tang.32000.json','["時當苦熱遠行人，石壁飛泉濺馬身。", "又到鍾陵知務大，還浮湓浦屬秋新。", "早程猨呌雲深極，宿館禽驚葉動頻。", "前者已聞廉使薦，兼言有畫靜邊塵。"]'),
('c6b8454d-8c53-446a-86f6-75c5480a6d6b','贈圓上人','賈島','唐','唐诗','tang','','[]','誦經千紙得爲僧，麈尾持行不拂蠅。',64,'全唐诗/poet.tang.32000.json','["誦經千紙得爲僧，麈尾持行不拂蠅。", "古塔月高聞呪水，新壇日午見燒燈。", "一雙童子澆紅藥，百八真珠貫綵繩。", "且說近來心裏事，仇讎相對似親朋。"]'),
('3f3761d5-9e2e-418f-ad19-1c505cd31839','處州李使君改任遂州因寄贈','賈島','唐','唐诗','tang','','[]','庭樹幾株陰入戶，主人何在客聞蟬。',64,'全唐诗/poet.tang.32000.json','["庭樹幾株陰入戶，主人何在客聞蟬。", "鑰開原上高樓鎖，瓶汲池東古井泉。", "趂靜野禽曾後到，休吟鄰叟始安眠。", "仙都山水誰能憶，西去風濤書滿船。"]'),
('4f921067-eb63-4575-85e6-6dc5f1f0841c','酬慈恩寺文郁上人','賈島','唐','唐诗','tang','','[]','袈裟影入禁池清，猶憶鄉山近赤城。',64,'全唐诗/poet.tang.32000.json','["袈裟影入禁池清，猶憶鄉山近赤城。", "籬落罅間寒蟹過，莓苔石上晚蛩行。", "期登野閣閑應甚，阻宿山房疾未平。", "聞說又尋南岳去，無端詩思忽然生。"]'),
('6d3c5fed-5305-4b58-97fa-ee458ae5eee0','訪鑒玄師姪','賈島','唐','唐诗','tang','','[]','維摩青石講初休，緣訪親宗到普州。',32,'全唐诗/poet.tang.32000.json','["維摩青石講初休，緣訪親宗到普州。", "我有軍持憑弟子，岳陽溪裏汲寒流。"]'),
('f220a485-b9cf-44ee-92ac-9dfd9e52b51c','夜坐','賈島','唐','唐诗','tang','','[]','蟋蟀漸多秋不淺，蟾蜍已沒夜應深。',32,'全唐诗/poet.tang.32000.json','["蟋蟀漸多秋不淺，蟾蜍已沒夜應深。", "三更兩鬢幾枝雪，一念雙峰四祖心。"]'),
('a0c4e0c4-801a-422b-b20d-3b75910570eb','送別','賈島','唐','唐诗','tang','','[]','門外便伸千里別，無車不得到河梁。',32,'全唐诗/poet.tang.32000.json','["門外便伸千里別，無車不得到河梁。", "高樓直上百餘尺，今日爲君南望長。"]'),
('97ad574a-7895-4d98-adbc-08c621f7f48c','聞蟬感懷','賈島','唐','唐诗','tang','','[]','新蟬忽發最高枝，不覺立聽無限時。',32,'全唐诗/poet.tang.32000.json','["新蟬忽發最高枝，不覺立聽無限時。", "正遇友人來告別，一心分作兩般悲。"]'),
('40b676f4-ff69-42d6-9325-5b7d3f9a63e1','夏夜上谷宿開元寺','賈島','唐','唐诗','tang','','[]','詩成一夜月中題，便臥松風到曙雞。',32,'全唐诗/poet.tang.32000.json','["詩成一夜月中題，便臥松風到曙雞。", "帶月時聞山鳥語，郡城知近武陵溪。"]'),
('8325674d-a4a3-447c-b828-4d5d41c8ac03','送于總持歸京','賈島','唐','唐诗','tang','','[]','出家初隷何方寺，上國西明御水東。',32,'全唐诗/poet.tang.32000.json','["出家初隷何方寺，上國西明御水東。", "却見舊房堦下樹，別來二十一春風。"]'),
('172ac0dc-f264-4c00-ba3b-213ca0d6d916','崔卿池上鶴','賈島','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','月中時呌葉紛紛，不異洞庭霜夜聞。',32,'全唐诗/poet.tang.32000.json','["月中時呌葉紛紛，不異洞庭霜夜聞。", "翎羽如今從放長，猶能飛起向孤雲。"]'),
('e30d6701-1d8a-4d9b-95ea-325f5065eda5','登田中丞高亭','賈島','唐','唐诗','tang','','[]','高亭林表迥嵯峨，獨坐秋宵不寢多。',32,'全唐诗/poet.tang.32000.json','["高亭林表迥嵯峨，獨坐秋宵不寢多。", "玉兔玉人歌裏出，白雲難似莫相和。"]'),
('f4d56c7c-df1f-4dc1-9637-1a594faef343','友人婚楊氏催妝','賈島','唐','唐诗','tang','','[]','不知今夕是何夕，催促陽臺近鏡臺。',32,'全唐诗/poet.tang.32000.json','["不知今夕是何夕，催促陽臺近鏡臺。", "誰道芙蓉水中種，青銅鏡裏一枝開。"]'),
('e71b6625-f5ea-496a-967a-75e294b41406','酬朱侍御望月見寄','賈島','唐','唐诗','tang','','[]','他寢此時吾不寢，近秋三五日逢晴。',32,'全唐诗/poet.tang.32000.json','["他寢此時吾不寢，近秋三五日逢晴。", "相思唯有霜臺月，望盡孤光見却生。"]'),
('363b8932-110c-4914-9908-1cbc43c9dc69','題韋雲叟草堂','賈島','唐','唐诗','tang','','[]','新起此堂開北窗，當窗山隔一重江。',32,'全唐诗/poet.tang.32000.json','["新起此堂開北窗，當窗山隔一重江。", "白茅草苫重重密，愛此秋天夜雨淙。"]'),
('7fbb8ad9-85d1-4e8c-af90-10c309744ac3','和韓吏部泛南溪','賈島','唐','唐诗','tang','','[]','溪裏晚從池岸出，石泉秋急夜深聞。',32,'全唐诗/poet.tang.32000.json','["溪裏晚從池岸出，石泉秋急夜深聞。", "木蘭船共山人上，月映渡頭零落雲。"]'),
('f8593c7b-a58c-4f96-9b69-1b7f30b9b58d','方鏡','賈島','唐','唐诗','tang','','[]','背如刀截機頭錦，面似升量澗底泉。',32,'全唐诗/poet.tang.32000.json','["背如刀截機頭錦，面似升量澗底泉。", "銅雀臺南秋日後，照來照去已三年。"]'),
('cbae4436-47c4-4df0-81ad-062bab528c81','詶姚合','賈島','唐','唐诗','tang','','[]','黍穗豆苗侵古道，晴原午後早秋時。',32,'全唐诗/poet.tang.32000.json','["黍穗豆苗侵古道，晴原午後早秋時。", "故人相憶僧來說，楊柳無風蟬滿枝。"]'),
('a94fc010-0cd4-462a-a738-53245b9442a1','送靈應上人','賈島','唐','唐诗','tang','','[]','遍參尊宿遊方久，名岳奇峰問此公。',32,'全唐诗/poet.tang.32000.json','["遍參尊宿遊方久，名岳奇峰問此公。", "五月半間看瀑布，青城山裏白雲中。"]'),
('f4c2326d-0fb5-4188-979c-332a54ceea94','贈丘先生','賈島','唐','唐诗','tang','','[]','常言喫藥全勝飯，華岳松邊採茯神。',32,'全唐诗/poet.tang.32000.json','["常言喫藥全勝飯，華岳松邊採茯神。", "不遣髭鬚一莖白，擬爲白日上昇人。"]'),
('89ef4498-db55-4011-b531-c9f49b8ec723','渡桑乾','賈島','唐','唐诗','tang','','["\u601d\u4e61"]','客舍幷州已十霜，歸心日夜憶咸陽。',32,'全唐诗/poet.tang.32000.json','["客舍幷州已十霜，歸心日夜憶咸陽。", "無端更渡桑乾水，却望幷州是故鄉。"]'),
('73498ff0-87e4-4229-ae32-531fdc32c339','夜期嘯客呂逸人不至','賈島','唐','唐诗','tang','','[]','逸人期宿石牀中，遣我開扉對晚空。',32,'全唐诗/poet.tang.32000.json','["逸人期宿石牀中，遣我開扉對晚空。", "不知何處嘯秋月，閑著松門一夜風。"]'),
('e81eb208-19b7-4d0f-97c8-fada6606d205','夜集烏行中所居','賈島','唐','唐诗','tang','','[]','環爐促席復持杯，松院雙扉向月開。',32,'全唐诗/poet.tang.32000.json','["環爐促席復持杯，松院雙扉向月開。", "座上同聲半先達，名山獨入此心來。"]'),
('7ebfe239-c6b5-4a84-9f9c-8ade495d1521','贈梁浦秀才斑竹拄杖','賈島','唐','唐诗','tang','','[]','揀得林中最細枝，結根石上長身遲。',32,'全唐诗/poet.tang.32000.json','["揀得林中最細枝，結根石上長身遲。", "莫嫌滴瀝紅斑少，恰似湘妃淚盡時。"]'),
('6cd53d54-86dd-439a-a5fe-b09f2c181b47','尋石甕寺上方','賈島','唐','唐诗','tang','','[]','野寺入時春雪後，崎嶇得到此房前。',32,'全唐诗/poet.tang.32000.json','["野寺入時春雪後，崎嶇得到此房前。", "老僧不出迎朝客，已住上方三十年。"]'),
('bcabcef4-8664-48db-aa56-9d13c10c72a1','早秋寄題天竺靈隱寺','賈島','唐','唐诗','tang','','[]','峰前峰後寺新秋，絕頂高窗見沃洲。',64,'全唐诗/poet.tang.32000.json','["峰前峰後寺新秋，絕頂高窗見沃洲。", "人在定中聞蟋蟀，鶴從棲處挂獼猴。", "山鐘夜渡空江水，汀月寒生古石樓。", "心憶懸帆身未遂，謝公此地昔年遊。"]'),
('e980ce8b-0977-4361-a9b6-ab7923c63c2b','黎陽寄姚合','賈島','唐','唐诗','tang','','["\u9ec4\u6cb3"]','魏都城裏曾遊熟，才子齋中止泊多。',64,'全唐诗/poet.tang.32000.json','["魏都城裏曾遊熟，才子齋中止泊多。", "去日綠楊垂紫陌，歸時白草夾黃河。", "新詩不覺千迴詠，古鏡曾經幾度磨。", "惆悵心思滑臺北，滿杯濃酒與愁和。"]'),
('b463925b-db0a-4a6c-8dbe-841b2fc0ef39','送崔約秀才','賈島','唐','唐诗','tang','','[]','歸寧髣髴三千里，月向船窗見幾宵。',64,'全唐诗/poet.tang.32000.json','["歸寧髣髴三千里，月向船窗見幾宵。", "野鼠獨偷高樹果，前山漸見短禾苗。", "更深柵鎖淮波疾，葦動風生雨氣遙。", "重入石頭城下寺，南朝杉老未乾燋。"]'),
('d9569ee4-9de8-42bc-bf26-49e45c131651','詠懷','賈島','唐','唐诗','tang','','[]','縱把書看未省勤，一生生計秖長貧。',64,'全唐诗/poet.tang.32000.json','["縱把書看未省勤，一生生計秖長貧。", "可能在世無成事，不覺離家作老人。", "中嶽深林秋獨往，南原多草夜無鄰。", "經年抱疾誰來問，野鳥相過啄木頻。"]'),
('37bf2ec4-65ce-482d-a196-f3ddb690dd28','夏日寄高洗馬','賈島','唐','唐诗','tang','','[]','三十年來長在客，兩三行淚忽然垂。',64,'全唐诗/poet.tang.32000.json','["三十年來長在客，兩三行淚忽然垂。", "白衣蒼鬢經過嬾，赤日朱門偃息遲。", "花發應耽新熟酒，草顛還寫早朝詩。", "不緣馬死西州去，畫角堪聽是曉吹。"]'),
('b2f56545-b2b9-4c61-a498-a0a23c0c6542','送周判官元範赴越','賈島','唐','唐诗','tang','','[]','原下相逢便別離，蟬鳴關路使迴時。',64,'全唐诗/poet.tang.32000.json','["原下相逢便別離，蟬鳴關路使迴時。", "過淮漸有懸帆興，到越應將墜葉期。", "城上秋山生菊早，驛西寒渡落潮遲。", "已曾幾遍隨旌斾，去謁荒郊大禹祠。"]'),
('7b59434e-c8cf-4069-992f-fd1bd734fbb5','送羅少府歸牛渚','賈島','唐','唐诗','tang','','[]','作尉長安始三日，忽思牛渚夢天台。',64,'全唐诗/poet.tang.32000.json','["作尉長安始三日，忽思牛渚夢天台。", "楚山遠色獨歸去，灞水空流相送回。", "霜覆鶴身松子落，月分螢影石房開。", "白雲多處應頻到，寒澗泠泠漱古苔。"]'),
('eb3e2e1e-d92a-472c-9ae7-641921da44e3','題童真上人','賈島','唐','唐诗','tang','','[]','江上修持積歲年，灘聲未擬住潺湲。',64,'全唐诗/poet.tang.32000.json','["江上修持積歲年，灘聲未擬住潺湲。", "誓從五十身披衲，便向三千界坐禪。", "月峽青城那有滯，天台廬岳豈無緣。", "昨宵忽夢遊滄海，萬里波濤在目前。"]'),
('e28c9090-68c5-4f47-8dd4-af0996ce8f21','贈溫觀主','賈島','唐','唐诗','tang','','[]','一別羅浮竟未還，觀深廊古院多關。',64,'全唐诗/poet.tang.32000.json','["一別羅浮竟未還，觀深廊古院多關。", "君來幾日行虛洞，仙去空壇在遠山。", "胎息存思當黑處，井華懸綆取朝間。", "弊廬道室雖鄰近，自樂冬陽炙背閑。"]'),
('92623899-f54d-4c7a-9f2a-12e8d910465d','賀龐少尹除太常少卿','賈島','唐','唐诗','tang','','[]','太白山前終日見，十旬假滿擬秋尋。',64,'全唐诗/poet.tang.32000.json','["太白山前終日見，十旬假滿擬秋尋。", "中峰絕頂非無路，北闕除書阻入林。", "朝謁此時閑野屐，宿齋何處止鳴砧？", "省中石鐙陪隨步，唯賞煙霞不厭深。"]'),
('dda96013-c1b9-45a1-8931-c179a70ae5f9','上邠寧邢司徒','賈島','唐','唐诗','tang','','[]','箭頭破帖渾無敵，杖底敲毬遠有聲。',64,'全唐诗/poet.tang.32000.json','["箭頭破帖渾無敵，杖底敲毬遠有聲。", "馬走千蹄朝萬乘，地分三郡擁雙旌。", "春風欲盡山花發，曉角初吹客夢驚。", "不是邢公來鎮此，長安西北未能行。"]'),
('24557993-a632-4a04-8260-9477252f3506','欲遊嵩岳留別李少尹益','賈島','唐','唐诗','tang','','[]','孤策遲迴洛水湄，孤禽嘹唳幸人知。',64,'全唐诗/poet.tang.32000.json','["孤策遲迴洛水湄，孤禽嘹唳幸人知。", "嵩岳望中常待我，河梁欲上未題詩。", "新秋愛月愁多雨，古觀逢仙看盡棋。", "微眇此來將敢問，鳳凰何日定歸池。"]'),
('442b31d4-0c7e-4e45-820f-edb5f62f27f6','病鶻吟','賈島','唐','唐诗','tang','','[]','俊鳥還投高處栖，騰身戛戛下雲梯。',64,'全唐诗/poet.tang.32000.json','["俊鳥還投高處栖，騰身戛戛下雲梯。", "有時透霧凌空去，無事隨風入草迷。", "迅疾月邊捎玉兔，遲迴日裏拂金雞。", "不緣毛羽遭零落，焉肯雄心向爾低。"]'),
('6f6df361-6f48-42e9-be2e-cbfb6e8d3564','贈僧','賈島','唐','唐诗','tang','','[]','從來多是遊山水，省泊禪舟月下濤。',64,'全唐诗/poet.tang.32000.json','["從來多是遊山水，省泊禪舟月下濤。", "初過石橋年尚少，久辭天柱臘應高。", "青松帶雪懸銅錫，白髮如霜落鐵刀。", "常恐畫工援筆寫，身長七尺有眉毫。"]'),
('e0ceccdb-f542-46cd-9331-052937e7bbe0','贈翰林','賈島','唐','唐诗','tang','','[]','清重無過知內制，從前禮絕外庭人。',64,'全唐诗/poet.tang.32000.json','["清重無過知內制，從前禮絕外庭人。", "看花在處多隨駕，召宴無時不及身。", "馬自賜來騎覺穩，詩緣見徹語長新。", "應憐獨向名場苦，曾十餘年浪過春。"]'),
('63284c9b-55c9-4757-94c0-f3ec7f79bc21','頌德上賈常侍','賈島','唐','唐诗','tang','','[]','邊臣說使朝天子，發語轟然激夏雷。',64,'全唐诗/poet.tang.32000.json','["邊臣說使朝天子，發語轟然激夏雷。", "高節羽書期獨傳，分符絳郡滯長材。", "啁啾鳥恐鷹鸇起，流散人歸父母來。", "自顧此身無所立，恭談祖德朵頤開。"]'),
('7d2edcb0-f992-4d49-8aa6-56fd4c8e7725','田將軍書院','賈島','唐','唐诗','tang','','[]','滿庭花木半新栽，石自平湖遠岸來。',64,'全唐诗/poet.tang.32000.json','["滿庭花木半新栽，石自平湖遠岸來。", "筍迸鄰家還長竹，地經山雨幾層苔。", "井當深夜泉微上，閣入高秋戶盡開。", "行背曲江誰到此，琴書鎖著未朝迴。"]'),
('7a0a3c22-a5bb-482f-8380-0eeee3258d3f','投龐少尹','賈島','唐','唐诗','tang','','[]','閉戶息機搔白首，中庭一樹有清陰。',64,'全唐诗/poet.tang.32000.json','["閉戶息機搔白首，中庭一樹有清陰。", "年年不改風塵趣，日日轉多泉石心。", "病起望山臺上立，覺來聽雨燭前吟。", "龐公相識元和歲，眷分依依直至今。"]'),
('ff4b7e44-8cc5-43e2-93b4-8c5eaf86e0be','夏夜登南樓','賈島','唐','唐诗','tang','','[]','水岸寒樓帶月躋，夏林初見岳陽溪。',32,'全唐诗/poet.tang.32000.json','["水岸寒樓帶月躋，夏林初見岳陽溪。", "一㸃新螢報秋信，不知何處是菩提。"]'),
('f43b52da-d474-4712-92e0-cd619dcdf49f','題青龍寺','賈島','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','碣石山人一軸詩，終南山北數人知。',32,'全唐诗/poet.tang.32000.json','["碣石山人一軸詩，終南山北數人知。", "擬看青龍寺裏月，待無一點夜雲時。"]'),
('54e48a8e-9032-4b01-8c8f-cbc17bc1df06','贈李文通','賈島','唐','唐诗','tang','','[]','營當萬勝岡頭下，誓立千年不朽功。',32,'全唐诗/poet.tang.32000.json','["營當萬勝岡頭下，誓立千年不朽功。", "天子手擎新鉞斧，諫官請贈李文通。"]'),
('b433d2de-3186-43a7-8af7-65497fb0f9ab','題虢州三堂贈吳郎中','賈島','唐','唐诗','tang','','[]','無窮草樹昔誰栽，新起臨湖白石臺。',64,'全唐诗/poet.tang.32000.json','["無窮草樹昔誰栽，新起臨湖白石臺。", "半岸泥沙孤鶴立，三堂風雨四門開。", "荷翻團露驚秋近，柳轉斜陽過水來。", "昨夜北樓堪朗詠，虢城初鎖月裴回。"]'),
('6f015d3d-d269-4ac4-b181-32aa8635b0f8','送僧','賈島','唐','唐诗','tang','','[]','池上時時松雪落，焚香煙起見孤燈。',32,'全唐诗/poet.tang.32000.json','["池上時時松雪落，焚香煙起見孤燈。", "靜夜憶誰來對坐，曲江南岸寺中僧。"]'),
('24d3133e-3019-4178-99d9-fe02bfc5c8d2','三月晦日贈劉評事','賈島','唐','唐诗','tang','','["\u6625\u5929", "\u60dc\u6625"]','三月正當三十日，風光別我苦吟身。',32,'全唐诗/poet.tang.32000.json','["三月正當三十日，風光別我苦吟身。", "共君今夜不須睡，未到曉鐘猶是春。"]'),
('0b01872c-7a21-44e6-841f-2d6664c0570a','送張道者','賈島','唐','唐诗','tang','','[]','新歲抱琴何處去，洛陽三十六峰西。',32,'全唐诗/poet.tang.32000.json','["新歲抱琴何處去，洛陽三十六峰西。", "生來未識山人面，不得一聽烏夜啼。"]'),
('9783c660-9f08-4d74-86f3-37490cd51315','題魚尊師院','賈島','唐','唐诗','tang','','[]','老子堂前花萬樹，先生曾見幾迴春。',32,'全唐诗/poet.tang.32000.json','["老子堂前花萬樹，先生曾見幾迴春。", "夜煎白石平明喫，不擬敎人哭此身。"]'),
('34c7501c-ceec-4cb0-81fe-a330770c1e57','宿村家亭子','賈島','唐','唐诗','tang','','[]','牀頭枕是溪中石，井底泉通竹下池。',32,'全唐诗/poet.tang.32000.json','["牀頭枕是溪中石，井底泉通竹下池。", "宿客未眠過夜半，獨聞山雨到來時。"]'),
('3ef551c0-e97a-45d0-9347-954c5a3ccd4e','送稱上人','賈島','唐','唐诗','tang','','[]','歸蜀擬從巫峽過，何時得入舊房禪。',32,'全唐诗/poet.tang.32000.json','["歸蜀擬從巫峽過，何時得入舊房禪。", "寺中來後誰身化，起塔栽松向野田。"]'),
('1297ee3c-04a7-4db1-828c-a46976f2b8f1','楊祕書新居','賈島','唐','唐诗','tang','','[]','城角新居鄰靜寺，時從新閣上經樓。',32,'全唐诗/poet.tang.32000.json','["城角新居鄰靜寺，時從新閣上經樓。", "南山泉入宮中去，先向詩人門外流。"]'),
('fefce49d-d646-459b-848a-901eb3839979','聽樂山人彈易水','賈島','唐','唐诗','tang','','[]','朱絲弦底燕泉急，燕將雲孫白日彈。',32,'全唐诗/poet.tang.32000.json','["朱絲弦底燕泉急，燕將雲孫白日彈。", "嬴氏歸山陵已掘，聲聲猶帶髮衝冠。"]'),
('2b1eaa81-600a-479f-b574-fa7cfb9c762e','經蘇秦墓','賈島','唐','唐诗','tang','','[]','沙埋古篆折碑文，六國興亡事繫君。',32,'全唐诗/poet.tang.32000.json','["沙埋古篆折碑文，六國興亡事繫君。", "今日淒涼無處說，亂山秋盡有寒雲。"]'),
('37709253-66f8-47a5-9867-1c5f995acee3','題戴勝','賈島','唐','唐诗','tang','','[]','星點花冠道士衣，紫陽宮女化身飛。',32,'全唐诗/poet.tang.32000.json','["星點花冠道士衣，紫陽宮女化身飛。", "能傳上界春消息，若到蓬山莫放歸。"]'),
('f3f4685d-bbac-4c17-bdcb-4b7cd0a1f791','題隱者居','賈島','唐','唐诗','tang','','[]','雖有柴門常不關，片雲孤木伴身閑。',32,'全唐诗/poet.tang.32000.json','["雖有柴門常不關，片雲孤木伴身閑。", "猶嫌住久人知處，見擬移家更上山。"]'),
('844d0a76-b26f-4627-ac69-a893cec76b0e','哭孟東野','賈島','唐','唐诗','tang','','[]','蘭無香氣鶴無聲，哭盡秋天月不明。',32,'全唐诗/poet.tang.32000.json','["蘭無香氣鶴無聲，哭盡秋天月不明。", "自從東野先生死，側近雲山得散行。"]'),
('a5c2ecc0-7b90-43da-a1c6-820252d48eb8','過京索先生墳','賈島','唐','唐诗','tang','','[]','京索先生三尺墳，秋風漠漠吐寒雲。',32,'全唐诗/poet.tang.32000.json','["京索先生三尺墳，秋風漠漠吐寒雲。", "從來有恨君多哭，今日何人更哭君。"]'),
('f7f7eca7-c17b-4d82-8384-38c3e7c328bb','客思','賈島','唐','唐诗','tang','','[]','促織聲尖尖似針，更深刺著旅人心。',32,'全唐诗/poet.tang.32000.json','["促織聲尖尖似針，更深刺著旅人心。", "獨言獨語月明裏，驚覺眠童與宿禽。"]'),
('f1c01e1b-eb4f-4e7f-8a5b-dfa71145e483','鹽池院觀鹿','賈島','唐','唐诗','tang','','[]','條峰五老勢相連，此鹿來從若箇邊。',32,'全唐诗/poet.tang.32000.json','["條峰五老勢相連，此鹿來從若箇邊。", "別有野麋人不見，一生長飲白雲泉。"]'),
('6e2ef634-8a82-4cb0-b469-ad3e2f03018d','黃鵠下太液池','賈島','唐','唐诗','tang','','[]','高飛空外鵠，下向禁中池。',72,'全唐诗/poet.tang.32000.json','["高飛空外鵠，下向禁中池。", "岸印行蹤淺，波搖立影危。", "來從千里島，舞拂萬年枝。", "踉蹌孤風起，裴回水沫移。", "幽音清露滴，野性白雲隨。", "太液無彈射，靈禽翅不垂。"]'),
('c61e12a1-8c99-4ae1-bdd7-3cc7022c1266','代舊將','賈島','唐','唐诗','tang','','[]','舊事說如夢，誰當信老夫。',48,'全唐诗/poet.tang.32000.json','["舊事說如夢，誰當信老夫。", "戰場幾處在，部曲一人無。", "落日收病馬，晴天曬陣圖。", "猶希聖朝用，自鑷白髭鬚。"]'),
('d33e6652-56be-4268-aa9d-e7e487352970','老將','賈島','唐','唐诗','tang','','[]','膽壯亂鬚白，金瘡蠹百骸。',48,'全唐诗/poet.tang.32000.json','["膽壯亂鬚白，金瘡蠹百骸。", "旌旗猶入夢，歌舞不開懷。", "燕雀來鷹架，塵埃滿箭靫。", "自誇勳業重，開府是官階。"]'),
('7bc3282c-e9fa-4052-b52c-fd3c9561e9e4','春行','賈島','唐','唐诗','tang','','[]','去去行人遠，塵隨馬不窮。',48,'全唐诗/poet.tang.32000.json','["去去行人遠，塵隨馬不窮。", "旅情斜日後，春色早煙中。", "流水穿空館，閑花發故宮。", "舊鄉千里思，池上綠楊風。"]'),
('e63e4109-37bc-4567-9b90-c79b5f1f409c','題鄭常侍廳前竹','賈島','唐','唐诗','tang','','[]','綠竹臨詩酒，嬋娟思不窮。',120,'全唐诗/poet.tang.32000.json','["綠竹臨詩酒，嬋娟思不窮。", "亂枝低積雪，繁葉亞寒風。", "蕭颯疑泉過，縈迴有逕通。", "侵庭根出土，隔壁筍成叢。", "疎影紗窗外，清音寶瑟中。", "卷簾終日看，欹枕幾秋同。", "萬頃歌王子，千竿伴阮公。", "露光憐片片，雨潤愛濛濛。", "嶰谷蠻湖北，湘川灀水東。", "何如軒檻側，蒼翠褭長空。"]'),
('6302604c-8e12-4e1e-8f0a-d2021f8fad00','早行','賈島','唐','唐诗','tang','','[]','早起赴前程，鄰雞尚未鳴。',48,'全唐诗/poet.tang.32000.json','["早起赴前程，鄰雞尚未鳴。", "主人燈下別，羸馬暗中行。", "蹋石新霜滑，穿林宿鳥驚。", "遠山鐘動後，曙色漸分明。"]'),
('56489b17-c484-467b-9956-c8bfdab8b687','送人南歸','賈島','唐','唐诗','tang','','[]','分手向天涯，迢迢泛海波。',48,'全唐诗/poet.tang.32000.json','["分手向天涯，迢迢泛海波。", "雖然南地遠，見說北人多。", "山暖花常發，秋深鴈不過。", "炎方饒勝事，此去莫蹉跎。"]'),
('72536b70-ce00-4598-8818-a409527a18d4','送人南遊','賈島','唐','唐诗','tang','','[]','此別天涯遠，孤舟泛海中。',48,'全唐诗/poet.tang.32000.json','["此別天涯遠，孤舟泛海中。", "夜行常認火，帆去每因風。", "蠻國人多富，炎方語不同。", "鴈飛難度嶺，書信若爲通。"]'),
('c80fd603-a4ef-4410-a4e5-221ced7c04e2','送道者','賈島','唐','唐诗','tang','','[]','獨向山中見，今朝又別離。',48,'全唐诗/poet.tang.32000.json','["獨向山中見，今朝又別離。", "一心無挂住，萬里獨何之。", "到處絕煙火，逢人話古時。", "此行無弟子，白犬自相隨。"]'),
('4cf7085d-c0f6-4a2b-b3a1-55472f356f14','風蟬','賈島','唐','唐诗','tang','','[]','風蟬旦夕鳴，伴葉送新聲。',48,'全唐诗/poet.tang.32000.json','["風蟬旦夕鳴，伴葉送新聲。", "故里客歸盡，水邊身獨行。", "噪軒高樹合，驚枕暮山橫。", "聽處無人見，塵埃滿甑生。"]'),
('9965c0bc-cdc4-4c46-bc75-cbc600456505','清明日園林寄友人','賈島','唐','唐诗','tang','','["\u6e05\u660e\u8282", "\u5bc4\u8bed", "\u805a\u4f1a"]','今日清明節，園林勝事偏。',48,'全唐诗/poet.tang.32000.json','["今日清明節，園林勝事偏。", "晴風吹柳絮，新火起廚煙。", "杜草開三逕，文章憶二賢。", "幾時能命駕，對酒落花前。"]'),
('3efc3cf0-67fb-4e3d-8d01-9de558b43d13','上杜駙馬','賈島','唐','唐诗','tang','','[]','玉山突兀壓乾坤，出得朱門入戟門。',64,'全唐诗/poet.tang.32000.json','["玉山突兀壓乾坤，出得朱門入戟門。", "妻是九重天子女，身爲一品令公孫。", "鴛鴦殿裏參皇后，龍鳳堂前賀至尊。", "今日澧陽非久駐，佇爲霖雨拜新恩。"]'),
('543f20a9-4178-4f2c-b280-cdf690cf93f8','蓮峰歌','賈島','唐','唐诗','tang','','[]','錦礫潺湲玉溪水，曉來微雨藤花紫。',64,'全唐诗/poet.tang.32000.json','["錦礫潺湲玉溪水，曉來微雨藤花紫。", "冉冉山雞紅尾長，一聲樵斧驚飛起。", "松刺梳空石差齒，煙香風軟人參蕊。", "陽崖一夢伴雲根，仙菌靈芝夢魂裏。"]'),
('45f99d63-b306-40c3-8d4a-cf71c7057e51','壯士吟','賈島','唐','唐诗','tang','','[]','壯士不曾悲，悲即無回期。',24,'全唐诗/poet.tang.32000.json','["壯士不曾悲，悲即無回期。", "如何易水上，未歌先淚垂。"]'),
('51943122-8340-42b6-be85-c36a901b9087','題興化園亭','賈島','唐','唐诗','tang','','[]','破却千家作一池，不栽桃李種薔薇。',32,'全唐诗/poet.tang.32000.json','["破却千家作一池，不栽桃李種薔薇。", "薔薇花落秋風起，荆棘滿庭君始知。"]'),
('ee4860b7-5585-40aa-86ec-d4dbde20efb6','竹','賈島','唐','唐诗','tang','','[]','籬外清陰接藥欄，曉風交戛碧琅玕。',32,'全唐诗/poet.tang.32000.json','["籬外清陰接藥欄，曉風交戛碧琅玕。", "子猷沒後知音少，粉節霜筠漫歲寒。"]'),
('73bb067c-775a-44c7-a367-27f9080ec92b','李斯井','賈島','唐','唐诗','tang','','[]','井存上蔡南門外，置此井時來相秦。',32,'全唐诗/poet.tang.32000.json','["井存上蔡南門外，置此井時來相秦。", "斷綆數尋垂古甃，取將寒水是何人。"]'),
('563c81a7-b98e-426c-bd78-2dc7e0939d3c','題詩後','賈島','唐','唐诗','tang','','[]','二句三年得，一吟雙淚流。',24,'全唐诗/poet.tang.32000.json','["二句三年得，一吟雙淚流。", "知音如不賞，歸臥故山秋。"]'),
('471b6883-689e-407a-bc38-4ebc94ba3da9','送友人之南陵','賈島','唐','唐诗','tang','','[]','莫歎徒勞向宦途，不羣氣岸有誰如。',64,'全唐诗/poet.tang.32000.json','["莫歎徒勞向宦途，不羣氣岸有誰如。", "南陵暫掌仇香印，北闕終行賈誼書。", "好趂江山尋勝境，莫辭韋杜別幽居。", "少年躍馬同心使，免得詩中道跨驢。"]'),
('e8fd4040-6538-4696-89b5-1f65219f096f','尋人不遇','賈島','唐','唐诗','tang','','[]','聞說到揚州，吹簫有舊遊。',24,'全唐诗/poet.tang.32000.json','["聞說到揚州，吹簫有舊遊。", "人來多不見，莫是上迷樓。"]'),
('4f6575cc-12cc-4986-8bfc-5cedac7bb68f','尋隱者不遇','賈島','唐','唐诗','tang','','["\u4e94\u8a00\u7edd\u53e5", "\u5199\u4eba", "\u5bfb\u8bbf", "\u5510\u8bd7\u4e09\u767e\u9996"]','松下問童子，言師採藥去。',24,'全唐诗/poet.tang.32000.json','["松下問童子，言師採藥去。", "只在此山中，雲深不知處。"]'),
('ca3bd849-1b60-4fe1-9825-ce24b1848af6','行次漢上','賈島','唐','唐诗','tang','','[]','習家池沼草萋萋，嵐樹光中信馬蹄。',32,'全唐诗/poet.tang.32000.json','["習家池沼草萋萋，嵐樹光中信馬蹄。", "漢主廟前湘水碧，一聲風角夕陽低。"]'),
('27c15631-b181-46bd-8815-96bc407b77df','馬嵬','賈島','唐','唐诗','tang','','[]','長川幾處樹青青，孤驛危樓對翠屏。',32,'全唐诗/poet.tang.32000.json','["長川幾處樹青青，孤驛危樓對翠屏。", "一自上皇惆悵後，至今來往馬蹄腥。"]'),
('f3252596-3479-4349-8080-ea61ff3be551','冬夜送人','賈島','唐','唐诗','tang','','["\u6292\u60c5", "\u53cb\u4eba", "\u9001\u522b", "\u4f24\u6000"]','平明走馬上村橋，花落梅溪雪未消。',32,'全唐诗/poet.tang.32000.json','["平明走馬上村橋，花落梅溪雪未消。", "日短天寒愁送客，楚山無限路迢迢。"]'),
('40d96c31-f4c6-49c6-9c68-872d584c5b74','句','賈島','唐','唐诗','tang','','["\u957f\u6c5f"]','晴風吹柳絮，新火起廚煙。',48,'全唐诗/poet.tang.32000.json','["晴風吹柳絮，新火起廚煙。", "長江風送客，孤館雨留人。", "古岸崩將盡，平沙長未休。", "不如牛與羊，猶得日暮歸。"]'),
('8fd87152-66cb-4ee9-9932-82b48cad138a','雞鳴埭曲','溫庭筠','唐','唐诗','tang','','[]','南朝天子射雉時，銀河耿耿星參差。',160,'全唐诗/poet.tang.32000.json','["南朝天子射雉時，銀河耿耿星參差。", "銅壺漏斷夢初覺，寶馬塵高人未知。", "魚躍蓮東蕩宮沼，濛濛御柳懸棲鳥。", "紅妝萬戶鏡中春，碧樹一聲天下曉。", "盤踞勢窮三百年，朱方殺氣成愁煙。", "彗星拂地浪連海，戰鼓渡江塵漲天。", "繡龍畫雉填宮井，野火風驅燒九鼎。", "殿巢江燕砌生蒿，十二金人霜炯炯。", "芊綿平綠臺城基，暖色春容荒古陂。", "寧知玉樹後庭曲，留待野棠如雪枝。"]'),
('218ef7e6-38d1-4b4a-ad51-312bfd07cc90','織錦詞','溫庭筠','唐','唐诗','tang','','[]','丁東細漏侵瓊瑟，影轉高梧月初出。',96,'全唐诗/poet.tang.32000.json','["丁東細漏侵瓊瑟，影轉高梧月初出。", "簇簌金梭萬縷紅，鴛鴦豔錦初成匹。", "錦中百結皆同心，蘂亂雲盤相間深。", "此意欲傳傳不得，玫瑰作柱朱弦琴。", "爲君裁破合歡被，星斗迢迢共千里。", "象尺熏爐未覺秋，碧池已有新蓮子。"]'),
('39ec68ae-7037-4d89-8c33-a80243289f75','夜宴謠','溫庭筠','唐','唐诗','tang','','[]','長釵墜髮雙蜻蜓，碧盡山斜開畫屏。',128,'全唐诗/poet.tang.32000.json','["長釵墜髮雙蜻蜓，碧盡山斜開畫屏。", "虬鬚公子五侯客，一飲千鍾如建瓴。", "鸞咽奼唱圓無節，眉歛湘煙袖迴雪。", "清夜恩情四座同，莫令溝水東西別。", "亭亭蠟淚香珠殘，暗露曉風羅幕寒。", "飄颻戟帶儼相次，二十四枝龍畫竿。", "裂管縈弦共繁曲，芳樽細浪傾春醁。", "高樓客散杏花多，脉脉新蟾如瞪目。"]'),
('a8da5c20-a77c-4bca-b863-81bed34191fe','蓮浦謠','溫庭筠','唐','唐诗','tang','','["\u6000\u4eba", "\u611f\u65f6", "\u5199\u4eba", "\u5199\u4eba\u8bd7"]','鳴橈軋軋溪溶溶，廢綠平煙吳苑東。',64,'全唐诗/poet.tang.32000.json','["鳴橈軋軋溪溶溶，廢綠平煙吳苑東。", "水清蓮媚兩相向，鏡裏見愁愁更紅。", "白馬金鞭大堤上，西江日夕多風浪。", "荷心有露似驪珠，不是真圓亦搖蕩。"]'),
('b130568d-ec30-48db-ae64-7883c77f10b7','郭處士擊甌歌','溫庭筠','唐','唐诗','tang','','[]','佶栗金虬石潭古，勺陂瀲灩幽脩語。',178,'全唐诗/poet.tang.32000.json','["佶栗金虬石潭古，勺陂瀲灩幽脩語。", "湘君寶馬上神雲，碎佩叢鈴滿煙雨。", "吾聞三十六宮花離離，軟風吹春星斗稀。", "玉晨冷磬破昏夢，天露未乾香著衣。", "蘭釵委墜垂雲髮，小響丁當逐迴雪。", "晴碧煙滋重疊山，羅屏半掩桃花月。", "太平天子駐雲車，龍鑪勃鬱雙蟠拏。", "宮中近臣抱扇立，侍女低鬟落翠花。", "亂珠觸續正跳蕩，傾頭不覺金烏斜。", "我亦爲君長歎息，緘情遠寄愁無色。", "莫霑香夢綠楊絲，千里春風正無力。"]'),
('2a017556-7bd9-405e-b792-093428c88cab','遐水謠','溫庭筠','唐','唐诗','tang','','[]','天兵九月渡遐水，馬踏沙鳴驚雁起。',96,'全唐诗/poet.tang.32000.json','["天兵九月渡遐水，馬踏沙鳴驚雁起。", "殺氣空高萬里情，塞寒如箭傷眸子。", "狼煙堡上霜漫漫，枯葉號風天地乾。", "犀帶鼠裘無暖色，清光炯冷黃金鞍。", "虜塵如霧昏亭障，隴首年年漢飛將。", "麟閣無名期未歸，樓中思婦徒相望。"]'),
('7f3bd91b-92b1-4cd3-933e-eb4bad31ebb6','曉仙謠','溫庭筠','唐','唐诗','tang','','[]','玉妃喚月歸海宮，月色澹白涵春空。',128,'全唐诗/poet.tang.32000.json','["玉妃喚月歸海宮，月色澹白涵春空。", "銀河欲轉星靨靨，碧浪疊山埋早紅。", "宮花有露如新淚，小苑叢叢入寒翠。", "綺閣空傳唱漏聲，網軒未辨凌雲字。", "遙遙珠帳連湘煙，鶴扇如霜金骨仙。", "碧簫曲盡彩霞動，下視九州皆悄然。", "秦王女騎紅尾鳳，半空回首晨雞弄。", "霧蓋狂塵億兆家，世人猶作牽情夢。"]'),
('00a9475d-6686-4421-9d18-f11b5819071d','錦城曲','溫庭筠','唐','唐诗','tang','','[]','蜀山攢黛留晴雪，簝笋蕨芽縈九折。',96,'全唐诗/poet.tang.32000.json','["蜀山攢黛留晴雪，簝笋蕨芽縈九折。", "江風吹巧剪霞綃，花上千枝杜鵑血。", "杜鵑飛入巖下叢，夜呌思歸山月中。", "巴水漾情情不盡，文君織得春機紅。", "怨魄未歸芳草死，江頭學種相思子。", "樹成寄與望鄉人，白帝荒城五千里。"]'),
('b1c56a8f-0b6a-4402-8d56-d2382a44d77f','生禖屏風歌','溫庭筠','唐','唐诗','tang','','[]','玉墀暗接昆侖井，井上無人金索冷。',64,'全唐诗/poet.tang.32000.json','["玉墀暗接昆侖井，井上無人金索冷。", "畫壁陰森九子堂，階前細月鋪花影。", "繡屏銀鴨香蓊濛，天上夢歸花繞叢。", "宜男漫作後庭草，不似櫻桃千子紅。"]'),
('a352cadf-ae4d-45bc-9df5-c10ce5de5ae1','嘲春風','溫庭筠','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u98ce", "\u98ce", "\u8d5e\u7f8e"]','春風何處好，別殿饒芳草。',48,'全唐诗/poet.tang.32000.json','["春風何處好，別殿饒芳草。", "苒嫋轉鸞旗，萎蕤吹雉葆。", "揚芳歷九門，澹蕩入蘭蓀。", "爭奈白團扇，時時偷主恩。"]'),
('34eb8904-b418-40ee-8fda-fab1b71af496','舞衣曲','溫庭筠','唐','唐诗','tang','','[]','藕腸纖縷抽輕春，煙機漠漠嬌娥嚬。',128,'全唐诗/poet.tang.32000.json','["藕腸纖縷抽輕春，煙機漠漠嬌娥嚬。", "金梭淅瀝透空薄，剪落交刀吹斷雲。", "張家公子夜聞雨，夜向蘭堂思楚舞。", "蟬衫麟帶壓愁香，偷得鶯簧鏁金縷。", "管含蘭氣嬌語悲，胡槽雪腕鴛鴦絲。", "芙蓉力弱應難定，楊柳風多不自持。", "迴嚬笑語西牕客，星斗寥寥波脉脉。", "不逐秦王卷象牀，滿樓明月梨花白。"]'),
('aab693a7-a1dc-40d4-a2fa-58ddf3087340','張靜婉採蓮歌','溫庭筠','唐','唐诗','tang','','[]','蘭膏墜髮紅玉春，燕釵拖頸拋盤雲。',160,'全唐诗/poet.tang.32000.json','["蘭膏墜髮紅玉春，燕釵拖頸拋盤雲。", "城邊楊柳向嬌晚，門前溝水波粼粼。", "麒麟公子朝天客，珂馬璫璫度春陌。", "掌中無力舞衣輕，剪斷鮫綃破春碧。", "抱月飄煙一尺腰，麝臍龍髓憐嬌嬈。", "秋羅拂水碎光動，露重花多香不銷。", "鸂鶒交交塘水滿，綠芒如粟蓮莖短。", "一夜西風送雨來，粉痕零落愁紅淺。", "船頭折藕絲暗牽，藕根蓮子相留連。", "郎心似月月未缺，十五十六清光圓。"]'),
('637ab18d-596b-4458-bed8-d6c6d6f18b2f','湘宮人歌','溫庭筠','唐','唐诗','tang','','[]','池塘芳草濕，夜半東風起。',48,'全唐诗/poet.tang.32000.json','["池塘芳草濕，夜半東風起。", "生綠畫羅屏，金壺貯春水。", "黃粉楚宮人，芳花玉刻鱗。", "娟娟照棊燭，不語兩含嚬。"]'),
('e8bae9fe-b06f-4907-b243-9b16e16a5aeb','黃曇子歌','溫庭筠','唐','唐诗','tang','','[]','參差綠蒲短，搖豔雲塘滿。',48,'全唐诗/poet.tang.32000.json','["參差綠蒲短，搖豔雲塘滿。", "紅瀲蕩融融，鶯翁鸂鶒暖。", "萋芊小成路，馬上修蛾嬾。", "羅衫褭回風，點粉金鸝卵。"]'),
('0ea8bb3d-29e3-4f4d-8ddb-556ff7d68951','觱篥歌','溫庭筠','唐','唐诗','tang','','[]','蠟煙如纛新蟾滿，門外平沙草芽短。',160,'全唐诗/poet.tang.32000.json','["蠟煙如纛新蟾滿，門外平沙草芽短。", "黑頭丞相九天歸，夜聽飛瓊吹朔管。", "情遠氣調蘭蕙薰，天香瑞彩含絪緼。", "皓然纖指都揭血，日暖碧霄無片雲。", "含商咀徵雙幽咽，軟縠疎羅共蕭屑。", "不盡長圓疊翠愁，柳風吹破澄潭月。", "鳴梭淅瀝金絲蘂，恨語殷勤隴頭水。", "漢將營前萬里沙，更深一一霜鴻起。", "十二樓前花正繁，交枝簇蔕連壁門。", "景陽宮女正愁絕，莫使此聲催斷魂。"]'),
('8c8ec5b0-7744-4b41-8218-7e0ef6d5db42','照影曲','溫庭筠','唐','唐诗','tang','','[]','景陽妝罷瓊牕暖，欲照澄明香步嬾。',64,'全唐诗/poet.tang.32000.json','["景陽妝罷瓊牕暖，欲照澄明香步嬾。", "橋上衣多抱彩雲，金鱗不動春塘滿。", "黃印額山輕爲塵，翠鱗紅穉俱含嚬。", "桃花百媚如欲語，曾爲無雙今兩身。"]'),
('9bfbcd29-e1c6-449a-b506-37fa8cd97d09','拂舞詞','溫庭筠','唐','唐诗','tang','','["\u9ec4\u6cb3", "\u548f\u7269", "\u548f\u7269\u8bd7"]','黃河怒浪連天來，大響谹谹如殷雷。',96,'全唐诗/poet.tang.32000.json','["黃河怒浪連天來，大響谹谹如殷雷。", "龍伯驅風不敢上，百川噴雪高崔嵬。", "二十三弦何太哀，請公勿渡立徘徊。", "下有狂蛟鋸爲尾，裂帆截櫂磨霜齒。", "神椎鑿石塞神潭，白馬䟃𧽼赤塵起。", "公乎躍馬揚玉鞭，滅沒高蹄日千里。"]'),
('a719c277-bb80-4b9a-a329-b7884474e154','太液池歌','溫庭筠','唐','唐诗','tang','','[]','腥鮮龍氣連清防，花風漾漾吹細光。',64,'全唐诗/poet.tang.32000.json','["腥鮮龍氣連清防，花風漾漾吹細光。", "疊瀾不定照天井，倒影蕩搖晴翠長。", "平碧淺春生綠塘，雲容雨態連青蒼。", "夜深銀漢通柏梁，二十八宿朝玉堂。"]'),
('37a211de-64db-4498-90fd-045bf1e274e2','雉場歌','溫庭筠','唐','唐诗','tang','','[]','茭葉萋萋接煙曙，雞鳴埭上梨花露。',96,'全唐诗/poet.tang.32000.json','["茭葉萋萋接煙曙，雞鳴埭上梨花露。", "彩杖鏘鏘已合圍，繡翎白頸遙相妬。", "雕尾扇張金縷高，碎鈴素拂驪駒豪。", "綠場紅跡未相接，箭發銅牙傷彩毛。", "麥隴桑陰小山晚，六虬歸去凝笳遠。", "城頭却望幾含情，青畝春蕪連石苑。"]'),
('4c4b9a87-3ea2-4322-9f00-9f0676e99763','雍臺歌','溫庭筠','唐','唐诗','tang','','[]','太子池南樓百尺，入窓新樹疎簾隔。',64,'全唐诗/poet.tang.32000.json','["太子池南樓百尺，入窓新樹疎簾隔。", "黃金鋪首畫鉤陳，羽葆停幢拂交戟。", "盤紆闌楯臨高臺，帳殿臨流鸞扇開。", "早鴈驚鳴細波起，映花鹵簿龍飛迴。"]'),
('7b64c895-f608-4595-9a77-42332271cdf9','吳苑行','溫庭筠','唐','唐诗','tang','','[]','錦雉雙飛梅結子，平春遠綠牕中起。',64,'全唐诗/poet.tang.32000.json','["錦雉雙飛梅結子，平春遠綠牕中起。", "吳江澹畫水連空，三尺屏風隔千里。", "小苑有門紅扇開，天絲舞蝶共徘徊。", "綺戶雕楹長若此，韶光歲歲如歸來。"]'),
('7ea100ee-aae2-4b7f-ac7b-26ddfa221071','常林歡歌','溫庭筠','唐','唐诗','tang','','[]','宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。',64,'全唐诗/poet.tang.32000.json','["宜城酒熟花覆橋，沙晴綠鴨鳴咬咬。", "穠桑繞舍麥如尾，幽軋鳴機雙燕巢。", "馬聲特特荆門道，蠻水揚光色如草。", "錦薦金爐夢正長，東家咿喔雞鳴早。"]'),
('a2c005e0-2468-4fc7-b7e8-1ee6c06a9075','塞寒行','溫庭筠','唐','唐诗','tang','','[]','燕弓弦勁霜封瓦，樸簌寒鵰睇平野。',96,'全唐诗/poet.tang.32000.json','["燕弓弦勁霜封瓦，樸簌寒鵰睇平野。", "一點黃塵起鴈喧，白龍堆下千蹄馬。", "河源怒濁風如刀，剪斷朔雲天更高。", "晚出榆關逐征北，驚沙飛迸衝貂袍。", "心許凌煙名不滅，年年錦字傷離別。", "彩毫一畫竟何榮，空使青樓淚成血。"]'),
('5ba3be8c-3434-48e5-a239-9fcc54e2486f','湖陰詞','溫庭筠','唐','唐诗','tang','','[]','祖龍黃鬚珊瑚鞭，鐵驄金面青連錢。',128,'全唐诗/poet.tang.32000.json','["祖龍黃鬚珊瑚鞭，鐵驄金面青連錢。", "虎髯拔劒欲成夢，日壓賊營如血鮮。", "海旗風急驚眠起，甲重光搖照湖水。", "蒼黃追騎塵外歸，森索妖星陣前死。", "五陵愁碧春萋萋，霸川玉馬空中嘶。", "羽書如電入青璅，雪腕如槌催畫鞞。", "白虬天子金煌鋩，高臨帝座迴龍章。", "吳波不動楚山晚，花壓闌干春晝長。"]'),
('3d0ab06b-fbef-4b43-9b75-91edfbc504e1','蔣侯神歌','溫庭筠','唐','唐诗','tang','','[]','楚神鐵馬金鳴珂，夜動蛟潭生素波。',96,'全唐诗/poet.tang.32000.json','["楚神鐵馬金鳴珂，夜動蛟潭生素波。", "商風刮水報西帝，廟前古樹蟠白虵。", "吳王赤斧斫雲陣，畫堂列壁叢霜刃。", "巫娥傳意托悲絲，鐸語琅琅理雙鬢。", "湘煙刷翠湘山斜，東方日出飛神鴉。", "青雲自有黑龍子，潘妃莫結丁香花。"]'),
('086c429a-99ec-45d8-9b9a-0c4b9355d775','漢皇迎春詞','溫庭筠','唐','唐诗','tang','','[]','春草芊芊晴掃煙，宮城大錦紅殷鮮。',112,'全唐诗/poet.tang.32000.json','["春草芊芊晴掃煙，宮城大錦紅殷鮮。", "海日初融照仙掌，淮王小隊纓鈴響。", "獵獵東風燄赤旗，畫神金甲葱蘢網。", "鉅公步輦迎句芒，複道掃塵燕彗長。", "豹尾竿前趙飛燕，柳風吹盡眉間黃。", "碧草含情杏花喜，上林鶯囀遊絲起。", "寶馬搖環萬騎歸，恩光暗入簾櫳裏。"]'),
('3d522dba-b5dd-43b4-af06-a5bead6a0a4a','蘭塘詞','溫庭筠','唐','唐诗','tang','','[]','塘水汪汪鳧唼喋，憶上江南木蘭檝。',96,'全唐诗/poet.tang.32000.json','["塘水汪汪鳧唼喋，憶上江南木蘭檝。", "繡頸金鬚蕩倒光，團團皺綠雞頭葉。", "露凝荷卷珠淨圓，紫菱刺短浮根纏。", "小姑歸晚紅妝淺，鏡裏芙蓉照水鮮。", "東溝潏潏勞迴首，欲寄一杯瓊液酒。", "知道無郎却有情，長敎月照相思柳。"]'),
('0d4e879d-9cf7-4890-8780-49af2c1b2136','晚歸曲','溫庭筠','唐','唐诗','tang','','[]','格格水禽飛帶波，孤光斜起夕陽多。',128,'全唐诗/poet.tang.32000.json','["格格水禽飛帶波，孤光斜起夕陽多。", "湖西山淺似相笑，菱刺惹衣攢黛蛾。", "青絲繫船向江木，蘭芽出土吳江曲。", "水極晴搖泛灩紅，草平春染煙綿綠。", "玉鞭騎馬楊叛兒，刻金作鳳光參差。", "丁丁暖漏滴花影，催入景陽人不知。", "彎堤弱柳遙相矚，雀扇團圓掩香玉。", "蓮塘艇子歸不歸，柳暗桑穠聞布穀。"]'),
('2fcbdb24-5988-45e1-abad-580a0b9148d5','故城曲','溫庭筠','唐','唐诗','tang','','[]','漠漠沙堤煙，堤西雉子斑。',72,'全唐诗/poet.tang.32000.json','["漠漠沙堤煙，堤西雉子斑。", "雉聲何角角，麥秀桑陰閑。", "遊絲蕩平綠，明滅時相續。", "白馬金絡頭，東風故城曲。", "故城殷貴嬪，曾占未來春。", "自從香骨化，飛作馬蹄塵。"]'),
('2d3ff2e5-a6c6-4e3d-a77b-87e52009262e','昆明池水戰詞','溫庭筠','唐','唐诗','tang','','[]','汪汪積水光連空，重疊細紋晴漾紅。',128,'全唐诗/poet.tang.32000.json','["汪汪積水光連空，重疊細紋晴漾紅。", "赤帝龍孫鱗甲怒，臨流一盼生陰風。", "鼉鼓三聲報天子，雕旌獸艦凌波起。", "雷吼濤驚白石山，石鯨眼裂蟠蛟死。", "溟池海浦俱喧豗，青幟白旌相次來。", "箭羽槍纓三百萬，踏翻西海生塵埃。", "茂陵仙去菱花老，唼唼遊魚近煙島。", "渺莽殘陽釣艇歸，綠頭江鴨眠沙草。"]'),
('89e9397e-4e89-45f3-9a5f-d2b35c65b1d9','謝公墅歌','溫庭筠','唐','唐诗','tang','','[]','朱雀航南繞香陌，謝郎東墅連春碧。',96,'全唐诗/poet.tang.32000.json','["朱雀航南繞香陌，謝郎東墅連春碧。", "鳩眠高柳日方融，綺榭飄颻紫庭客。", "文楸方罫花參差，心陣未成星滿池。", "四座無喧梧竹靜，金蟬玉柄俱持頤。", "對局含情見千里，都城已得長虵尾。", "江南王氣繫疎襟，未許苻堅過淮水。"]'),
('445b69dd-9702-4b83-8ecf-81c3bbd8cb4a','罩魚歌','溫庭筠','唐','唐诗','tang','','[]','朝罩罩城南，暮罩罩城西。',112,'全唐诗/poet.tang.32000.json','["朝罩罩城南，暮罩罩城西。", "兩漿鳴幽幽，蓮子相高低。", "持罩入深水，金鱗大如手。", "魚尾迸圓波，千珠落湘藕。", "風颸颸，雨離離，菱尖茭刺鸂鶒飛。", "水連網眼白如影，淅瀝篷聲寒點微。", "楚岸有花花蓋屋，金塘柳色前溪曲。", "悠溶杳若去無窮，五色澄潭鴨頭綠。"]'),
('396c09e9-dc8b-4650-bc25-acf554e59745','春洲曲','溫庭筠','唐','唐诗','tang','','["\u6625\u5929", "\u5199\u666f"]','韶光染色如蛾翠，綠濕紅鮮水容媚。',64,'全唐诗/poet.tang.32000.json','["韶光染色如蛾翠，綠濕紅鮮水容媚。", "蘇小慵多蘭渚閑，融融浦日鵁鶄寐。", "紫騮蹀躞金銜嘶，岸上揚鞭煙草迷。", "門外平橋連柳堤，歸來晚樹黃鶯啼。"]'),
('12526081-cca9-439a-9a23-6e7b681ef2f5','臺城曉朝曲','溫庭筠','唐','唐诗','tang','','[]','司馬門前火千炬，蘭干星斗天將曙。',64,'全唐诗/poet.tang.32000.json','["司馬門前火千炬，蘭干星斗天將曙。", "朱網龕鬖丞相車，曉隨疊鼓朝天去。", "博山鏡樹香䒠茸，褭褭浮航金畫龍。", "大江歛勢避辰極，兩闕深嚴煙翠濃。"]'),
('aca5d1d1-7bce-42b6-b025-2d23c81624bc','走馬樓三更曲','溫庭筠','唐','唐诗','tang','','[]','春姿暖氣昏神沼，李樹拳枝紫芽小。',64,'全唐诗/poet.tang.32000.json','["春姿暖氣昏神沼，李樹拳枝紫芽小。", "玉皇夜入未央宮，長火千條照棲鳥。", "馬過平橋通畫堂，虎幡龍戟風飄揚。", "簾間清唱報寒點，丙舍無人遺燼香。"]'),
('da0c9f4e-4db4-404d-8d98-b415cf93dcad','達摩支曲','溫庭筠','唐','唐诗','tang','','[]','擣麝成塵香不滅，拗蓮作寸絲難絕。',99,'全唐诗/poet.tang.32000.json','["擣麝成塵香不滅，拗蓮作寸絲難絕。", "紅淚文姬洛水春，白頭蘇武天山雪。", "君不見無愁高緯花漫漫，漳浦宴餘清露寒。", "一旦臣僚共囚虜，欲吹羌管先汍瀾。", "舊臣頭鬢霜華早，可惜雄心醉中老。", "萬古春歸夢不歸，鄴城風雨連天草。"]'),
('b85033bc-2e60-4226-8bc8-75749b3536c0','陽春曲','溫庭筠','唐','唐诗','tang','','[]','雲母空牕曉煙薄，香昏龍氣凝暉閣。',64,'全唐诗/poet.tang.32000.json','["雲母空牕曉煙薄，香昏龍氣凝暉閣。", "霏霏霧雨杏花天，簾外春威著羅幕。", "曲闌伏檻金麒麟，沙苑芳郊連翠茵。", "廐馬何能嚙芳草，路人不敢隨流塵。"]'),
('29b32830-adc6-4711-9694-a693002585a4','湘東宴曲','溫庭筠','唐','唐诗','tang','','[]','湘東夜宴金貂人，楚女含情嬌翠嚬。',96,'全唐诗/poet.tang.32000.json','["湘東夜宴金貂人，楚女含情嬌翠嚬。", "玉管將吹插鈿帶，錦囊斜拂雙麒麟。", "重城漏斷孤帆去，唯恐瓊籤報天曙。", "萬戶沈沈碧樹圓，雲飛雨散知何處。", "欲上香車俱脉脉，清歌響斷銀屏隔。", "堤外紅塵蠟炬歸，樓前澹月連江白。"]'),
('0ea1677a-dbc9-4dd5-8373-62f8fab1acba','東郊行','溫庭筠','唐','唐诗','tang','','[]','鬬雞臺下東西道，柳覆班騅蝶縈草。',96,'全唐诗/poet.tang.32000.json','["鬬雞臺下東西道，柳覆班騅蝶縈草。", "坱靄韶容鏁澹愁，青筐葉盡蠶應老。", "綠渚幽香生白蘋，差差小浪吹魚鱗。", "王孫騎馬有歸意，林彩着空如細塵。", "安得人生各相守，燒船破棧休馳走。", "世上方應無別離，路傍更長千株柳。"]'),
('3e6fb299-803e-4e6b-bb02-d9d0c7f343f1','水仙謠','溫庭筠','唐','唐诗','tang','','[]','水客夜騎紅鯉魚，赤鸞雙鶴蓬瀛書。',64,'全唐诗/poet.tang.32000.json','["水客夜騎紅鯉魚，赤鸞雙鶴蓬瀛書。", "輕塵不起雨新霽，萬里孤光含碧虛。", "露魄冠輕見雲髮，寒絲七炷香泉咽。", "夜深天碧亂山姿，光碎平波滿船月。"]'),
('4117787f-d5ee-478b-9d97-eaf731645697','東峯歌','溫庭筠','唐','唐诗','tang','','[]','錦礫潺湲玉溪水，曉來微雨藤花紫。',64,'全唐诗/poet.tang.32000.json','["錦礫潺湲玉溪水，曉來微雨藤花紫。", "冉冉山雞紅尾長，一聲樵斧驚飛起。", "松刺梳空石差齒，煙香風軟人參蘂。", "陽崖一夢伴雲根，仙菌靈芝夢魂裏。"]'),
('8e2d7e5b-43cf-4f60-8fbf-0a07bc37566d','會昌丙寅豐歲歌','溫庭筠','唐','唐诗','tang','','[]','丙寅歲，休牛馬。',98,'全唐诗/poet.tang.32000.json','["丙寅歲，休牛馬。", "風如吹煙，日如渥赭。", "九重天子調天下，春綠將年到西野。", "西野翁，生兒童。", "門前好樹青䒠茸，䒠茸單衣麥田路。", "村南娶婦桃花紅，新姑車右及門柱，粉項韓憑雙扇中。", "喜氣自能成歲豐，農祥爾物來爭功。"]'),
('f4458131-dd91-425b-b517-292310925fd7','碌碌古詞','溫庭筠','唐','唐诗','tang','','[]','左亦不碌碌，右亦不碌碌。',72,'全唐诗/poet.tang.32000.json','["左亦不碌碌，右亦不碌碌。", "野草自根肥，羸牛生健犢。", "融蠟作杏蒂，男兒不戀家。", "春風破紅意，女頰如桃花。", "忠言未見信，巧語翻咨嗟。", "一鞘無兩刃，徒勞油壁車。"]'),
('93c6e6e8-bcdc-43c6-96af-e0c3418376ef','春野行','溫庭筠','唐','唐诗','tang','','[]','草淺淺，春如剪。',52,'全唐诗/poet.tang.32000.json','["草淺淺，春如剪。", "花壓李娘愁，飢蠶欲成繭。", "東城年少氣堂堂，金丸驚起雙鴛鴦。", "含羞更問衛公子，月到枕前春夢長。"]'),
('36b70e35-54e7-466c-aae9-b8632fb6c1b4','醉歌','溫庭筠','唐','唐诗','tang','','[]','簷柳初黃燕新乳，曉碧芊綿過微雨。',240,'全唐诗/poet.tang.32000.json','["簷柳初黃燕新乳，曉碧芊綿過微雨。", "樹色深含臺榭情，鶯聲巧作煙花主。", "錦袍公子陳杯觴，撥醅百甕春酒香。", "入門下馬問誰在，降堦握手登華堂。", "臨邛美人連山眉，低抱琵琶含怨思。", "朔風繞指我先笑，明月入懷君自知。", "勸君莫惜金樽酒，年少須臾如覆手。", "辛勤到老慕簞瓢，於我悠悠竟何有。", "洛陽盧仝稱文房，妻子脚禿舂黃糧。", "阿耋光顏不識字，指麾豪儁如驅羊。", "天犀壓斷朱鼹鼠，瑞錦驚飛金鳳皇。", "其餘豈足霑牙齒，欲用何能報天子。", "駑馬垂頭搶暝塵，驊騮一日行千里。", "但有沈冥醉客家，支頤瞪目持流霞。", "唯恐南國風雨落，碧蕪狼籍棠梨花。"]'),
('c2d36d62-b954-4bf7-b93b-2a28cc1bfd05','江南曲','溫庭筠','唐','唐诗','tang','','[]','妾家白蘋浦，日上芙蓉檝。',240,'全唐诗/poet.tang.32000.json','["妾家白蘋浦，日上芙蓉檝。", "軋軋搖漿聲，移舟入茭葉。", "溪長茭葉深，作底難相尋。", "避郎郎不見，鸂鶒自浮沈。", "拾萍萍無根，採蓮蓮有子。", "不作浮萍生，寧爲藕花死。", "岸傍騎馬郎，烏帽紫遊韁。", "含愁復含笑，回首問橫塘。", "妾住金陵浦，門前朱雀航。", "流蘇持作帳，芙蓉持作梁。", "出入金犢幰，兄弟侍中郎。", "前年學歌舞，定得郎相許。", "連娟眉繞山，依約腰如杵。", "鳳管悲若咽，鸞弦嬌欲語。", "扇薄露紅鉛，羅輕壓金縷。", "明月西南樓，珠簾玳瑁鉤。", "橫波巧能笑，彎蛾不識愁。", "花開子留樹，草長根依土。", "早聞金溝遠，底事歸郎許。", "不學楊白花，朝朝淚如雨。"]'),
('d9791443-723d-4d0d-bc59-1c5b7eae5803','堂堂曲','溫庭筠','唐','唐诗','tang','','[]','錢唐岸上春如織，淼淼寒潮帶睛色。',64,'全唐诗/poet.tang.32000.json','["錢唐岸上春如織，淼淼寒潮帶睛色。", "淮南遊客馬連嘶，碧草迷人歸不得。", "風飄客意如吹煙，纖指殷勤傷雁弦。", "一曲堂堂紅燭筵，長鯨瀉酒如飛泉。"]'),
('d89c3568-7852-4241-ba7b-d3c98807ba0f','惜春詞','溫庭筠','唐','唐诗','tang','','["\u6625\u5929", "\u611f\u4f24", "\u5973\u5b50", "\u60dc\u82b1"]','百舌問花花不語，低迴似恨橫塘雨。',64,'全唐诗/poet.tang.32000.json','["百舌問花花不語，低迴似恨橫塘雨。", "蜂爭粉蘂蝶分香，不似垂楊惜金縷。", "願君留得長妖韶，莫逐東風還蕩搖。", "秦女含嚬向煙月，愁紅帶露空迢迢。"]'),
('6098df4a-d47d-4882-86a3-09b33dbadf92','春愁曲','溫庭筠','唐','唐诗','tang','','[]','紅絲穿露珠簾冷，百尺啞啞下纖綆。',96,'全唐诗/poet.tang.32000.json','["紅絲穿露珠簾冷，百尺啞啞下纖綆。", "遠翠愁山入臥屏，兩重雲母空烘影。", "涼簪墜髮春眠重，玉兔煴香柳如夢。", "錦疊空牀委墮紅，颸颸掃尾雙金鳳。", "蜂喧蝶駐俱悠揚，柳拂赤欄纖草長。", "覺後梨花委平綠，春風和雨吹池塘。"]'),
('1ec12e46-6e5d-4889-bda3-436cb0266864','蘇小小歌','溫庭筠','唐','唐诗','tang','','[]','買蓮莫破券，買酒莫解金。',60,'全唐诗/poet.tang.32000.json','["買蓮莫破券，買酒莫解金。", "酒裏春容抱離恨，水中蓮子懷芳心。", "吳宮女兒腰似束，家在錢唐小江曲。", "一自檀郎逐便風，門前春水年年綠。"]'),
('f7a0d6a9-c4fe-4f42-80ad-9ec2c2a0522f','春江花月夜詞','溫庭筠','唐','唐诗','tang','','["\u957f\u6c5f"]','玉樹歌闌海雲黑，花庭忽作青蕪國。',160,'全唐诗/poet.tang.32000.json','["玉樹歌闌海雲黑，花庭忽作青蕪國。", "秦淮有水水無情，還向金陵漾春色。", "楊家二世安九重，不御華芝嫌六龍。", "百幅錦帆風力滿，連天展盡金芙蓉。", "珠翠丁星復明滅，龍頭劈浪哀笳發。", "千里涵空澄水魂，萬枝破鼻飄香雪。", "漏轉霞高滄海西，頗黎枕上聞天雞。", "蠻弦代寫曲如語，一醉昏昏天下迷。", "四方傾動煙塵起，猶在濃香夢魂裏。", "後主荒宮有曉鶯，飛來只隔西江水。"]'),
('a01af79c-7a30-4fae-8556-c36e4bbdf555','懊惱曲','溫庭筠','唐','唐诗','tang','','["\u6b4c\u9882", "\u5199\u4eba", "\u7231\u60c5"]','藕絲作線難勝鍼，蘂粉染黃那得深。',128,'全唐诗/poet.tang.32000.json','["藕絲作線難勝鍼，蘂粉染黃那得深。", "玉白蘭芳不相顧，青樓一笑輕千金。", "莫言自古皆如此，健劒刜鐘鉛繞指。", "三秋庭綠盡迎霜，惟有荷花守紅死。", "廬江小吏朱斑輪，柳縷吐芽香玉春。", "兩股金釵已相許，不令獨作空成塵。", "悠悠楚水流如馬，恨紫愁紅滿平野。", "野土千年怨不平，至今燒作鴛鴦瓦。"]'),
('d22d5225-8079-4bd5-99b1-91e7ba2fbd29','三洲詞','溫庭筠','唐','唐诗','tang','','[]','團圓莫作波中月，潔白莫爲枝上雪。',64,'全唐诗/poet.tang.32000.json','["團圓莫作波中月，潔白莫爲枝上雪。", "月隨波動碎潾潾，雪似梅花不堪折。", "李娘十六青絲髮，畫帶雙花爲君結。", "門前有路輕別離，唯恐歸來舊香滅。"]'),
('bde15c6c-785e-4ae8-81a2-a8b47e4197dc','春曉曲','溫庭筠','唐','唐诗','tang','','[]','家臨長信往來道，乳燕雙雙拂煙草。',64,'全唐诗/poet.tang.32000.json','["家臨長信往來道，乳燕雙雙拂煙草。", "油壁車輕金犢肥，流蘇帳曉春雞早。", "籠中嬌鳥暖猶睡，簾外落花閑不掃。", "衰桃一樹近前池，似惜紅顏鏡中老。"]'),
('f90a58c4-7b3e-4e33-a76a-fe0891190458','獵騎辭','溫庭筠','唐','唐诗','tang','','[]','早辭平扆殿，夕奉湘南宴。',84,'全唐诗/poet.tang.32000.json','["早辭平扆殿，夕奉湘南宴。", "香兔抱微煙，重鱗疊輕扇。", "蠶飢使君馬，雁避將軍箭。", "寶柱惜離弦，流黃悲赤縣。", "理釵低舞鬢，換袖迴歌面。", "晚柳未如絲，春花已如霰。", "所嗟故里曲，不及青樓宴。"]'),
('934920aa-3eb2-47d9-809e-a4ed081160d6','西州詞','溫庭筠','唐','唐诗','tang','','[]','悠悠復悠悠，昨日下西州。',168,'全唐诗/poet.tang.32000.json','["悠悠復悠悠，昨日下西州。", "西州風色好，遙見武昌樓。", "武昌何鬱鬱，儂家定無匹。", "小婦被流黃，登樓撫瑤瑟。", "朱弦繁復輕，素手直淒清。", "一彈三四解，掩抑似含情。", "南樓登且望，西江廣復平。", "艇子搖兩槳，催過石頭城。", "門前烏臼樹，慘澹天將曙。", "鸂鶒飛復還，郎隨早帆去。", "迴頭語同伴，定復負情儂。", "去帆不安幅，作抵使西風。", "他日相尋索，莫作西州客。", "西州人不歸，春草年年碧。"]'),
('7522233e-072d-4ee6-b735-a3cef602acb2','燒歌','溫庭筠','唐','唐诗','tang','','[]','起來望南山，山火燒山田。',192,'全唐诗/poet.tang.32000.json','["起來望南山，山火燒山田。", "微紅夕如滅，短燄復相連。", "差差向巖石，冉冉凌青壁。", "低隨迴風盡，遠照簷茅赤。", "鄰翁能楚言，倚插欲澘然。", "自言楚越俗，燒畬爲早田。", "豆苗蟲促促，籬上花當屋。", "廢棧豕歸欄，廣場雞啄粟。", "新年春雨晴，處處賽神聲。", "持錢就人卜，敲瓦隔林鳴。", "卜得山上卦，歸來桑棗下。", "吹火向白茅，腰鐮映赬蔗。", "風驅槲葉煙，槲樹連平山。", "迸星拂霞外，飛燼落堦前。", "仰面呻復嚏，鴉娘咒豐歲。", "誰知蒼翠容，盡作官家稅。"]'),
('621a9d7f-47a8-4b77-acb3-c158adb156ea','長安寺','溫庭筠','唐','唐诗','tang','','[]','仁祠寫露宮，長安佳氣濃。',96,'全唐诗/poet.tang.32000.json','["仁祠寫露宮，長安佳氣濃。", "煙樹含葱蒨，金剎映䒠茸。", "繡戶香焚象，珠網玉盤龍。", "寶題斜翡翠，天井倒芙蓉。", "幡長迴遠吹，牕虛含曉風。", "遊騎迷青鎖，歸鳥思華鐘。", "雲栱承跗邐，羽葆背花重。", "所嗟蓮社客，輕蕩不相從。"]'),
('88c845fa-0fc3-4908-add2-ffaa18f643f3','和沈參軍招友生觀芙蓉池','溫庭筠','唐','唐诗','tang','','[]','桂棟坐清曉，瑤琴商鳳絲。',120,'全唐诗/poet.tang.32000.json','["桂棟坐清曉，瑤琴商鳳絲。", "況聞楚澤香，適與秋風期。", "遂從櫂萍客，靜嘯煙草湄。", "倒影迴澹蕩，愁紅媚漣漪。", "湘莖久鮮澀，宿雨增離披。", "而我江海意，楚遊動夢思。", "北渚水雲葉，南塘煙霧枝。", "豈亡臺榭芳，獨與鷗鳥知。", "珠墜魚迸淺，影多鳧泛遲。", "落英不可攀，返照昏澄陂。"]'),
('a92e0483-953e-4b6e-b1b2-57c249a8eb4f','寓懷','溫庭筠','唐','唐诗','tang','','[]','誠足不顧得，妄矜徒有言。',96,'全唐诗/poet.tang.32000.json','["誠足不顧得，妄矜徒有言。", "語斯諒未盡，隱顯何悠然。", "洵彼都邑盛，眷惟車馬喧。", "自期尊客卿，非意干王孫。", "銜知有貞爵，處實非厚顏。", "苟無海岱氣，奚取壺漿恩。", "唯絲南山楊，適我松菊香。", "鵬鵾誠未憶，誰謂凌風翔。"]'),
('c174dcf6-c37f-4f50-97f1-d716528c3aa4','余昔自西濱得蘭數本移藝於庭亦既逾歲而芃然蕃殖自余遊者未始以芳草爲遇矣因悲夫物有厭常而反不若混然者有之焉遂寄情於此','溫庭筠','唐','唐诗','tang','','[]','寓賞本殊致，意幽非我情。',120,'全唐诗/poet.tang.32000.json','["寓賞本殊致，意幽非我情。", "吾常有流淺，外物無重輕。", "各言藝幽深，彼美香素莖。", "豈爲賞者設，自保孤根生。", "易地無赤株，麗土亦同榮。", "賞際林壑近，泛餘煙露清。", "余懷既鬱陶，爾類徒縱橫。", "妍蚩苟不信，寵辱何爲驚。", "貞隱諒無迹，激時猶揀名。", "幽叢靄綠畹，豈必懷歸耕。"]'),
('6ceade9d-e0c1-48a0-9d59-79d45e77004e','秋日','溫庭筠','唐','唐诗','tang','','[]','爽氣變昏旦，神臯徧原隰。',168,'全唐诗/poet.tang.32000.json','["爽氣變昏旦，神臯徧原隰。", "煙華久蕩搖，石澗仍清急。", "柳闇山犬吠，蒲荒水禽立。", "菊花明欲迷，棗葉光如濕。", "天籟思林嶺，車塵倦都邑。", "譸張夙所違，悔恡何由入。", "芳草秋可藉，幽泉曉堪汲。", "牧羊燒外鳴，林果雨中拾。", "復此遂閑曠，翛然脫羇縶。", "田收鳥雀喧，氣肅龍蛇蟄。", "佳節足豐穰，良朋阻遊集。", "沈機日寂寥，葆素常呼吸。", "投迹倦攸往，放懷志所執。", "良時有東菑，吾將事蓑笠。"]'),
('0bceea86-b012-4e7e-b5af-159b28704c0d','七夕','溫庭筠','唐','唐诗','tang','','[]','鳴機札札停金梭，芙蓉澹蕩生池波。',80,'全唐诗/poet.tang.32000.json','["鳴機札札停金梭，芙蓉澹蕩生池波。", "神軒紅粉陳香羅，鳳低蟬薄愁雙蛾。", "微光奕奕凌天河，鸞咽鶴唳飄颻歌。", "彎橋銷盡愁奈何，天氣駘蕩雲陂陁。", "平明花木有秋意，露濕綵盤蛛網多。"]'),
('28443bec-1873-488a-8352-3db8e3d8eb0f','酬友人','溫庭筠','唐','唐诗','tang','','[]','辭榮亦素尚，倦遊非夙心。',72,'全唐诗/poet.tang.32000.json','["辭榮亦素尚，倦遊非夙心。", "寧復思金籍，獨此臥煙林。", "閑雲無定貌，佳樹有餘陰。", "坐久芰荷發，釣闌茭葦深。", "遊魚自搖漾，浴鳥故浮沈。", "唯君清露夕，一爲灑煩襟。"]'),
('ddcca25a-868e-4f11-bb63-24215ac28e19','觀舞妓','溫庭筠','唐','唐诗','tang','','[]','朔音悲嘒管，瑤踏動芳塵。',48,'全唐诗/poet.tang.32000.json','["朔音悲嘒管，瑤踏動芳塵。", "總袖時增怨，聽破復含嚬。", "凝腰倚風軟，花題照錦春。", "朱弦固淒緊，瓊樹亦迷人。"]'),
('942a4217-2f9f-4c3e-ac53-cff400acea92','邊笳曲','溫庭筠','唐','唐诗','tang','','[]','朔管迎秋動，雕陰雁來早。',48,'全唐诗/poet.tang.32000.json','["朔管迎秋動，雕陰雁來早。", "上郡隱黃雲，天山吹白草。", "嘶馬悲寒磧，朝陽照霜堡。", "江南戍客心，門外芙蓉老。"]'),
('c35bdac8-4305-4f9f-8d9a-c3b6c7b67f7d','經西塢偶題','溫庭筠','唐','唐诗','tang','','[]','搖搖弱柳黃鸝啼，芳草無情人自迷。',64,'全唐诗/poet.tang.32000.json','["搖搖弱柳黃鸝啼，芳草無情人自迷。", "日影明滅金色鯉，杏花唼喋青頭雞。", "微紅柰蔕惹蜂粉，潔白芹芽穿燕泥。", "借問含嚬向何事，昔年曾到武陵溪。"]'),
('ff47e1b4-5f0b-4907-a612-0898411c4f5d','金虎臺','溫庭筠','唐','唐诗','tang','','[]','碧草連金虎，青苔蔽石麟。',48,'全唐诗/poet.tang.32000.json','["碧草連金虎，青苔蔽石麟。", "皓齒芳塵起，纖腰玉樹春。", "倚瑟紅鉛濕，分香翠黛嚬。", "誰言奉陵寢，相顧復沾巾。"]'),
('da47d59e-d416-4eae-a33f-7ccd0b141582','俠客行','溫庭筠','唐','唐诗','tang','','["\u5199\u4eba", "\u8c6a\u8fc8", "\u8d5e\u7f8e", "\u5199\u4eba\u8bd7"]','欲出鴻都門，陰雲蔽城闕。',36,'全唐诗/poet.tang.32000.json','["欲出鴻都門，陰雲蔽城闕。", "寶劒黯如水，微紅濕餘血。", "白馬夜頻驚，三更霸陵雪。"]'),
('2e5f3088-bc20-4b17-b0e3-610d455b16a3','詠曉','溫庭筠','唐','唐诗','tang','','[]','蟲歇紗牕靜，鴉散碧梧寒。',48,'全唐诗/poet.tang.32000.json','["蟲歇紗牕靜，鴉散碧梧寒。", "稍驚朝珮動，猶傳清漏殘。", "亂珠凝燭淚，微紅上露盤。", "褰衣復理鬢，餘潤拂芝蘭。"]'),
('88eb3cfc-8c6e-41c2-9276-7b75f38023ce','芙蓉','溫庭筠','唐','唐诗','tang','','[]','刺莖澹蕩碧，花片參差紅。',48,'全唐诗/poet.tang.32000.json','["刺莖澹蕩碧，花片參差紅。", "吳歌秋水冷，湘廟夜雲空。", "濃豔香露裏，美人青鏡中。", "南樓未歸客，一夕練塘東。"]'),
('a2ab610c-0f3a-40b0-8a23-a8c71abfa51a','勅勒歌塞北','溫庭筠','唐','唐诗','tang','','[]','敕勒金𭘵壁，陰山無歲華。',48,'全唐诗/poet.tang.32000.json','["敕勒金𭘵壁，陰山無歲華。", "帳外風飄雪，營前月照沙。", "羌兒吹玉管，胡姬踏錦花。", "却笑江南客，梅落不歸家。"]'),
('a1ff8207-ac62-40fb-a687-aaad98bb5ad9','邯鄲郭公詞','溫庭筠','唐','唐诗','tang','','[]','金笳悲故曲，玉座積深塵。',48,'全唐诗/poet.tang.32000.json','["金笳悲故曲，玉座積深塵。", "言是邯鄲伎，不見鄴城人。", "青苔竟埋骨，紅粉自傷神。", "唯有漳河柳，還向舊營春。"]'),
('692d77fb-1c84-4e00-977d-8b8069cfef5f','古意','溫庭筠','唐','唐诗','tang','','[]','莫莫復莫莫，絲蘿緣澗壑。',48,'全唐诗/poet.tang.32000.json','["莫莫復莫莫，絲蘿緣澗壑。", "散木無斧斤，纖莖得依託。", "枝低浴鳥歇，根靜懸泉落。", "不慮見春遲，空傷致身錯。"]'),
('9ddc41e1-0ecf-4e8f-a183-fd98823787d1','齊宮','溫庭筠','唐','唐诗','tang','','[]','白馬雜金飾，言從雕輦迴。',48,'全唐诗/poet.tang.32000.json','["白馬雜金飾，言從雕輦迴。", "粉香隨笑度，鬢態伴愁來。", "遠水斜如剪，青莎綠似裁。", "所恨章華日，冉冉下層臺。"]'),
('e7b9fec0-ad1b-4c86-8acf-a177a660ade6','春日','溫庭筠','唐','唐诗','tang','','[]','柳岸杏花稀，梅梁乳燕飛。',48,'全唐诗/poet.tang.32000.json','["柳岸杏花稀，梅梁乳燕飛。", "美人鸞鏡笑，嘶馬雁門歸。", "楚宮雲影薄，臺城心賞違。", "從來千里恨，邊色滿戎衣。"]'),
('2ebb92bd-fc53-4266-a78c-22b85681233f','詠春幡','溫庭筠','唐','唐诗','tang','','[]','閑庭見早梅，花影爲誰栽。',48,'全唐诗/poet.tang.32000.json','["閑庭見早梅，花影爲誰栽。", "碧煙隨刃落，蟬鬢覺春來。", "代郡嘶金勒，梵聲悲鏡臺。", "玉釵風不定，香步獨徘徊。"]'),
('68abccc3-13d8-4c8e-a56f-560371a7b114','陳宮詞','溫庭筠','唐','唐诗','tang','','[]','雞鳴人草草，香輦出宮花。',48,'全唐诗/poet.tang.32000.json','["雞鳴人草草，香輦出宮花。", "妓語細腰轉，馬嘶金面斜。", "早鶯隨綵仗，驚雉避凝笳。", "淅瀝湘風外，紅輪映曙霞。"]'),
('e4c43230-0ade-4f34-8dfc-732909a8dfd2','春日野行','溫庭筠','唐','唐诗','tang','','[]','騎馬踏煙莎，青春奈怨何。',48,'全唐诗/poet.tang.32000.json','["騎馬踏煙莎，青春奈怨何。", "蝶翎朝粉盡，鴉背夕陽多。", "柳豔欺芳帶，山愁縈翠蛾。", "別情無處說，方寸是星河。"]'),
('7d7d979a-a153-432e-898a-f2d472094796','詠嚬','溫庭筠','唐','唐诗','tang','','[]','毛羽歛愁翠，黛嬌攢豔春。',48,'全唐诗/poet.tang.32000.json','["毛羽歛愁翠，黛嬌攢豔春。", "恨容偏落淚，低態定思人。", "枕上夢隨月，扇邊歌遶塵。", "玉鉤鸞不住，波淺石磷磷。"]'),
('4cd0bdf0-f7fe-4503-93f6-0b6f9f99c103','中書令裴公挽歌詞二首 一','溫庭筠','唐','唐诗','tang','','[]','王儉風華首，蕭何社稷臣。',48,'全唐诗/poet.tang.32000.json','["王儉風華首，蕭何社稷臣。", "丹陽布衣客，蓮渚白頭人。", "銘勒燕山暮，碑沈漢水春。", "從今虛醉飽，無復汙車茵。"]'),
('e8b1f8cc-24d3-48e4-b37d-a50f2c3faa8a','中書令裴公挽歌詞二首 二','溫庭筠','唐','唐诗','tang','','[]','箭下妖星落，風前殺氣廻。',48,'全唐诗/poet.tang.32000.json','["箭下妖星落，風前殺氣廻。", "國香荀令去，樓月庾公來。", "玉璽終無慮，金縢意不開。", "空嗟薦賢路，芳草滿燕臺。"]'),
('f71d3784-4553-48dc-a21c-62d29851dd42','唐莊恪太子挽歌詞二首 一','溫庭筠','唐','唐诗','tang','','[]','疊鼓辭宮殿，悲笳降杳冥。',48,'全唐诗/poet.tang.32000.json','["疊鼓辭宮殿，悲笳降杳冥。", "影離雲外日，光滅火前星。", "鄴客瞻秦苑，商公下漢庭。", "依依陵樹色，空繞古原青。"]'),
('8a94f955-d5ad-4283-bec9-683276498157','唐莊恪太子挽歌詞二首 二','溫庭筠','唐','唐诗','tang','','[]','東府虛容衛，西園寄夢思。',48,'全唐诗/poet.tang.32000.json','["東府虛容衛，西園寄夢思。", "鳳懸吹曲夜，雞斷問安時。", "塵陌都人恨，霜郊賵馬悲。", "唯餘埋璧地，煙草近丹墀。"]'),
('20b551ac-35d4-4185-bfeb-17744c6b6e32','祕書劉尚書挽歌詞二首 一','溫庭筠','唐','唐诗','tang','','[]','王筆活鸞鳳，謝詩生芙蓉。',48,'全唐诗/poet.tang.32000.json','["王筆活鸞鳳，謝詩生芙蓉。", "學筵開絳帳，談柄發洪鐘。", "粉署見飛鵩，玉山猜臥龍。", "遺風麗清韻，蕭散九原松。"]'),
('35101887-613a-4b4c-bd6f-8a5095e35fac','祕書劉尚書挽歌詞二首 二','溫庭筠','唐','唐诗','tang','','[]','麈尾近良玉，鶴裘吹素絲。',48,'全唐诗/poet.tang.32000.json','["麈尾近良玉，鶴裘吹素絲。", "壞陵殷浩謫，春墅謝安棊。", "京口貴公子，襄陽諸女兒。", "折花兼踏月，多唱柳郎詞。"]'),
('4d182f8c-6cad-4a43-af62-d5c1e8c8c154','太子西池二首 一','溫庭筠','唐','唐诗','tang','','[]','梨花雪壓枝，鶯囀柳如絲。',48,'全唐诗/poet.tang.32000.json','["梨花雪壓枝，鶯囀柳如絲。", "嬾逐粧成曉，春融夢覺遲。", "鬢輕全作影，嚬淺未成眉。", "莫信張公子，窗間斷暗期。"]'),
('edfb62e2-c4ec-4a65-b1af-129f7a69bbfa','太子西池二首 二','溫庭筠','唐','唐诗','tang','','[]','花紅蘭紫莖，愁草雨新晴。',48,'全唐诗/poet.tang.32000.json','["花紅蘭紫莖，愁草雨新晴。", "柳占三春色，鶯偷百鳥聲。", "日長嫌輦重，風暖覺衣輕。", "薄暮香塵起，長楊落照明。"]'),
('41e2e819-270c-4ae0-acab-8ede9188a7d0','西陵道士茶歌','溫庭筠','唐','唐诗','tang','','[]','乳竇濺濺通石脉，綠塵愁草春江色。',64,'全唐诗/poet.tang.32000.json','["乳竇濺濺通石脉，綠塵愁草春江色。", "澗花入井水味香，山月當人松影直。", "仙翁白扇霜鳥翎，拂壇夜讀黃庭經。", "疎香皓齒有餘味，更覺鶴心通杳冥。"]'),
('b7b40c94-b3a2-4edc-b11c-879fa8fec0d2','過西堡塞北','溫庭筠','唐','唐诗','tang','','[]','淺草乾河闊，叢棘廢城高。',48,'全唐诗/poet.tang.32000.json','["淺草乾河闊，叢棘廢城高。", "白馬犀匕首，黑裘金佩刀。", "霜清徹兔目，風急吹鵰毛。", "一經何用厄，日暮涕沾袍。"]'),
('57eee7e4-f266-4988-a802-89e8deb2673a','送李億東歸','溫庭筠','唐','唐诗','tang','','["\u9ec4\u5c71"]','黃山遠隔秦樹，紫禁斜通渭城。',56,'全唐诗/poet.tang.32000.json','["黃山遠隔秦樹，紫禁斜通渭城。", "別路青青柳弱，前溪漠漠苔生。", "和風澹蕩歸客，落月殷勤早鶯。", "灞上金樽未飲，讌歌已有餘聲。"]'),
('53326c00-2c68-4274-84c1-8504e4aac1c6','開聖寺','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u5199\u666f"]','路分谿石夾煙叢，十里蕭蕭古樹風。',64,'全唐诗/poet.tang.32000.json','["路分谿石夾煙叢，十里蕭蕭古樹風。", "出寺馬嘶秋色裏，向陵鴉亂夕陽中。", "竹間泉落山廚靜，塔下僧歸影殿空。", "猶有南朝舊碑在，恥將興廢問休公。"]'),
('e0388b49-fa6b-481e-95b5-4f4e5185d028','贈蜀府將','溫庭筠','唐','唐诗','tang','','[]','十年分散劒關秋，萬事皆隨錦水流。',64,'全唐诗/poet.tang.32000.json','["十年分散劒關秋，萬事皆隨錦水流。", "志氣已曾明漢節，功名猶自滯吳鉤。", "鵰邊認箭寒雲重，馬上聽笳塞草愁。", "今日逢君倍惆悵，灌嬰韓信盡封侯。"]'),
('9ce2b4fd-2bd0-4e47-8742-2177fde229ad','西江貽釣叟騫生','溫庭筠','唐','唐诗','tang','','[]','晴江如鏡月如鉤，泛灩蒼茫送客愁。',64,'全唐诗/poet.tang.32000.json','["晴江如鏡月如鉤，泛灩蒼茫送客愁。", "夜淚潛生竹枝曲，春潮遙上木蘭舟。", "事隨雲去身難到，夢逐煙銷水自流。", "昨日歡娛竟何在，一枝梅謝楚江頭。"]'),
('a695e5e1-36eb-4d82-8fb6-0a52682192c4','寄清源寺僧','溫庭筠','唐','唐诗','tang','','[]','石路無塵竹徑開，昔年曾伴戴顒來。',64,'全唐诗/poet.tang.32000.json','["石路無塵竹徑開，昔年曾伴戴顒來。", "窗間半偈聞鐘後，松下殘棊送客回。", "簾向玉峰藏夜雪，砌因藍水長秋苔。", "白蓮社裹如相問，爲說遊人是姓雷。"]'),
('06a63130-0876-491f-a91c-f7d5cad85e75','重遊圭峰宗密禪師精廬','溫庭筠','唐','唐诗','tang','','[]','百尺青崖三尺墳，微言已絕杳難聞。',64,'全唐诗/poet.tang.32000.json','["百尺青崖三尺墳，微言已絕杳難聞。", "戴顒今日稱居士，支遁他年識領軍。", "暫對杉松如結社，偶同麋鹿自成羣。", "故山弟子空廻首，葱嶺唯應見宋雲。"]'),
('4d343500-66fb-42a2-a32e-97e1e3e9be71','題李處士幽居','溫庭筠','唐','唐诗','tang','','[]','水玉簪頭白角巾，瑤琴寂歷拂輕塵。',64,'全唐诗/poet.tang.32000.json','["水玉簪頭白角巾，瑤琴寂歷拂輕塵。", "濃陰似帳紅薇晚，細雨如煙碧草春。", "隔竹見籠疑有鶴，捲簾看畫靜無人。", "南山自是忘年友，谷口徒稱鄭子真。"]'),
('ac97d42b-8fef-42c9-829f-baafe89b4cdc','利州南渡','溫庭筠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u4e03\u8a00\u5f8b\u8bd7", "\u6292\u6000", "\u6e21\u6c5f", "\u5c71\u6c34"]','澹然空水對斜暉，曲島蒼茫接翠微。',64,'全唐诗/poet.tang.32000.json','["澹然空水對斜暉，曲島蒼茫接翠微。", "波上馬嘶看櫂去，柳邊人歇待船歸。", "數叢沙草羣鷗散，萬頃江田一鷺飛。", "誰解乘舟尋范蠡，五湖煙水獨忘機。"]'),
('f13425b8-aac5-4293-bd62-4ff620614a18','贈李將軍','溫庭筠','唐','唐诗','tang','','[]','誰言荀羨愛功勳，年少登壇衆所聞。',64,'全唐诗/poet.tang.32000.json','["誰言荀羨愛功勳，年少登壇衆所聞。", "曾以能書稱內史，又因明易號將軍。", "金溝故事春長在，玉軸遺文火半焚。", "不學龍驤畫山水，醉鄉無跡似閑雲。"]'),
('0340ecf4-9a26-451f-a8ac-a3cf62cc9334','寒食日作','溫庭筠','唐','唐诗','tang','','["\u5bd2\u98df\u8282"]','紅深綠暗逕相交，抱暖含芳披紫袍。',64,'全唐诗/poet.tang.32000.json','["紅深綠暗逕相交，抱暖含芳披紫袍。", "綵索平時牆婉娩，輕毬落處晚寥梢。", "窗中草色妬雞卵，盤上芹泥憎燕巢。", "自有玉樓春意在，不能騎馬度煙郊。"]'),
('2aa683db-4203-4bec-b015-a8ec37aba283','李羽處士寄新醖走筆戲酬','溫庭筠','唐','唐诗','tang','','[]','高談有伴還成藪，沈醉無期即是鄉。',64,'全唐诗/poet.tang.32000.json','["高談有伴還成藪，沈醉無期即是鄉。", "已恨流鶯欺謝客，更將浮蟻與劉郎。", "簷前柳色分張綠，窗外花枝借助香。", "所恨玳筵紅燭夜，草玄寥落近廻塘。"]'),
('470fdb98-6897-4278-b3a7-6ea6016f9627','郊居秋日有懷一二知己','溫庭筠','唐','唐诗','tang','','[]','稻田鳧雁滿晴沙，釣渚歸來一逕斜。',64,'全唐诗/poet.tang.32000.json','["稻田鳧雁滿晴沙，釣渚歸來一逕斜。", "門帶果林招邑吏，井分蔬圃屬鄰家。", "臯原寂歷垂禾穗，桑竹參差映豆花。", "自笑謾懷經濟策，不將心事許煙霞。"]'),
('a6a0618e-0935-48b1-a252-d56fa4cd55de','題友人池亭','溫庭筠','唐','唐诗','tang','','[]','月榭風亭繞曲池，粉垣廻互瓦參差。',64,'全唐诗/poet.tang.32000.json','["月榭風亭繞曲池，粉垣廻互瓦參差。", "侵簾片白搖翻影，落鏡愁紅寫倒枝。", "鸂鶒刷毛花蕩漾，鷺鷥拳足雪離披。", "山翁醉後如相憶，羽扇清樽我自知。"]'),
('2597e95e-2867-4e8c-9cca-51944484b1f3','南湖','溫庭筠','唐','唐诗','tang','','[]','湖上微風入檻涼，翻翻菱荇滿廻塘。',64,'全唐诗/poet.tang.32000.json','["湖上微風入檻涼，翻翻菱荇滿廻塘。", "野船著岸偎春草，水鳥帶波飛夕陽。", "蘆葉有聲疑霧雨，浪花無際似瀟湘。", "飄然篷艇東歸客，盡日相看憶楚鄉。"]'),
('a916dbf1-65fd-405c-b894-90a546c0ac00','贈袁司錄','溫庭筠','唐','唐诗','tang','','[]','一朝辭滿有心期，花發楊園雪壓枝。',64,'全唐诗/poet.tang.32000.json','["一朝辭滿有心期，花發楊園雪壓枝。", "劉尹故人諳往事，謝郎諸弟得新知。", "金釵醉就胡姬畫，玉管閑留洛客吹。", "記得襄陽耆舊語，不堪風景峴山碑。"]'),
('5f793728-5900-4155-b48d-4acce7ee6744','題西明寺僧院','溫庭筠','唐','唐诗','tang','','["\u5e90\u5c71"]','曾識匡山遠法師，低松片石對前墀。',65,'全唐诗/poet.tang.32000.json','["曾識匡山遠法師，低松片石對前墀。", "爲尋名畫來過院，因訪閑人得看棊。", "新雁參差雲碧處，寒鴉遼亂葉紅時。", "自知終有張華識，不向滄洲州理釣絲。"]'),
('cc9b30b9-4137-4872-a3ca-b8af7cfc36bd','偶題','溫庭筠','唐','唐诗','tang','','[]','微風和暖日鮮明，草色迷人向渭城。',64,'全唐诗/poet.tang.32000.json','["微風和暖日鮮明，草色迷人向渭城。", "吳客捲簾閑不語，楚娥攀樹獨含情。", "紅垂果蔕櫻桃重，黃染花叢蝶粉輕。", "自恨青樓無近信，不將心事許卿卿。"]'),
('2a7be2d6-34fd-4fd6-8674-c62fe2cd8fec','寄湘陰閻少府乞釣輪子','溫庭筠','唐','唐诗','tang','','[]','釣輪形與月輪同，獨繭和煙影似空。',64,'全唐诗/poet.tang.32000.json','["釣輪形與月輪同，獨繭和煙影似空。", "若向三湘逢雁信，莫辭千里寄漁翁。", "篷聲夜滴松江雨，菱葉秋傳鏡水風。", "終日垂鉤還有意，尺書多在錦鱗中。"]'),
('7fdda368-6d56-48a7-9f8b-d1a6cb5ba2fb','哭王元裕','溫庭筠','唐','唐诗','tang','','[]','聞說蕭郎逐逝川，伯牙因此絕清弦。',64,'全唐诗/poet.tang.32000.json','["聞說蕭郎逐逝川，伯牙因此絕清弦。", "柳邊猶憶青驄影，墳上俄生碧草煙。", "篋裏詩書疑謝後，夢中風貌似潘前。", "他時若到相尋處，碧樹紅樓自宛然。"]'),
('96f7caf5-2ea5-4f65-9f75-107f207dfac7','法雲寺雙檜','溫庭筠','唐','唐诗','tang','','[]','晉朝名輩此離羣，想對濃陰去住分。',64,'全唐诗/poet.tang.32000.json','["晉朝名輩此離羣，想對濃陰去住分。", "題處尚尋王內史，畫時應是顧將軍。", "長廊夜靜聲疑雨，古殿秋深影勝雲。", "一下南臺到人世，曉泉清籟更難聞。"]'),
('25f7203e-270e-4a9c-9118-39c18b3bc7b9','送陳嘏之侯官兼簡李常侍','溫庭筠','唐','唐诗','tang','','[]','縱得步兵無綠蟻，不緣句漏有丹砂。',64,'全唐诗/poet.tang.32000.json','["縱得步兵無綠蟻，不緣句漏有丹砂。", "殷勤爲報同袍友，我亦無心似海槎。", "春服照塵連草色，夜船聞雨滴蘆花。", "梅仙自是青雲客，莫羨相如却到家。"]'),
('debd689a-f10e-4069-afe8-91855547c735','春日野行','溫庭筠','唐','唐诗','tang','','[]','雨漲西塘金堤斜，碧草芊芊晴吐芽。',64,'全唐诗/poet.tang.32000.json','["雨漲西塘金堤斜，碧草芊芊晴吐芽。", "野岸明媚山芍藥，水田呌噪官蝦蟇。", "鏡中有浪動菱蔓，陌上無風飄柳花。", "何事輕橈句溪客，綠萍方好不歸家。"]'),
('3a02279d-5b32-474c-a76d-32e242e8651f','溪上行','溫庭筠','唐','唐诗','tang','','[]','綠塘漾漾煙濛濛，張翰此來情不窮。',64,'全唐诗/poet.tang.32000.json','["綠塘漾漾煙濛濛，張翰此來情不窮。", "雪羽䙰褷立倒影，金鱗撥剌跳晴空。", "風翻荷葉一向白，雨濕蓼花千穗紅。", "心羨夕陽波上客，片時歸夢釣船中。"]'),
('5654e427-74f4-42cf-b2fa-aa374e5b8ca0','投翰林蕭舍人','溫庭筠','唐','唐诗','tang','','[]','人間鵷鷺杳難從，獨恨金扉直九重。',64,'全唐诗/poet.tang.32000.json','["人間鵷鷺杳難從，獨恨金扉直九重。", "萬象晚歸仁壽鏡，百花春隔景陽鐘。", "紫微芒動詞初出，紅燭香殘誥未封。", "每過朱門愛庭樹，一枝何日許相容。"]'),
('a37dd2b9-5b29-4c37-9e0d-d5696ea354bd','春日偶作','溫庭筠','唐','唐诗','tang','','[]','西園一曲豔陽歌，擾擾車塵負薜蘿。',64,'全唐诗/poet.tang.32000.json','["西園一曲豔陽歌，擾擾車塵負薜蘿。", "自欲放懷猶未得，不知經世竟如何。", "夜聞猛雨判花盡，寒戀重衾覺夢多。", "釣渚別來應更好，春風還爲起微波。"]'),
('74a426ca-921b-49c3-bcb8-e22bb614a144','春暮宴罷寄宋壽先輩','溫庭筠','唐','唐诗','tang','','[]','斜掩朱門花外鐘，曉鶯時節好相逢。',64,'全唐诗/poet.tang.32000.json','["斜掩朱門花外鐘，曉鶯時節好相逢。", "窗間桃蘂宿粧在，雨後牡丹春睡濃。", "蘇小風姿迷下蔡，馬卿才調似臨邛。", "誰憐芳草生三徑，參佐橋西陸士龍。"]'),
('002b2c32-f2c5-4088-bce6-7b41e90fc18a','馬嵬驛','溫庭筠','唐','唐诗','tang','','[]','穆滿曾爲物外遊，六龍經此暫淹留。',64,'全唐诗/poet.tang.32000.json','["穆滿曾爲物外遊，六龍經此暫淹留。", "返魂無驗青煙滅，埋血空生碧草愁。", "香輦却歸長樂殿，曉鐘還下景陽樓。", "甘泉不復重相見，誰道文成是故侯。"]'),
('5347f8af-04ed-450b-90e1-39b677ae59f6','和道溪君別業','溫庭筠','唐','唐诗','tang','','[]','積潤初銷碧草新，鳳陽晴日帶雕輪。',64,'全唐诗/poet.tang.32000.json','["積潤初銷碧草新，鳳陽晴日帶雕輪。", "風飄弱柳平橋晚，雪點寒梅小苑春。", "屏上樓臺陳後主，鏡中金翠李夫人。", "花房透露紅珠落，蛺蝶雙飛護粉塵。"]'),
('01ac69a9-82d3-41ec-a20d-b81f338ae4b8','奉天西佛寺','溫庭筠','唐','唐诗','tang','','[]','憶昔狂童犯順年，玉虬閑暇出甘泉。',64,'全唐诗/poet.tang.32000.json','["憶昔狂童犯順年，玉虬閑暇出甘泉。", "宗臣欲舞千鈞劒，追騎猶觀七寶鞭。", "星背紫垣終埽地，日歸黃道却當天。", "至今南頓諸耆舊，猶指榛蕪作弄田。"]'),
('73e98562-ad4b-4d7c-b6a3-aa9ba7899d20','題望苑驛','溫庭筠','唐','唐诗','tang','','[]','弱柳千條杏一枝，半含春雨半垂絲。',64,'全唐诗/poet.tang.32000.json','["弱柳千條杏一枝，半含春雨半垂絲。", "景陽寒井人難到，長樂晨鐘鳥自知。", "花影至今通博望，樹名從此號相思。", "分明十二樓前月，不向西陵照盛姬。"]'),
('365ccc87-dc31-430c-9ea6-b99e955bef96','寄分司元庶子兼呈元處士','溫庭筠','唐','唐诗','tang','','[]','閉門高臥莫長嗟，水木凝暉屬謝家。',66,'全唐诗/poet.tang.32000.json','["閉門高臥莫長嗟，水木凝暉屬謝家。", "緱嶺參差殘曉雪，洛波清淺露晴沙。", "劉公春盡蕪菁色，華[廙]愁深苜蓿花。", "月榭知君還悵望，碧霄煙闊雁行斜。"]'),
('89eb81af-1a1f-4d3e-bd71-527ec7df6a3d','題柳','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u67f3\u6811", "\u7231\u60c5"]','楊柳千條拂面絲，綠煙金穗不勝吹。',64,'全唐诗/poet.tang.32000.json','["楊柳千條拂面絲，綠煙金穗不勝吹。", "香隨靜婉歌塵起，影伴嬌嬈舞袖垂。", "羌管一聲何處曲，流鶯百囀最高枝。", "千門九陌花如雪，飛過宮牆兩自知。"]'),
('6216babf-bc9e-4940-a94c-228ef1146788','和友人悼亡','溫庭筠','唐','唐诗','tang','','[]','玉貌潘郎淚滿衣，畫羅輕鬢[雨]霏微。',66,'全唐诗/poet.tang.32000.json','["玉貌潘郎淚滿衣，畫羅輕鬢[雨]霏微。", "紅蘭委露愁難盡，白馬朝天望不歸。", "寶鏡塵昏鸞影在，鈿箏弦斷雁行稀。", "春來多少傷心事，碧草侵堦粉蝶飛。"]'),
('99d510b8-68e2-409d-a0a1-3a261a88777a','李羽處士故里','溫庭筠','唐','唐诗','tang','','[]','柳不成絲草帶煙，海槎東去鶴歸天。',64,'全唐诗/poet.tang.32000.json','["柳不成絲草帶煙，海槎東去鶴歸天。", "愁腸斷處春何限，病眼開時月正圓。", "花若有情還悵望，水應無事莫潺湲。", "終知此恨銷難盡，辜負南華第一篇。"]'),
('f9247b61-367d-49e4-8872-f9c1165f080a','却經商山寄昔同行人','溫庭筠','唐','唐诗','tang','','[]','曾道逍遙第一篇，爾來無處不恬然。',64,'全唐诗/poet.tang.32000.json','["曾道逍遙第一篇，爾來無處不恬然。", "便同南郭能忘象，兼笑東林學坐禪。", "人事轉新花爛熳，客程依舊水潺湲。", "若敎猶作當時意，應有垂絲在鬢邊。"]'),
('fbafea96-0799-4aa4-8e79-ccab790e974d','池塘七夕','溫庭筠','唐','唐诗','tang','','[]','月出西南露氣秋，綺羅河漢在斜溝。',64,'全唐诗/poet.tang.32000.json','["月出西南露氣秋，綺羅河漢在斜溝。", "楊家繡作鴛鴦幔，張氏金爲翡翠鉤。", "香燭有花妨宿燕，畫屏無睡待牽牛。", "萬家砧杵三篙水，一夕橫塘似舊遊。"]'),
('89826a88-d58a-442a-8e0c-225cdea57e54','偶遊','溫庭筠','唐','唐诗','tang','','[]','曲巷斜臨一水間，小門終日不開關。',64,'全唐诗/poet.tang.32000.json','["曲巷斜臨一水間，小門終日不開關。", "紅珠斗帳櫻桃熟，金尾屏風孔雀閑。", "雲髻幾迷芳草蝶，額黃無限夕陽山。", "與君便是鴛鴦侶，休向人間覓往還。"]'),
('bc1bd77b-fcbe-4a18-9a10-c81abe36712f','寄河南杜少尹','溫庭筠','唐','唐诗','tang','','[]','十載歸來鬢未凋，玳簪珠履見常僚。',64,'全唐诗/poet.tang.32000.json','["十載歸來鬢未凋，玳簪珠履見常僚。", "豈關名利分榮路，自有才華作慶霄。", "鳥影參差經上苑，騎聲斷續過中橋。", "夕陽亭畔山如畫，應念田歌正寂寥。"]'),
('a89caac5-432b-4272-8c29-d058b56131da','贈知音','溫庭筠','唐','唐诗','tang','','[]','翠羽花冠碧樹雞，未明先向短牆啼。',64,'全唐诗/poet.tang.32000.json','["翠羽花冠碧樹雞，未明先向短牆啼。", "窗間謝女青蛾歛，門外蕭郎白馬嘶。", "星漢漸移庭竹影，露珠猶綴野花迷。", "景陽宮裏鐘初動，不語垂鞭上柳堤。"]'),
('6879701e-c949-4b63-9431-d43baa941e69','過陳琳墓','溫庭筠','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6000\u53e4"]','曾於青史見遺文，今日飄蓬過古墳。',64,'全唐诗/poet.tang.32000.json','["曾於青史見遺文，今日飄蓬過古墳。", "詞客有靈應識我，霸才無主始憐君。", "石麟埋沒藏春草，銅雀荒涼對暮雲。", "莫怪臨風倍惆悵，欲將書劒學從軍。"]'),
('a0903b2a-03fb-401a-bdee-2ccea5073e32','題崔公池舊遊','溫庭筠','唐','唐诗','tang','','[]','皎鏡方塘菡萏秋，此來重見採蓮舟。',64,'全唐诗/poet.tang.32000.json','["皎鏡方塘菡萏秋，此來重見採蓮舟。", "誰能不逐當年樂，還恐添成異日愁。", "紅豔影多風嫋嫋，碧空雲斷水悠悠。", "簷前依舊青山色，盡日無人獨上樓。"]'),
('d0401d1b-d034-4553-b059-fa4c052a32d6','回中作','溫庭筠','唐','唐诗','tang','','[]','蒼莽寒空遠色愁，嗚嗚戍角上高樓。',64,'全唐诗/poet.tang.32000.json','["蒼莽寒空遠色愁，嗚嗚戍角上高樓。", "吳姬怨思吹雙管，燕客悲歌別五侯。", "千里關山邊草暮，一星烽火朔雲秋。", "夜來霜重西風起，隴水無聲凍不流。"]'),
('a456cc8d-2cd1-41c9-9cc8-52163216510d','西江上送漁父','溫庭筠','唐','唐诗','tang','','[]','却逐嚴光向若耶，釣輪菱櫂寄年華。',64,'全唐诗/poet.tang.32000.json','["却逐嚴光向若耶，釣輪菱櫂寄年華。", "三秋梅雨愁楓葉，一夜篷舟宿葦花。", "不見水雲應有夢，偶隨鷗鷺便成家。", "白蘋風起樓船暮，江燕雙雙五兩斜。"]'),
('b7807234-8674-468f-a2d9-87f574aaf5c0','經故秘書崔監揚州南塘舊居','溫庭筠','唐','唐诗','tang','','[]','昔年曾識范安成，松竹風姿鶴性情。',64,'全唐诗/poet.tang.32000.json','["昔年曾識范安成，松竹風姿鶴性情。", "西掖曙河橫漏響，北山秋月照江聲。", "乘舟覓吏經輿縣，爲酒求官得步兵。", "千頃水流通故墅，至今留得謝公名。"]'),
('99e03e7b-8b9c-4080-8575-9b6bbd399c34','經故秘書崔監揚州南塘舊居','溫庭筠','唐','唐诗','tang','','[]','昔年曽識謝宣城，松竹風姿鶴性情。',64,'全唐诗/poet.tang.32000.json','["昔年曽識謝宣城，松竹風姿鶴性情。", "唯向舊山留月色，偶逢秋澗似琴聲。", "乗舟覔吏經輿縣，爲酒求官得步兵。", "玉柄寂寥譚客散，却尋池閣淚縱横。"]'),
('bdfe4ef8-154d-4eb9-98a8-785a11628662','七夕','溫庭筠','唐','唐诗','tang','','[]','鵲歸燕去兩悠悠，青瑣西南月似鉤。',64,'全唐诗/poet.tang.32000.json','["鵲歸燕去兩悠悠，青瑣西南月似鉤。", "天上歲時星右轉，世間離別水東流。", "金風入樹千門夜，銀漢橫空萬象秋。", "蘇小橫塘通桂檝，未應清淺隔牽牛。"]'),
('c2bc2287-eefa-487a-8469-b8697b95cf46','題韋籌博士草堂','溫庭筠','唐','唐诗','tang','','[]','玄晏先生已白頭，不隨鵷鷺狎羣鷗。',64,'全唐诗/poet.tang.32000.json','["玄晏先生已白頭，不隨鵷鷺狎羣鷗。", "元卿謝免開三徑，平仲朝歸臥一裘。", "醉後獨知殷甲子，病來猶作晉春秋。", "滄浪未濯塵纓在，野水無情處處流。"]'),
('eb60707b-7659-4c24-ad73-d0fe1d88eb62','和友人題壁','溫庭筠','唐','唐诗','tang','','[]','沖尚猶來出範圍，肯將經世作風徽。',64,'全唐诗/poet.tang.32000.json','["沖尚猶來出範圍，肯將經世作風徽。", "三台位缺嚴陵臥，百戰功高范蠡歸。", "自欲一鳴驚鶴寢，不應孤憤學牛衣。", "西州未有看棋暇，澗戶何由得掩扉。"]'),
('db92fa1d-ae7d-44ea-9939-a6180917ac91','春日將欲東歸寄新及第苗紳先輩','溫庭筠','唐','唐诗','tang','','[]','幾年辛苦與君同，得喪悲歡盡是空。',64,'全唐诗/poet.tang.32000.json','["幾年辛苦與君同，得喪悲歡盡是空。", "猶喜故人先折桂，自憐羈客尚飄蓬。", "三春月照千山道，十日花開一夜風。", "知有杏園無路入，馬前惆悵滿枝紅。"]'),
('020fd638-66f0-452d-893d-61875b0b0a54','經李徵君故居','溫庭筠','唐','唐诗','tang','','[]','露濃煙重草萋萋，樹映闌干柳拂堤。',64,'全唐诗/poet.tang.32000.json','["露濃煙重草萋萋，樹映闌干柳拂堤。", "一院落花無客醉，五更殘月有鶯啼。", "芳筵想像情難盡，故榭荒涼路已迷。", "惆悵羸驂往來慣，每經門巷亦長嘶。"]'),
('c79fd881-06c9-4678-a589-c55609a97720','送崔郎中赴幕','溫庭筠','唐','唐诗','tang','','[]','一別黔巫似斷弦，故交東去更淒然。',64,'全唐诗/poet.tang.32000.json','["一別黔巫似斷弦，故交東去更淒然。", "心遊目送三千里，雨散雲飛二十年。", "發跡豈勞天上桂，屬詞還得幕中蓮。", "相思休話長安遠，江月隨人處處圓。"]'),
('d192b2b3-174b-4270-834f-c8d1421fdc7c','經舊遊','溫庭筠','唐','唐诗','tang','','[]','珠箔金鉤對彩橋，昔年於此見嬌嬈。',64,'全唐诗/poet.tang.32000.json','["珠箔金鉤對彩橋，昔年於此見嬌嬈。", "香燈悵望飛瓊鬢，涼月慇勤碧玉簫。", "屏倚故窗山六扇，柳垂寒砌露千條。", "壞牆經雨蒼苔遍，拾得當時舊翠翹。"]'),
('35265b90-cd0b-4ddb-9c8a-014eecb21b6f','老君廟','溫庭筠','唐','唐诗','tang','','[]','紫氣氤氳捧半巖，蓮峰仙掌共巉巉。',64,'全唐诗/poet.tang.32000.json','["紫氣氤氳捧半巖，蓮峰仙掌共巉巉。", "廟前晚色連寒水，天外斜陽帶遠帆。", "百二關山扶玉座，五千文字閟瑤緘。", "自憐金骨無人識，知有飛龜在石函。"]'),
('b215d262-2d70-43d9-bd9e-b43c0eb26c0e','過五丈原','溫庭筠','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u5199\u666f", "\u548f\u53f2\u6000\u53e4"]','鐵馬雲雕久絕塵，柳陰高壓漢營春。',64,'全唐诗/poet.tang.32000.json','["鐵馬雲雕久絕塵，柳陰高壓漢營春。", "天晴殺氣屯關右，夜半妖星照渭濱。", "下國臥龍空誤主，中原逐鹿不因人。", "象牀錦帳無言語，從此譙周是老臣。"]'),
('f6ea550b-5635-4a41-ad28-e44718b6c24f','和友人傷歌姬','溫庭筠','唐','唐诗','tang','','[]','月缺花殘莫愴然，花須終發月終圓。',64,'全唐诗/poet.tang.32000.json','["月缺花殘莫愴然，花須終發月終圓。", "更能何事銷芳念，亦有濃華委逝川。", "一曲豔歌留婉轉，九原春草妬嬋娟。", "王孫莫學多情客，自古多情損少年。"]'),
('46fe9d66-3468-4e36-a6bd-987fcc04943d','山中與諸道友夜坐聞邊防不寧因示同志','溫庭筠','唐','唐诗','tang','','[]','龍砂鐵馬犯煙塵，跡近羣鷗意倍親。',64,'全唐诗/poet.tang.32000.json','["龍砂鐵馬犯煙塵，跡近羣鷗意倍親。", "風卷蓬根屯戊己，月移松影守庚申。", "韜鈐豈足爲經濟，巖壑何嘗是隱淪。", "心許故人知此意，古來知者竟誰人。"]'),
('11745c54-4dcd-4092-af49-02cfb69925d6','秘書省有賀監知章草題詩筆力遒健風尚高遠拂塵尋玩因有此作','溫庭筠','唐','唐诗','tang','','[]','越溪漁客賀知章，任達憐才愛酒狂。',96,'全唐诗/poet.tang.32000.json','["越溪漁客賀知章，任達憐才愛酒狂。", "鸂鶒葦花隨釣艇，蛤蜊菰菜夢橫塘。", "幾年涼月拘華省，一宿秋風憶故鄉。", "榮路脫身終自得，福庭迴首莫相忘。", "出籠鸞鶴歸遼海，落筆龍蛇滿壞牆。", "李白死來無醉客，可憐神彩弔殘陽。"]'),
('a64ba7b6-c02b-4962-90db-6b2277d438f8','題裴晉公林亭','溫庭筠','唐','唐诗','tang','','[]','謝傅林亭暑氣微，山丘零落閟音徽。',64,'全唐诗/poet.tang.32000.json','["謝傅林亭暑氣微，山丘零落閟音徽。", "東山終爲蒼生起，南浦虛言白首歸。", "池鳳已傳春水浴，渚禽猶帶夕陽飛。", "悠然到此忘情處，一日何妨有萬幾。"]'),
('bfa680d3-fd3c-43d1-8299-149ab2d121c5','車駕西遊因而有作','溫庭筠','唐','唐诗','tang','','[]','宣曲長楊瑞氣凝，上林狐兔待秋鷹。',32,'全唐诗/poet.tang.32000.json','["宣曲長楊瑞氣凝，上林狐兔待秋鷹。", "誰將詞賦陪雕輦，寂寞相如臥茂林。"]'),
('5ac20b52-5102-4a6f-b5a3-1673ef7c8711','傷溫德彝','溫庭筠','唐','唐诗','tang','','[]','昔年戎虜犯榆關，一敗龍城匹馬還。',32,'全唐诗/poet.tang.32000.json','["昔年戎虜犯榆關，一敗龍城匹馬還。", "侯印不聞封李廣，他人丘壟似天山。"]'),
('50f5662f-f3a3-4e72-8a0b-dda78fc55330','贈少年','溫庭筠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','江海相逢客恨多，秋風葉下洞庭波。',32,'全唐诗/poet.tang.32000.json','["江海相逢客恨多，秋風葉下洞庭波。", "酒酣夜別淮陰市，月照高樓一曲歌。"]'),
('ce7a789e-e4f6-4b0c-8be7-b08ccc404595','贈鄭徵君家匡山首春與丞相贊皇公遊止','溫庭筠','唐','唐诗','tang','','["\u5e90\u5c71"]','一拋蘭櫂逐燕鴻，曾向江湖識謝公。',32,'全唐诗/poet.tang.32000.json','["一拋蘭櫂逐燕鴻，曾向江湖識謝公。", "每到朱門還悵望，故山多在畫屏中。"]'),
('a35426ef-7a2f-430d-b6a5-c7b419cb28a3','夏中病痁作','溫庭筠','唐','唐诗','tang','','[]','山鬼揚威正氣愁，便辭珍簟襲狐裘。',32,'全唐诗/poet.tang.32000.json','["山鬼揚威正氣愁，便辭珍簟襲狐裘。", "西窗一夕悲人事，團扇無情不待秋。"]'),
('7d741600-24bd-422e-aa9c-003d158a7898','題友人居','溫庭筠','唐','唐诗','tang','','[]','盡日松堂看畫圖，綺疏岑寂似清都。',32,'全唐诗/poet.tang.32000.json','["盡日松堂看畫圖，綺疏岑寂似清都。", "若敎煙水無鷗鳥，張翰何由到五湖。"]'),
('ee8d09e5-41e5-4e09-856c-c90bd119d2d8','題李相公勅賜錦屏風','溫庭筠','唐','唐诗','tang','','[]','豐沛曾爲社稷臣，賜書名畫墨猶新。',32,'全唐诗/poet.tang.32000.json','["豐沛曾爲社稷臣，賜書名畫墨猶新。", "幾人同保山河誓，猶自栖栖九陌塵。"]'),
('d70f376f-02f0-4742-819a-09ea1f121910','蔡中郎墳','溫庭筠','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u6292\u60c5", "\u548f\u53f2\u6000\u53e4"]','古墳零落野花春，聞說中郎有後身。',32,'全唐诗/poet.tang.32000.json','["古墳零落野花春，聞說中郎有後身。", "今日愛才非昔日，莫拋心力作詞人。"]'),
('9afee2bc-4123-4e11-aace-ced5551c732d','元處士池上','溫庭筠','唐','唐诗','tang','','[]','蓼穗菱叢思蟪蛄，水螢江鳥滿煙蒲。',32,'全唐诗/poet.tang.32000.json','["蓼穗菱叢思蟪蛄，水螢江鳥滿煙蒲。", "愁紅一片風前落，池上秋波似五湖。"]'),
('dabc2faf-6bbe-4c03-9815-37986e7205df','華陰韋氏林亭','溫庭筠','唐','唐诗','tang','','[]','自有林亭不得閑，陌塵宮樹是非間。',32,'全唐诗/poet.tang.32000.json','["自有林亭不得閑，陌塵宮樹是非間。", "終南長在茅簷外，別向人間看華山。"]'),
('0adcf238-f09f-4cd1-9422-07935f0c4979','寄裴生乞釣鉤','溫庭筠','唐','唐诗','tang','','["\u592a\u6e56"]','一隨菱櫂謁王侯，深媿移文負釣舟。',32,'全唐诗/poet.tang.32000.json','["一隨菱櫂謁王侯，深媿移文負釣舟。", "今日太湖風色好，却將詩句乞魚鉤。"]'),
('7af13fb2-8c2d-46ab-ba36-b8e34ae88d12','長安春晚二首 一','溫庭筠','唐','唐诗','tang','','[]','曲江春半日遲遲，正是王孫悵望時。',32,'全唐诗/poet.tang.32000.json','["曲江春半日遲遲，正是王孫悵望時。", "杏花落盡不歸去，江上東風吹柳絲。"]'),
('d1d2ae4a-a30e-40d8-a4d2-6c5df69714b3','長安春晚二首 二','溫庭筠','唐','唐诗','tang','','[]','四方無事太平年，萬象鮮明禁火前。',32,'全唐诗/poet.tang.32000.json','["四方無事太平年，萬象鮮明禁火前。", "九重細雨惹春色，輕染龍池楊柳煙。"]'),
('bb7776cf-d5f0-4a07-83dc-a87a8c807dd4','三月十八日雪中作','溫庭筠','唐','唐诗','tang','','[]','芍藥薔薇語早梅，不知誰是豔陽才。',32,'全唐诗/poet.tang.32000.json','["芍藥薔薇語早梅，不知誰是豔陽才。", "今朝領得春風意，不復饒君雪裏開。"]'),
('40e6ddbb-746f-43ec-a57b-61741d3579c0','咸陽值雨','溫庭筠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u5199\u96e8", "\u5199\u666f", "\u96e8"]','咸陽橋上雨如懸，萬點空濛隔釣船。',32,'全唐诗/poet.tang.32000.json','["咸陽橋上雨如懸，萬點空濛隔釣船。", "還似洞庭春水色，晚雲將入岳陽天。"]'),
('8a539e5e-4148-4ae8-b2eb-81b42b25173a','彈箏人','溫庭筠','唐','唐诗','tang','','[]','天寶年中事玉皇，曾將新曲敎寧王。',32,'全唐诗/poet.tang.32000.json','["天寶年中事玉皇，曾將新曲敎寧王。", "鈿蟬金雁今零落，一曲伊州淚萬行。"]'),
('b7d50789-e0d5-4291-8014-eddf65a124df','瑤瑟怨','溫庭筠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u79bb\u522b", "\u4e03\u8a00\u7edd\u53e5", "\u95fa\u6028"]','冰簟銀牀夢不成，碧天如水夜雲輕。',32,'全唐诗/poet.tang.32000.json','["冰簟銀牀夢不成，碧天如水夜雲輕。", "雁聲遠過瀟湘去，十二樓中月自明。"]'),
('b5127877-3f72-413e-84e2-16f6314c7d70','題端正樹','溫庭筠','唐','唐诗','tang','','[]','路傍佳樹碧雲愁，曾侍金輿幸驛樓。',32,'全唐诗/poet.tang.32000.json','["路傍佳樹碧雲愁，曾侍金輿幸驛樓。", "草木榮枯似人事，綠陰寂寞漢陵秋。"]'),
('052ad12c-02a6-4aab-9c12-7288c042f99d','渭上題三首 一','溫庭筠','唐','唐诗','tang','','[]','呂公榮達子陵歸，萬古煙波遶釣磯。',32,'全唐诗/poet.tang.32000.json','["呂公榮達子陵歸，萬古煙波遶釣磯。", "橋上一通名利迹，至今江鳥背人飛。"]'),
('5379f566-4b31-4745-b607-4a0c9db2ccb6','渭上題三首 二','溫庭筠','唐','唐诗','tang','','[]','目極雲霄思浩然，風帆一片水連天。',32,'全唐诗/poet.tang.32000.json','["目極雲霄思浩然，風帆一片水連天。", "輕橈便是東歸路，不肯忘機作釣船。"]'),
('a201ba89-e924-4180-bb6a-c7234c6e5325','渭上題三首 三','溫庭筠','唐','唐诗','tang','','[]','煙水何曾息世機，暫時相向亦依依。',32,'全唐诗/poet.tang.32000.json','["煙水何曾息世機，暫時相向亦依依。", "所嗟白首磻谿叟，一下漁舟更不歸。"]'),
('62e8c1ab-86e8-4b82-9afa-22491fd8b845','經故翰林袁學士居','溫庭筠','唐','唐诗','tang','','[]','劒逐驚波玉委塵，謝安門下更何人。',32,'全唐诗/poet.tang.32000.json','["劒逐驚波玉委塵，謝安門下更何人。", "西州城外花千樹，盡是羊曇醉後春。"]'),
('882c4ec8-8fd9-44cb-a7f5-da4d500f5643','題城南杜邠公林亭','溫庭筠','唐','唐诗','tang','','[]','卓氏壚前金線柳，隋家堤畔錦帆風。',32,'全唐诗/poet.tang.32000.json','["卓氏壚前金線柳，隋家堤畔錦帆風。", "貪爲兩地分霖雨，不見池蓮照水紅。"]'),
('c16f2a83-a9c0-437e-b3ad-2789717505a0','夜看牡丹','溫庭筠','唐','唐诗','tang','','[]','高低深淺一闌紅，把火殷勤遶露叢。',32,'全唐诗/poet.tang.32000.json','["高低深淺一闌紅，把火殷勤遶露叢。", "希逸近來成嬾病，不能容易向春風。"]'),
('cb7518c4-1baf-41ca-a286-4f15f1b77cb5','宿城南亡友別墅','溫庭筠','唐','唐诗','tang','','[]','水流花落歎浮生，又伴遊人宿杜城。',32,'全唐诗/poet.tang.32000.json','["水流花落歎浮生，又伴遊人宿杜城。", "還似昔年殘夢裏，透簾斜月獨聞鶯。"]'),
('a67da702-57ba-4f4b-9f7e-dfa60e3eeb25','過分水嶺','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u63cf\u5199\u6c34", "\u5199\u6c34"]','溪水無情似有情，入山三日得同行。',32,'全唐诗/poet.tang.32000.json','["溪水無情似有情，入山三日得同行。", "嶺頭更是分頭處，惜別潺湲一夜聲。"]'),
('772ce407-979a-463b-9194-8f9c67f0d4c2','鄠杜郊居','溫庭筠','唐','唐诗','tang','','[]','槿籬芳援近樵家，壠麥青青一逕斜。',32,'全唐诗/poet.tang.32000.json','["槿籬芳援近樵家，壠麥青青一逕斜。", "寂寞遊人寒食後，夜來風雨送梨花。"]'),
('8f061ff5-50d9-40d3-95c4-c5a2bd50b4f6','題河中紫極宮','溫庭筠','唐','唐诗','tang','','[]','昔年曾伴玉真遊，每到仙宮即是秋。',32,'全唐诗/poet.tang.32000.json','["昔年曾伴玉真遊，每到仙宮即是秋。", "曼倩不歸花落盡，滿叢煙露月當樓。"]'),
('8fe8dd20-37a1-464b-99a5-bcbd7673103b','四皓','溫庭筠','唐','唐诗','tang','','[]','商於甪里便成功，一寸沈機萬古同。',32,'全唐诗/poet.tang.32000.json','["商於甪里便成功，一寸沈機萬古同。", "但得戚姬甘定分，不應真有紫芝翁。"]'),
('d065d8b2-3fd1-4a75-861b-84d334ebcf9b','贈張鍊師','溫庭筠','唐','唐诗','tang','','[]','丹溪藥盡變金骨，清洛月寒吹玉笙。',32,'全唐诗/poet.tang.32000.json','["丹溪藥盡變金骨，清洛月寒吹玉笙。", "他日隱居無訪處，碧桃花發水縱橫。"]'),
('85eda7b9-c445-4432-a693-309b4a502e5a','病中書懷呈友人','溫庭筠','唐','唐诗','tang','','[]','逸足皆先路，窮郊獨向隅。',288,'全唐诗/poet.tang.32000.json','["逸足皆先路，窮郊獨向隅。", "頑童逃廣柳，羸馬臥平蕪。", "黃卷嗟誰問，朱弦偶自娛。", "鹿鳴皆綴士，雌伏竟非夫。", "采地荒遺野，爰田失故都。", "亡羊猶博簺，牧馬倦呼盧。", "奕世參周祿，承家學魯儒。", "功庸留劒舃，銘戒在盤盂。", "經濟懷良畫，行藏識遠圖。", "未能鳴楚玉，空欲握隋珠。", "定爲魚緣木，曾因兔守株。", "五車堆縹帙，三逕闔繩樞。", "適與羣英集，將期善價沽。", "葉龍圖夭矯，燕鼠笑胡盧。", "賦分知前定，寒心畏厚誣。", "躡塵追慶忌，操劒學班輸。", "文囿陪多士，神州試大巫。", "對雖希鼓瑟，名亦濫吹竽。", "正使猜奔競，何嘗計有無。", "鎦惔虛訪覓，王霸竟揶揄。", "市義虛焚券，關譏謾棄繻。", "至言今信矣，微尚亦悲夫。", "白雪調歌響，清風樂舞雩。", "脅肩難黽勉，搔首易嗟吁。"]'),
('4591b990-c99c-4b8d-8ef3-97076a4dda8c','感舊陳情五十韻獻淮南李僕射','溫庭筠','唐','唐诗','tang','','[]','嵇紹垂髫日，山濤筮仕年。',288,'全唐诗/poet.tang.32000.json','["嵇紹垂髫日，山濤筮仕年。", "琴樽陳席上，紈綺拜牀前。", "鄰里纔三徙，雲霄已九遷。", "感深情戃怳，言發淚潺湲。", "憶昔龍圖盛，方今鶴羽全。", "桂枝香可襲，楊葉舊頻穿。", "玉籍標人瑞，金丹化地仙。", "賦成攢筆寫，歌出滿城傳。", "既矯排虛翅，將持造物權。", "萬靈思鼓鑄，羣品待陶甄。", "視草絲綸出，持綱雨露懸。", "法行黃道內，居近翠華邊。", "書迹臨湯鼎，吟聲接舜絃。", "白麻紅燭夜，清漏紫微天。", "雷電隨神筆，魚龍落彩牋。", "閑宵陪雍畤，清暑在甘泉。", "耿介非持祿，優游是養賢。", "冰清臨百粵，風靡化三川。", "委寄崇推轂，威儀壓控弦。", "梁園提彀騎，淮水換戎旃。", "照日青油濕，迎風錦帳鮮。", "黛蛾陳二八，珠履列三千。", "舞轉廻紅袖，歌愁歛翠鈿。", "滿堂開照曜，分座儼嬋娟。"]'),
('05555152-7c48-44c6-ba85-def3e3d1244c','題翠微寺二十二韻','溫庭筠','唐','唐诗','tang','','[]','邠土初成邑，虞賓竟讓王。',264,'全唐诗/poet.tang.32000.json','["邠土初成邑，虞賓竟讓王。", "乾符初得位，天弩夜收鋩。", "偃息齊三代，優游念四方。", "萬靈扶正寢，千嶂抱重岡。", "幽石歸階陛，喬柯入棟梁。", "火雲如沃雪，湯殿似含霜。", "澗籟添仙曲，巖花借御香。", "野麋陪獸舞，林鳥逐鵷行。", "鏡寫三秦色，窗搖八水光。", "問雲徵楚女，疑粉試何郎。", "蘭芷承雕輦，杉蘿入畫堂。", "受朝松露曉，頒朔桂煙涼。", "嵐濕金鋪外，溪鳴錦幄傍。", "倚絲憂漢祖，持璧告秦皇。", "短景催風馭，長星屬羽觴。", "儲君猶問豎，元老已登牀。", "鶴蓋趨平樂，雞人下建章。", "龍髯悲滿眼，螭首淚沾裳。", "疊鼓嚴靈杖，吹笙送夕陽。", "斷泉辭劒佩，昏日伴旂常。", "遺廟青蓮在，頹垣碧草芳。", "無因奏韶濩，流涕對幽篁。"]'),
('824423a3-e7e6-41f5-bf24-d0d755bd5ed7','過孔北海墓二十韻','溫庭筠','唐','唐诗','tang','','[]','撫事如神遇，臨風獨涕零。',240,'全唐诗/poet.tang.32000.json','["撫事如神遇，臨風獨涕零。", "墓平春草綠，碑折古苔青。", "珪玉埋英氣，山河孕炳靈。", "發言驚辨囿，撝翰動文星。", "蘊策期干世，持權欲反經。", "激揚思壯志，流落歎頹齡。", "惡木人皆息，貪泉我獨醒。", "輪轅無匠石，刀几有庖丁。", "碌碌迷藏器，規規守挈瓶。", "憤容凌鼎鑊，公議動朝廷。", "故國將辭寵，危邦竟緩刑。", "鈍工磨白璧，凡石礪青萍。", "揭日昭東夏，摶風滯北溟。", "後塵遵軌轍，前席詠儀型。", "木秀當憂悴，弦傷不底寧。", "矜誇遭斥鷃，光彩困飛螢。", "白羽留談柄，清風襲德馨。", "鸞凰嬰雪刃，狼虎犯雲屏。", "蘭蕙荒遺址，榛蕪蔽舊坰。", "轘轅近沂水，何事戀明庭。"]'),
('8573544b-7016-432e-9e2e-6c8f7f153de3','過華清宮二十二韻','溫庭筠','唐','唐诗','tang','','[]','憶昔開元日，承平事勝遊。',266,'全唐诗/poet.tang.32000.json','["憶昔開元日，承平事勝遊。", "貴妃專寵幸，天子富春秋。", "月白霓裳殿，風乾羯鼓樓。", "鬬雞花蔽膝，騎馬玉搔頭。", "繡轂千門妓，金鞍萬戶侯。", "薄雲欹雀扇，輕雪犯貂裘。", "過客聞韶濩，居人識冕旒。", "氣和春不覺，煙暖霽難收。", "澀浪和瓊甃，晴陽上彩斿。", "卷衣輕鬢嬾，窺鏡澹蛾羞。", "屏掩芙蓉帳，簾褰玳瑁鉤。", "重瞳分渭曲，纖手指神州。", "御案迷萱草，天袍妬石榴。", "深巖藏浴鳳，鮮隰媚潛虬。", "不料邯鄲蝨，俄成即墨牛。", "劒鋒揮太皞，旗焰拂蚩尤。", "內嬖陪行在，孤臣預坐籌。", "瑤簪遺翡翠，霜仗駐驊騮。", "豔笑雙飛斷，[香]魂一哭休。", "早梅悲蜀道，高樹隔昭丘。", "朱閣重霄近，蒼崖萬古愁。", "至今湯殿水，嗚咽縣前流。"]'),
('656586f8-3110-47aa-b23b-4f97283dbc2f','洞戶二十二韻','溫庭筠','唐','唐诗','tang','','[]','洞戶連珠網，方疏隱碧潯。',264,'全唐诗/poet.tang.32000.json','["洞戶連珠網，方疏隱碧潯。", "燭盤煙墜燼，簾壓月通陰。", "粉白仙郎署，霜清玉女砧。", "醉鄉高窈窈，棊陣靜愔愔。", "素手琉璃扇，玄髫玳瑁簪。", "昔邪看寄迹，梔子詠同心。", "樹列千秋勝，樓懸七夕鍼。", "舊詞翻白紵，新賦換黃金。", "唳鶴調蠻鼓，驚蟬應寶琴。", "舞疑繁易度，歌轉斷難尋。", "露委花相妬，風欹柳不禁。", "橋彎雙表逈，池漲一篙深。", "清蹕傳恢囿，黃旗幸上林。", "神鷹參翰苑，天馬破蹄涔。", "武庫方題品，文園有好音。", "朱莖殊菌蠢，丹桂欲蕭森。", "黼帳廻瑤席，華燈對錦衾。", "畫圖驚走獸，書帖得來禽。", "河曙秦樓映，山晴魏闕臨。", "綠囊逢趙后，青鎖見王沈。", "任達嫌孤憤，疎慵倦九箴。", "若爲南遁客，猶作臥龍吟。"]'),
('c4398517-f5ee-4157-b972-5e4d307fff37','送洛南李主簿','溫庭筠','唐','唐诗','tang','','[]','想君秦塞外，因見楚山青。',48,'全唐诗/poet.tang.32000.json','["想君秦塞外，因見楚山青。", "槲葉曉迷路，枳花春滿庭。", "祿優仍侍膳，官散得專經。", "子敬懷愚谷，歸心在翠屏。"]'),
('262a4225-0f04-4d59-9fa0-ec11b999250e','巫山神女廟','溫庭筠','唐','唐诗','tang','','[]','黯黯閉宮殿，霏霏蔭薜蘿。',48,'全唐诗/poet.tang.32000.json','["黯黯閉宮殿，霏霏蔭薜蘿。", "曉峰眉上色，春水臉前波。", "古樹芳菲盡，扁舟離恨多。", "一叢斑竹夜，環佩響如何。"]'),
('ea05a06f-93f2-4847-b699-025630d0ddb8','地肺山春日','溫庭筠','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','冉冉花明岸，涓涓水繞山。',24,'全唐诗/poet.tang.32000.json','["冉冉花明岸，涓涓水繞山。", "幾時拋俗事，來共白雲閑。"]'),
('0d09fabb-6e88-44a6-b795-0e02632c08d8','題陳處士幽居','溫庭筠','唐','唐诗','tang','','[]','松軒塵外客，高枕自蕭疎。',48,'全唐诗/poet.tang.32000.json','["松軒塵外客，高枕自蕭疎。", "雨後苔侵井，霜來葉滿渠。", "閑看鏡湖畫，秋得越僧書。", "若待前溪月，誰人伴釣魚。"]'),
('9fe7f03d-21ec-4cfe-a408-774b57b26856','握柘詞','溫庭筠','唐','唐诗','tang','','[]','楊柳縈橋綠，玫瑰拂地紅。',48,'全唐诗/poet.tang.32000.json','["楊柳縈橋綠，玫瑰拂地紅。", "繡衫金騕褭，花髻玉瓏璁。", "宿雨香潛潤，春流水暗通。", "畫樓初夢斷，曉日照湘風。"]'),
('081c823e-2f7f-4693-93cd-8ed7011bdf75','題盧處士山居','溫庭筠','唐','唐诗','tang','','["\u5199\u5c71", "\u5bfb\u8bbf", "\u5199\u666f", "\u63cf\u5199\u5c71"]','西溪問樵客，遙識楚人家。',48,'全唐诗/poet.tang.32000.json','["西溪問樵客，遙識楚人家。", "古樹老連石，急泉清露沙。", "千峰隨雨暗，一逕入雲斜。", "日暮飛鴉集，滿山蕎麥花。"]'),
('021826a4-0bde-4271-9846-d3fc0016fc32','初秋寄友人','溫庭筠','唐','唐诗','tang','','[]','閑夢正悠悠，涼風生竹樓。',48,'全唐诗/poet.tang.32000.json','["閑夢正悠悠，涼風生竹樓。", "夜琴知欲雨，曉簟覺新秋。", "獨鳥楚山遠，一蟬關樹愁。", "憑將離別恨，江外問同遊。"]'),
('51ed193a-266f-4e32-96aa-bf2c5603f610','題豐安里王相林亭二首 一','溫庭筠','唐','唐诗','tang','','[]','花竹有薄埃，嘉遊集上才。',48,'全唐诗/poet.tang.32000.json','["花竹有薄埃，嘉遊集上才。", "白蘋安石渚，紅葉子雲臺。", "朱戶雀羅設，黃門馭騎來。", "不知淮水濁，丹藕爲誰開。"]'),
('f6d43e80-e7fe-464b-a409-9bb62c9ecbe7','題豐安里王相林亭二首 二','溫庭筠','唐','唐诗','tang','','[]','偶到烏衣巷，含情更惘然。',48,'全唐诗/poet.tang.32000.json','["偶到烏衣巷，含情更惘然。", "西州曲堤柳，東府舊池蓮。", "星坼悲元老，雲歸送墨仙。", "誰知濟川檝，今作野人船。"]'),
('625e5d3b-c785-4637-8707-7c0834a288eb','早秋山居','溫庭筠','唐','唐诗','tang','','[]','山近覺寒早，草堂霜氣晴。',48,'全唐诗/poet.tang.32000.json','["山近覺寒早，草堂霜氣晴。", "樹凋窗有日，池滿水無聲。", "果落見猿過，葉乾聞鹿行。", "素琴機慮靜，空伴夜泉清。"]'),
('6cdf0ffd-f93e-494b-999b-24d56a68a7d4','和友人盤石寺逢舊友','溫庭筠','唐','唐诗','tang','','[]','楚寺上方宿，滿堂皆舊遊。',48,'全唐诗/poet.tang.32000.json','["楚寺上方宿，滿堂皆舊遊。", "月溪逢遠客，煙浪有歸舟。", "江館白蘋夜，水關紅葉秋。", "西風吹暮雨，汀草更堪愁。"]'),
('43b388ea-85c6-45ec-95e7-ed29abf9200f','送人南遊','溫庭筠','唐','唐诗','tang','','[]','送君遊楚國，江浦樹蒼然。',48,'全唐诗/poet.tang.32000.json','["送君遊楚國，江浦樹蒼然。", "沙淨有波迹，岸平多草煙。", "角悲臨海郡，月到渡淮船。", "唯以一桮酒，相思高楚天。"]'),
('8d3ce376-9b2c-4c0e-ba5a-6ef10d170e09','贈鄭處士','溫庭筠','唐','唐诗','tang','','[]','飄然隨釣艇，雲水是天涯。',48,'全唐诗/poet.tang.32000.json','["飄然隨釣艇，雲水是天涯。", "紅葉下荒井，碧梧侵古槎。", "醉收陶令菊，貧賣邵平瓜。", "更有相期處，南籬一樹花。"]'),
('9ecbcbc5-181e-4972-92ab-399fa3c662f3','江岸即事','溫庭筠','唐','唐诗','tang','','[]','水容侵古岸，峰影度青蘋。',48,'全唐诗/poet.tang.32000.json','["水容侵古岸，峰影度青蘋。", "廟竹唯聞鳥，江帆不見人。", "雀聲花外暝，客思柳邊春。", "別恨轉難盡，行行汀草新。"]'),
('190b3c15-f403-45f7-8e96-2423f0ffc989','贈隱者','溫庭筠','唐','唐诗','tang','','[]','茅堂對薇蕨，爐曖一裘輕。',48,'全唐诗/poet.tang.32000.json','["茅堂對薇蕨，爐曖一裘輕。", "醉後楚山夢，覺來春鳥聲。", "採茶溪樹綠，煮藥石泉清。", "不問人間事，忘機過此生。"]'),
('85faedaf-3758-4c8a-8eb0-276c984c1c5f','渚宮晚春寄秦地友人','溫庭筠','唐','唐诗','tang','','[]','風華已眇然，獨立思江天。',48,'全唐诗/poet.tang.32000.json','["風華已眇然，獨立思江天。", "鳧鴈野塘水，牛羊春草煙。", "秦原曉重疊，灞浪夜潺湲。", "今日思歸客，愁容在鏡懸。"]'),
('8e269048-5ec9-4dc4-b49c-f71559570c7b','碧澗驛曉思','溫庭筠','唐','唐诗','tang','','["\u6292\u60c5", "\u7f81\u65c5", "\u5199\u666f"]','香燈伴殘夢，楚國在天涯。',24,'全唐诗/poet.tang.32000.json','["香燈伴殘夢，楚國在天涯。", "月落子規歇，滿庭山杏花。"]'),
('bacfc609-2d58-4beb-a773-2bd9c5ea4248','送幷州郭書記','溫庭筠','唐','唐诗','tang','','[]','賓筵得佳客，侯印有光輝。',48,'全唐诗/poet.tang.32000.json','["賓筵得佳客，侯印有光輝。", "候騎不傳箭，迴文空上機。", "塞城收馬去，烽火射鵰歸。", "惟有嚴家瀨，回環逕草微。"]'),
('c8a0199c-bb4a-4bfb-af37-961551c9c87e','贈越僧岳雲二首 一','溫庭筠','唐','唐诗','tang','','[]','世機消已盡，巾屨亦飄然。',48,'全唐诗/poet.tang.32000.json','["世機消已盡，巾屨亦飄然。", "一室故山月，滿瓶秋澗泉。", "禪庵過微雪，鄉寺隔寒煙。", "應共白蓮客，相期松桂前。"]'),
('e4eb4f18-2098-4ab8-b5ed-0db472754d60','贈越僧岳雲二首 二','溫庭筠','唐','唐诗','tang','','[]','蘭亭舊都講，今日意如何。',48,'全唐诗/poet.tang.32000.json','["蘭亭舊都講，今日意如何。", "有樹關深院，無塵到淺莎。", "僧居隨處好，人事出門多。", "不及新春雁，年年鏡水波。"]'),
('905ad3a1-c6ad-493f-90ba-80b38fd60e57','詠山雞','溫庭筠','唐','唐诗','tang','','[]','萬壑動晴景，山禽凌翠微。',36,'全唐诗/poet.tang.32000.json','["萬壑動晴景，山禽凌翠微。", "繡翎翻草去，紅觜啄花歸。", "巢暖碧雲色，影孤清鏡輝。"]'),
('19bc5010-51a7-44da-b090-a8bcaabd0aff','清旦題採藥翁草堂','溫庭筠','唐','唐诗','tang','','[]','幽人尋藥逕，來自曉雲邊。',48,'全唐诗/poet.tang.32000.json','["幽人尋藥逕，來自曉雲邊。", "衣濕朮花雨，語成松嶺煙。", "解藤開澗戶，踏石過溪泉。", "林外晨光動，山昏鳥滿天。"]'),
('768ab03f-279d-43c3-932e-131a347eb031','商山早行','溫庭筠','唐','唐诗','tang','','["\u4e5d\u5e74\u7ea7\u4e0a\u518c(\u8bfe\u5916)", "\u601d\u4e61", "\u521d\u4e2d\u53e4\u8bd7", "\u5199\u666f"]','晨起動征鐸，客行悲故鄉。',48,'全唐诗/poet.tang.32000.json','["晨起動征鐸，客行悲故鄉。", "雞聲茅店月，人迹板橋霜。", "槲葉落山路，枳花明驛牆。", "因思杜陵夢，鳧雁滿迴塘。"]'),
('c97ea54e-f300-4992-93f2-cddbc4bb35d9','題竹谷神祠','溫庭筠','唐','唐诗','tang','','[]','蒼蒼松竹晚，一逕入荒祠。',48,'全唐诗/poet.tang.32000.json','["蒼蒼松竹晚，一逕入荒祠。", "古樹風吹馬，虛廊日照旗。", "煙煤朝奠處，風雨夜歸時。", "寂寞東湖客，空看蔣帝碑。"]'),
('6e011f26-2bac-4dfb-86b4-b3f03f851a48','途中有懷','溫庭筠','唐','唐诗','tang','','[]','驅車何日閑，擾擾路岐間。',48,'全唐诗/poet.tang.32000.json','["驅車何日閑，擾擾路岐間。", "歲暮自多感，客程殊未還。", "亭臯汝陽道，風雪穆陵關。", "臘後寒梅發，誰人在故山。"]'),
('46e5f908-806a-4bd9-9c0c-37c1aa54c794','經李處士杜城別業','溫庭筠','唐','唐诗','tang','','[]','憶昔幾遊集，今來倍歎傷。',48,'全唐诗/poet.tang.32000.json','["憶昔幾遊集，今來倍歎傷。", "百花情易老，一笑事難忘。", "白社已蕭索，青樓空豔陽。", "不閑雲雨夢，猶欲過高唐。"]'),
('59c9d0f6-8d4b-44f5-8754-65973afee477','登李羽士東樓','溫庭筠','唐','唐诗','tang','','[]','經客有餘音，他年終故林。',48,'全唐诗/poet.tang.32000.json','["經客有餘音，他年終故林。", "高樓本危睇，涼月更傷心。", "此意竟難折，伊人成古今。", "流塵其可欲，非復嬾鳴琴。"]'),
('f839af23-10a5-447c-bf07-6641576d58b6','題僧泰恭院二首 一','溫庭筠','唐','唐诗','tang','','[]','昔歲東林下，深公識姓名。',48,'全唐诗/poet.tang.32000.json','["昔歲東林下，深公識姓名。", "爾來辭半偈，空復歎勞生。", "憂患慕禪味，寂寥遺世情。", "所歸心自得，何事倦塵纓。"]'),
('75adbd27-4cda-49e3-8c53-9db3c171b1fc','題僧泰恭院二首 二','溫庭筠','唐','唐诗','tang','','[]','微生竟勞止，晤言猶是非。',48,'全唐诗/poet.tang.32000.json','["微生竟勞止，晤言猶是非。", "出門還有淚，看竹暫忘機。", "爽氣三秋近，浮生一笑稀。", "故山松菊在，終欲掩荆扉。"]'),
('664db117-12b7-4bd1-af88-4a8e5fef272a','西遊書懷','溫庭筠','唐','唐诗','tang','','[]','渭川通野戍，有路上桑乾。',48,'全唐诗/poet.tang.32000.json','["渭川通野戍，有路上桑乾。", "獨鳥青天暮，驚麏赤燒殘。", "高秋辭故國，昨日夢長安。", "客意自如此，非關行路難。"]'),
('315bc0e1-f76c-49d5-9940-b212e5f9c2ae','送人東遊','溫庭筠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u53cb\u60c5", "\u9001\u522b", "\u4e94\u8a00\u5f8b\u8bd7", "\u60dc\u522b", "\u79cb\u5929"]','荒戍落黃葉，浩然離故關。',48,'全唐诗/poet.tang.32000.json','["荒戍落黃葉，浩然離故關。", "高風漢陽渡，初日郢門山。", "江上幾人在，天涯孤櫂還。", "何當重相見，尊酒慰離顏。"]'),
('35092cbf-ff9a-4065-ae7c-bcc5945fb978','寄山中友人','溫庭筠','唐','唐诗','tang','','[]','惟昔有歸趣，今茲固願言。',48,'全唐诗/poet.tang.32000.json','["惟昔有歸趣，今茲固願言。", "嘯歌成往事，風雨坐涼軒。", "時物信佳節，歲華非故園。", "固知春草色，何意爲王孫。"]'),
('808bff5f-d76e-4621-ad83-1e5ad76038a9','偶題','溫庭筠','唐','唐诗','tang','','[]','孔雀眠高閣，櫻桃拂短簷。',48,'全唐诗/poet.tang.32000.json','["孔雀眠高閣，櫻桃拂短簷。", "畫明金冉冉，箏語玉纖纖。", "細雨無妨燭，輕寒不隔簾。", "欲將紅錦段，因夢寄江淹。"]'),
('221e44cd-103f-4531-86a3-911bd57d7f86','贈考功盧郎中','溫庭筠','唐','唐诗','tang','','[]','白首方辭滿，荆扉對渚田。',36,'全唐诗/poet.tang.32000.json','["白首方辭滿，荆扉對渚田。", "雪中無陋巷，醉後似當年。", "一笈負山藥，兩瓶攜澗泉。"]'),
('9efab7e0-e323-4420-b552-20ebc129be2d','題蕭山廟','溫庭筠','唐','唐诗','tang','','[]','故道木陰濃，荒祠山影東。',48,'全唐诗/poet.tang.32000.json','["故道木陰濃，荒祠山影東。", "杉松一庭雨，幡蓋滿堂風。", "客奠曉莎濕，馬嘶秋廟空。", "夜深池上歇，龍入古潭中。"]'),
('8248ebc9-adf3-46cb-9fcd-d38340d1d9d6','春日寄岳州從事李員外二首 一','溫庭筠','唐','唐诗','tang','','[]','苒弱樓前柳，輕空花外窗。',48,'全唐诗/poet.tang.32000.json','["苒弱樓前柳，輕空花外窗。", "蝶高飛有伴，鶯早語無雙。", "剪勝裁春字，開屏見曉江。", "從來共情戰，今日欲歸降。"]'),
('308a66a9-8104-45b9-ae17-e1ce8e425fb7','春日寄岳州從事李員外二首 二','溫庭筠','唐','唐诗','tang','','[]','從小識賓卿，恩深若弟兄。',48,'全唐诗/poet.tang.32000.json','["從小識賓卿，恩深若弟兄。", "相逢在何日，此別不勝情。", "紅粉座中客，綵斿江上城。", "尚平婚嫁累，無路逐雙旌。"]'),
('bd6fb867-ac97-4113-b61a-5c97f22cc0e7','和段少常柯古','溫庭筠','唐','唐诗','tang','','[]','稱觴慙座客，懷刺即門人。',48,'全唐诗/poet.tang.32000.json','["稱觴慙座客，懷刺即門人。", "素向寧知貴，清淡不厭貧。", "野梅江上晚，堤柳雨中春。", "未報淮南詔，何勞問白蘋。"]'),
('8278d0c0-0e30-4f1c-bc4e-614e18727ce4','海榴','溫庭筠','唐','唐诗','tang','','[]','海榴開似火，先解報春風。',48,'全唐诗/poet.tang.32000.json','["海榴開似火，先解報春風。", "葉亂裁牋綠，花宜插鬢紅。", "蠟珠攢作蔕，緗綵剪成叢。", "鄭驛多歸思，相期一笑同。"]'),
('e5f2f5d6-beac-4610-aa30-53eed85ab155','李先生別墅望僧舍寶剎因作雙韻聲','溫庭筠','唐','唐诗','tang','','[]','棲息消心象，簷楹溢豔陽。',48,'全唐诗/poet.tang.32000.json','["棲息消心象，簷楹溢豔陽。", "簾櫳蘭露落，鄰里柳林涼。", "高閣過空谷，孤竿隔古岡。", "潭廬同淡蕩，髣髴復芬芳。"]'),
('74fad94e-1b54-4559-abb1-e26eb0b20bbb','敷水小桃盛開因作','溫庭筠','唐','唐诗','tang','','[]','敷水小橋東，娟娟照露叢。',48,'全唐诗/poet.tang.32000.json','["敷水小橋東，娟娟照露叢。", "所嗟非勝地，堪恨是春風。", "二月豔陽節，一枝惆悵紅。", "定知留不住，吹落路塵中。"]'),
('7f4e8909-ce94-4b1b-8a9b-d27389580458','寄山中人','溫庭筠','唐','唐诗','tang','','[]','月中一雙鶴，石上千尺松。',48,'全唐诗/poet.tang.32000.json','["月中一雙鶴，石上千尺松。", "素琴入爽籟，山酒和春容。", "幽瀑有時斷，片雲無所從。", "何事蘇門生，攜手東南峰。"]'),
('ca789aac-36a3-487c-a9e6-3b39bbb84168','送淮陰孫令之官','溫庭筠','唐','唐诗','tang','','[]','隋堤楊柳煙，孤櫂正悠然。',48,'全唐诗/poet.tang.32000.json','["隋堤楊柳煙，孤櫂正悠然。", "蕭寺通淮戍，蕪城枕楚壖。", "魚鹽橋上市，燈火雨中船。", "故老青葭岸，先知虙子賢。"]'),
('5606b6e0-c119-4e33-8c19-df38d69cd995','宿輝公精舍','溫庭筠','唐','唐诗','tang','','[]','禪房無外物，清話此宵同。',50,'全唐诗/poet.tang.32000.json','["禪房無外物，清話此宵同。", "林彩水煙裏，澗聲[山]月中。", "橡霜諸壑霽，杉火一爐空。", "擁褐寒更徹，心知覺路通。"]'),
('57042eb4-218a-40f8-acd6-0e037080af00','旅泊新津却寄一二知己','溫庭筠','唐','唐诗','tang','','[]','維舟息行役，霽景近江村。',48,'全唐诗/poet.tang.32000.json','["維舟息行役，霽景近江村。", "併起別離恨，似聞歌吹喧。", "高林月初上，遠水霧猶昏。", "王粲平生感，登臨幾斷魂。"]'),
('6ee7cab5-a2e1-48d9-9c60-742c8b14baab','贈僧雲栖','溫庭筠','唐','唐诗','tang','','[]','麈尾與筇杖，幾年離石壇。',48,'全唐诗/poet.tang.32000.json','["麈尾與筇杖，幾年離石壇。", "梵餘林雪厚，棊罷岳鐘殘。", "開卷喜先悟，漱缾知早寒。", "衡陽寺前雁，今日到長安。"]'),
('d571587c-8ec8-4404-b621-6546fe69d982','雪夜與友生同宿曉寄近鄰','溫庭筠','唐','唐诗','tang','','[]','閉門羣動息，積雪透疎林。',48,'全唐诗/poet.tang.32000.json','["閉門羣動息，積雪透疎林。", "有客寒方覺，無聲曉已深。", "正繁聞近雁，併落起栖禽。", "寂寞寒塘路，憐君獨阻尋。"]'),
('4ec99b96-e980-4ad6-8932-b05ac8e3159c','題造微禪師院','溫庭筠','唐','唐诗','tang','','[]','夜香聞偈後，岑寂掩雙扉。',48,'全唐诗/poet.tang.32000.json','["夜香聞偈後，岑寂掩雙扉。", "照竹燈和雪，看松月到衣。", "草堂疎磬斷，江寺故人稀。", "唯憶湘南雨，春風獨鳥歸。"]'),
('e768c583-263d-4ef2-a289-6eb589747c1a','正見寺曉別生公','溫庭筠','唐','唐诗','tang','','[]','清曉盥秋水，高窗留夕陰。',48,'全唐诗/poet.tang.32000.json','["清曉盥秋水，高窗留夕陰。", "初陽到古寺，宿鳥起寒林。", "香火有良願，宦名非素心。", "靈山緣未絕，他日重來尋。"]'),
('c90e8b67-7c47-4cf0-a59e-2f94f9e4d3c8','旅次盱眙縣','溫庭筠','唐','唐诗','tang','','[]','離離麥擢芒，楚客意偏傷。',48,'全唐诗/poet.tang.32000.json','["離離麥擢芒，楚客意偏傷。", "波上旅愁起，天邊歸路長。", "孤橈投楚驛，殘月在淮檣。", "外杜三千里，誰人數雁行。"]'),
('c9ba2892-b146-41d6-a5ff-bac17b1a0538','鄠郊別墅寄所知','溫庭筠','唐','唐诗','tang','','[]','持頤望平綠，萬景集所思。',48,'全唐诗/poet.tang.32000.json','["持頤望平綠，萬景集所思。", "南塘遇新雨，百草生容姿。", "幽鳥不相識，美人如何期。", "徒然委搖蕩，惆悵春風時。"]'),
('a51fef9d-0ec6-4498-841d-f21d23a2ff96','京兆公池上作','溫庭筠','唐','唐诗','tang','','[]','稻香山色疊，平野接荒陂。',48,'全唐诗/poet.tang.32000.json','["稻香山色疊，平野接荒陂。", "蓮折舟行遠，萍多釣下遲。", "壞堤泉落處，涼簟雨來時。", "京口兵堪用，何因入夢思。"]'),
('c90a2223-1336-497d-8bd8-c1339983d7d8','盧氏池上遇雨贈同遊者','溫庭筠','唐','唐诗','tang','','[]','簟翻涼氣集，溪上潤殘棊。',48,'全唐诗/poet.tang.32000.json','["簟翻涼氣集，溪上潤殘棊。", "萍皺風來後，荷喧雨到時。", "寂寥閑望久，飄灑獨歸遲。", "無限松江恨，煩君解釣絲。"]'),
('192c9299-8208-4bdb-ba69-2dfbe5d0b8cb','題薛昌之所居','溫庭筠','唐','唐诗','tang','','[]','所得乃清曠，寂寥常掩關。',48,'全唐诗/poet.tang.32000.json','["所得乃清曠，寂寥常掩關。", "獨來春尚在，相得暮方還。", "花白風露晚，柳青街陌閑。", "翠微應有雪，窗外見南山。"]'),
('03fadb0f-d34a-4944-a2a7-c28530749011','東歸有懷','溫庭筠','唐','唐诗','tang','','[]','晴川通野陂，此地昔傷離。',48,'全唐诗/poet.tang.32000.json','["晴川通野陂，此地昔傷離。", "一去迹常在，獨來心自知。", "鷺眠茭葉折，魚靜蓼花垂。", "無限高秋淚，扁舟極路岐。"]'),
('f92767ce-8b70-4cf9-8f34-2cec0813c0a4','休澣日西掖謁所知','溫庭筠','唐','唐诗','tang','','[]','赤墀高閣自從容，玉女窗扉報曙鐘。',64,'全唐诗/poet.tang.32000.json','["赤墀高閣自從容，玉女窗扉報曙鐘。", "日麗九門青鎖闥，雨晴雙闕翠微峰。", "毫端蕙露滋仙草，琴上薰風入禁松。", "荀令鳳池春婉娩，好將餘潤變魚龍。"]'),
('40f8c0e6-e243-4712-8141-857631a8265c','博山','溫庭筠','唐','唐诗','tang','','[]','博山香重欲成雲，錦段機絲妬鄂君。',64,'全唐诗/poet.tang.32000.json','["博山香重欲成雲，錦段機絲妬鄂君。", "粉蝶團飛花轉影，彩鴛雙泳水生紋。", "青樓二月春將半，碧瓦千家日未曛。", "見說楊朱無限淚，豈能空爲路岐分。"]'),
('5ca57e47-ba4d-4302-8b70-0fcbec5b2b58','送盧處士遊吳越','溫庭筠','唐','唐诗','tang','','[]','羨君東去見殘梅，唯有王孫獨未廻。',64,'全唐诗/poet.tang.32000.json','["羨君東去見殘梅，唯有王孫獨未廻。", "吳苑夕陽明古堞，越宮春草上高臺。", "波生野水雁初下，風滿驛樓潮欲來。", "試逐漁舟看雪浪，幾多江燕荇花開。"]'),
('5f55bdd0-5ecb-461e-ae85-cd10ae7b8c66','過新豐','溫庭筠','唐','唐诗','tang','','[]','一劒乘時帝業成，沛中鄉里到咸京。',64,'全唐诗/poet.tang.32000.json','["一劒乘時帝業成，沛中鄉里到咸京。", "寰區已作皇居貴，風月猶含白社情。", "泗水舊亭春草徧，千門遺瓦古苔生。", "至今留得離家恨，雞犬相聞落照明。"]'),
('2e92c3b9-3fd6-44c7-815d-58f8b4210817','過潼關','溫庭筠','唐','唐诗','tang','','[]','地形盤屈帶河流，景氣澄明是勝遊。',64,'全唐诗/poet.tang.32000.json','["地形盤屈帶河流，景氣澄明是勝遊。", "十里曉雞關樹暗，一行寒雁隴雲愁。", "片時無事溪泉好，盡日凝眸岳色秋。", "麈尾角巾應曠望，更嗟芳靄隔秦樓。"]'),
('9595514e-8ad5-470e-8c3c-a56bd6232e40','題西平王舊賜屏風','溫庭筠','唐','唐诗','tang','','[]','曾向金扉玉砌來，百花鮮濕隔塵埃。',64,'全唐诗/poet.tang.32000.json','["曾向金扉玉砌來，百花鮮濕隔塵埃。", "披香殿下櫻桃熟，結綺樓前芍藥開。", "朱鷺已隨新鹵簿，黃鸝猶濕舊池臺。", "世間剛有東流水，一送恩波更不廻。"]'),
('fc22cdfd-916c-43ff-855e-21e682e07073','河中陪帥遊亭','溫庭筠','唐','唐诗','tang','','[]','倚闌愁立獨徘徊，欲賦慙非宋玉才。',64,'全唐诗/poet.tang.32000.json','["倚闌愁立獨徘徊，欲賦慙非宋玉才。", "滿座山光搖劒戟，繞城波色動樓臺。", "鳥飛天外斜陽盡，人過橋心倒影來。", "添得五湖多少恨，柳花飄蕩似寒梅。"]'),
('f43085b1-0c91-4976-a191-aa8bacf50eea','和趙嘏題岳寺','溫庭筠','唐','唐诗','tang','','[]','疎鐘細響亂鳴泉，客省高臨似水天。',64,'全唐诗/poet.tang.32000.json','["疎鐘細響亂鳴泉，客省高臨似水天。", "嵐翠暗來空覺潤，澗茶餘爽不成眠。", "越僧寒立孤燈外，岳月秋當萬木前。", "張邴宦情何太薄，遠公窗外有池蓮。"]'),
('cae8a893-7ae6-4824-b4c5-eada730b075f','蘇武廟','溫庭筠','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u4e03\u8a00\u5f8b\u8bd7", "\u5199\u4eba", "\u51ed\u540a\u53e4\u8ff9", "\u8d5e\u9882"]','蘇武魂銷漢使前，古祠高樹兩茫然。',64,'全唐诗/poet.tang.32000.json','["蘇武魂銷漢使前，古祠高樹兩茫然。", "雲邊雁斷胡天月，隴上羊歸塞草煙。", "廻日樓臺非甲帳，去時冠劒是丁年。", "茂陵不見封侯印，空向秋波哭逝川。"]'),
('adf12ced-258a-4890-99d4-544ec28385d4','送客偶作','溫庭筠','唐','唐诗','tang','','[]','石路荒涼接野蒿，西風吹馬利如刀。',64,'全唐诗/poet.tang.32000.json','["石路荒涼接野蒿，西風吹馬利如刀。", "小橋連驛楊柳晚，廢寺入門禾黍高。", "雞犬夕陽喧縣市，鳧鷖秋水曝城壕。", "故山有夢不歸去，官樹陌塵何太勞。"]'),
('4dccf5d6-dd4c-40ac-aefe-c9b3594cfc53','寒食前有懷','溫庭筠','唐','唐诗','tang','','[]','萬物鮮華雨乍晴，春寒寂歷近清明。',64,'全唐诗/poet.tang.32000.json','["萬物鮮華雨乍晴，春寒寂歷近清明。", "殘芳荏苒雙飛蝶，曉睡朦朧百囀鶯。", "舊侶不歸成獨酌，故園雖在有誰耕。", "悠然更起嚴灘恨，一宿東風蕙草生。"]'),
('b780c16d-05aa-40ed-95c0-e1ecaa6e433f','宿雲際寺','溫庭筠','唐','唐诗','tang','','[]','白蓋微雲一逕深，東峰弟子遠相尋。',64,'全唐诗/poet.tang.32000.json','["白蓋微雲一逕深，東峰弟子遠相尋。", "蒼苔路熟僧歸寺，紅葉聲乾鹿在林。", "高閣清香生靜境，夜堂疎磬發禪心。", "自從紫桂巖前別，不見南能直至今。"]'),
('5fce7dac-6d91-43bd-b574-299740303228','寄岳州李外郎遠','溫庭筠','唐','唐诗','tang','','[]','含嚬不語坐持頤，天遠樓高宋玉悲。',64,'全唐诗/poet.tang.32000.json','["含嚬不語坐持頤，天遠樓高宋玉悲。", "湖上殘棊人散後，岳陽微雨鳥來遲。", "早梅猶得廻歌扇，春水還應理釣絲。", "獨有袁宏正憔悴，一罇惆悵落花時。"]'),
('d2eb119c-087b-4d77-b26b-fd044cec1c62','遊南塘寄知者','溫庭筠','唐','唐诗','tang','','[]','白鳥梳翎立岸莎，藻花菱刺泛微波。',64,'全唐诗/poet.tang.32000.json','["白鳥梳翎立岸莎，藻花菱刺泛微波。", "煙光似帶侵垂柳，露點如珠落卷荷。", "楚水曉涼催客早，杜陵秋思傍蟬多。", "鎦公不信歸心切，聽取江樓一曲歌。"]'),
('f1c66a8b-b78c-4945-a3a4-7e6bd4fe643d','寄盧生','溫庭筠','唐','唐诗','tang','','[]','遺業荒涼近故都，門前堤路枕平湖。',64,'全唐诗/poet.tang.32000.json','["遺業荒涼近故都，門前堤路枕平湖。", "綠楊陰裏千家月，紅藕香中萬點珠。", "此地別來雙鬢改，幾時歸去片帆孤。", "他年猶擬金貂換，寄語黃公舊酒壚。"]'),
('891a34dc-3531-4352-b786-035b2a839eaf','春日訪李十四處士','溫庭筠','唐','唐诗','tang','','[]','花深橋轉水潺潺，甪里先生自閉關。',64,'全唐诗/poet.tang.32000.json','["花深橋轉水潺潺，甪里先生自閉關。", "看竹已知行處好，望雲空得暫時閑。", "誰言有策堪經世，自是無錢可買山。", "一局殘棊千點雨，綠萍池上暮方還。"]'),
('296bfdb7-8069-461a-9a56-8c57c891686e','宿松門寺','溫庭筠','唐','唐诗','tang','','[]','白石青崖世界分，卷簾孤坐對氛氳。',64,'全唐诗/poet.tang.32000.json','["白石青崖世界分，卷簾孤坐對氛氳。", "林間禪室春深雪，潭上龍堂夜半雲。", "落月蒼涼登閣在，曉鐘搖蕩隔江聞。", "西山舊是經行地，願漱寒缾逐領軍。"]'),
('74c30b20-ec45-4e00-8914-f6aa1e5c9b03','詠寒宵','溫庭筠','唐','唐诗','tang','','[]','寒宵何耿耿，良讌有餘姿。',96,'全唐诗/poet.tang.32000.json','["寒宵何耿耿，良讌有餘姿。", "寶靺徘徊處，熏鑪悵望時。", "曲瓊垂翡翠，斜月到罘罳。", "委墜金釭燼，闌珊玉局棊。", "話窮猶注睇，歌罷尚持頤。", "晻暖遙相屬，氛氳積所思。", "秦蛾卷衣晚，胡雁度雲遲。", "上郡歸來夢，那知錦字詩。"]'),
('69e030dd-e356-4aa7-95dd-cf812cf4794e','寄渚宮遺民弘里生','溫庭筠','唐','唐诗','tang','','[]','柳弱湖堤曲，籬疎水巷深。',120,'全唐诗/poet.tang.32000.json','["柳弱湖堤曲，籬疎水巷深。", "酒闌初促席，歌罷欲分襟。", "波月欺華燭，汀雲潤故琴。", "鏡清花並蔕，牀冷簟連心。", "荷疊平橋暗，萍稀敗舫沈。", "城頭五通鼓，窗外萬家砧。", "異縣魚投浪，當年鳥共林。", "八行香未滅，千里夢難尋。", "未肯暌良願，空期嗣好音。", "他時因詠作，猶得比南金。"]'),
('994c9cd5-93f6-447b-8d3e-9f513862f853','春盡與友人入裴氏林探漁竿','溫庭筠','唐','唐诗','tang','','[]','一逕互紆直，茅棘亦已繁。',72,'全唐诗/poet.tang.32000.json','["一逕互紆直，茅棘亦已繁。", "晴陽入荒竹，曖曖如春園。", "倚杖息慚倦，徘徊戀微暄。", "歷尋嬋娟節，翦破蒼筤根。", "地閉修莖孤，林振餘籜翻。", "適心在所好，非必尋湘沅。"]'),
('9562c01f-bf63-45ce-bdac-d15827cb13a0','春日','溫庭筠','唐','唐诗','tang','','[]','問君何所思，迢遞豔陽時。',72,'全唐诗/poet.tang.32000.json','["問君何所思，迢遞豔陽時。", "門靜人歸晚，牆高蝶過遲。", "一雙青瑣燕，千萬綠楊絲。", "屏上吳山遠，樓中朔管悲。", "寶書無寄處，香轂有來期。", "草色將林彩，相添入黛眉。"]'),
('7f16efb1-9f3b-450c-b88f-a95d65d7ddfc','洛陽','溫庭筠','唐','唐诗','tang','','[]','鞏樹先春雪滿枝，上陽宮柳囀黃鸝。',32,'全唐诗/poet.tang.32000.json','["鞏樹先春雪滿枝，上陽宮柳囀黃鸝。", "桓譚未便忘西笑，豈爲長安有鳳池。"]'),
('3f876230-ed38-4a37-bf92-95df6764ab5b','題賀知章故居疊韻作','溫庭筠','唐','唐诗','tang','','[]','廢砌翳薜荔，枯湖無菰蒲。',24,'全唐诗/poet.tang.32000.json','["廢砌翳薜荔，枯湖無菰蒲。", "老媼飽藁草，愚儒輸逋租。"]'),
('63d2442b-288b-4ae8-9ad7-bb0019891906','雨中與李先生期垂釣先後相失因作疊韻','溫庭筠','唐','唐诗','tang','','[]','隔石覓屐跡，西溪迷雞啼。',24,'全唐诗/poet.tang.32000.json','["隔石覓屐跡，西溪迷雞啼。", "小鳥擾曉沼，犂泥齊低畦。"]'),
('9b2d85ae-188b-4fe3-8d4e-aa16281d8936','春日雨','溫庭筠','唐','唐诗','tang','','[]','細雨濛濛入絳紗，湖亭寒食孟珠家。',32,'全唐诗/poet.tang.32000.json','["細雨濛濛入絳紗，湖亭寒食孟珠家。", "南朝漫自稱流品，宮體何曾爲杏花。"]'),
('40b37093-bc68-47ad-a4b4-1f26f296edab','細雨','溫庭筠','唐','唐诗','tang','','[]','憑軒望秋雨，涼入暑衣清。',48,'全唐诗/poet.tang.32000.json','["憑軒望秋雨，涼入暑衣清。", "極目鳥頻沒，片時雲復輕。", "沼萍開更歛，山葉動還鳴。", "楚客秋江上，蕭蕭故國情。"]'),
('8c96ad97-81fd-4371-8ce7-4ad5c11bc6a7','秋雨','溫庭筠','唐','唐诗','tang','','[]','雲滿鳥行滅，池涼龍氣腥。',48,'全唐诗/poet.tang.32000.json','["雲滿鳥行滅，池涼龍氣腥。", "斜飄看棊簟，疎灑望山亭。", "細響鳴林葉，圓文破沼萍。", "秋陰杳無際，平野但冥冥。"]'),
('04fa06aa-5863-441c-8573-56f2c62d25b0','春初對暮雨','溫庭筠','唐','唐诗','tang','','[]','淅瀝生叢篠，空濛泫網軒。',72,'全唐诗/poet.tang.32000.json','["淅瀝生叢篠，空濛泫網軒。", "暝姿看遠樹，春意入塵根。", "點細飄風急，聲輕入夜繁。", "雀喧爭槿樹，人靜出蔬園。", "瓦濕光先起，房深影易昏。", "不應江上草，相與滯王孫。"]'),
('7f7b3abf-38d3-483f-9088-503f71200880','雪二首 一','溫庭筠','唐','唐诗','tang','','[]','硯水池先凍，窗風酒易消。',72,'全唐诗/poet.tang.32000.json','["硯水池先凍，窗風酒易消。", "鴉聲出山郭，人跡過村橋。", "稍急方縈轉，才深未寂寥。", "細光穿暗隟，輕白駐寒條。", "草靜封還折，松攲墮復搖。", "謝莊今病眼，無意坐通宵。"]'),
('784bd231-aa8b-457b-9bdf-b75a2a079e7f','雪二首 二','溫庭筠','唐','唐诗','tang','','[]','羸驂出更慵，林寺已疎鐘。',48,'全唐诗/poet.tang.32000.json','["羸驂出更慵，林寺已疎鐘。", "踏緊寒聲澀，飛交細點重。", "圃斜人過跡，皆靜鳥行蹤。", "寂寞梁鴻病，誰人代夜舂。"]'),
('48cfd687-4d05-4e5c-b05f-d2851bb73b58','送人遊淮海','溫庭筠','唐','唐诗','tang','','[]','背檣燈色暗，宿客夢初成。',48,'全唐诗/poet.tang.32000.json','["背檣燈色暗，宿客夢初成。", "半夜竹窗雨，滿池荷葉聲。", "簟涼秋閤思，木落故山情。", "明發又愁起，桂花溪水清。"]'),
('c741f233-7243-479b-bdd6-8847445c31d7','原隰荑綠柳','溫庭筠','唐','唐诗','tang','','["\u67f3\u6811", "\u613f\u671b", "\u5199\u666f"]','逈野韶光早，晴川柳滿堤。',72,'全唐诗/poet.tang.32000.json','["逈野韶光早，晴川柳滿堤。", "拂塵生嫩綠，披雪見柔荑。", "碧玉牙猶短，黃金縷未齊。", "腰肢弄寒吹，眉意入春閨。", "預恐狂夫折，迎牽逸客迷。", "新鶯將出谷，應借一枝棲。"]'),
('17b94f10-22c9-4a1b-b823-9e6fc9d3c3cc','宿秦生山齋','溫庭筠','唐','唐诗','tang','','[]','衡巫路不同，結室在東峰。',48,'全唐诗/poet.tang.32000.json','["衡巫路不同，結室在東峰。", "歲晚得支遁，夜寒逢戴顒。", "龕燈落葉寺，山雪隔林鐘。", "行解無由發，曹溪欲施舂。"]'),
('bb28f914-c334-4c34-ba08-3ff34bfb64b8','贈楚雲上人','溫庭筠','唐','唐诗','tang','','[]','松根滿苔石，盡日閉禪關。',48,'全唐诗/poet.tang.32000.json','["松根滿苔石，盡日閉禪關。", "有伴年年月，無家處處山。", "煙波五湖遠，瓶屨一身閑。", "岳寺蕙蘭晚，幾時幽鳥還。"]'),
('f991f56e-7cd8-47bb-bbd8-142f5bd28626','宿白蓋峰寺寄僧','溫庭筠','唐','唐诗','tang','','[]','山房霜氣晴，一宿遂平生。',48,'全唐诗/poet.tang.32000.json','["山房霜氣晴，一宿遂平生。", "閤上見林影，月中聞澗聲。", "佛燈銷永夜，僧磬徹寒更。", "不學何居士，焚香爲宦情。"]'),
('40556d3f-d004-4b00-a4b1-3005145ca360','送僧東遊','溫庭筠','唐','唐诗','tang','','[]','師歸舊山去，此別已悽然。',48,'全唐诗/poet.tang.32000.json','["師歸舊山去，此別已悽然。", "燈影秋江寺，篷聲夜雨船。", "鷗飛吳市外，麟臥晉陵前。", "若到東林社，誰人更問禪。"]'),
('83d558bf-f1e8-4d53-9582-b66e1399fdfc','盤石寺留別成公','溫庭筠','唐','唐诗','tang','','[]','槲葉蕭蕭帶葦風，寺前歸客別支公。',64,'全唐诗/poet.tang.32000.json','["槲葉蕭蕭帶葦風，寺前歸客別支公。", "三秋岸雪花初白，一夜林霜葉盡紅。", "山疊楚天雲壓塞，浪遙吳苑水連空。", "悠然旅榜頻迴首，無復松窗半偈同。"]'),
('bdc41346-8038-4112-8295-c2f483cf847d','題中南佛塔寺','溫庭筠','唐','唐诗','tang','','[]','鳴泉隔翠微，千里到柴扉。',48,'全唐诗/poet.tang.32000.json','["鳴泉隔翠微，千里到柴扉。", "地勝人無慾，林昏虎有威。", "澗苔侵客屨，山雪入禪衣。", "桂樹芳陰在，還期歲晏歸。"]'),
('dbe7616f-ae91-496e-81a0-eb93bfc63854','馬嵬佛寺','溫庭筠','唐','唐诗','tang','','[]','荒雞夜唱戰塵深，五鼓雕輿過上林。',64,'全唐诗/poet.tang.32000.json','["荒雞夜唱戰塵深，五鼓雕輿過上林。", "才信傾城是真語，直敎塗地始甘心。", "兩重秦苑成千里，一炷胡香抵萬金。", "曼倩死來無絕藝，後人誰肯惜青禽。"]'),
('ed5f8328-25cf-4bfd-8dd8-307705d7e29a','清涼寺','溫庭筠','唐','唐诗','tang','','[]','黃花紅樹謝芳蹊，宮殿參差黛巘西。',64,'全唐诗/poet.tang.32000.json','["黃花紅樹謝芳蹊，宮殿參差黛巘西。", "詩閤曉窗藏雪嶺，畫堂秋水接藍溪。", "松飄晚吹摐金鐸，竹蔭寒苔上石梯。", "妙跡奇名竟何在，下方煙暝草萋萋。"]'),
('eb8064a9-c9ba-42ba-963c-1f7f747c9ba3','贈盧長史','溫庭筠','唐','唐诗','tang','','[]','移病欲成隱，扁舟歸舊居。',48,'全唐诗/poet.tang.32000.json','["移病欲成隱，扁舟歸舊居。", "地深新事少，官散故交疎。", "道直更無侶，家貧唯有書。", "東門煙水夢，非獨爲鱸魚。"]'),
('e08bdbb8-e54a-4bd5-9531-d2b58222c1ff','秋日旅舍寄義山李侍御','溫庭筠','唐','唐诗','tang','','[]','一水悠悠隔渭城，渭城風物近柴荆。',64,'全唐诗/poet.tang.32000.json','["一水悠悠隔渭城，渭城風物近柴荆。", "寒蛩乍響催機杼，旅雁初來憶弟兄。", "自爲林泉牽曉夢，不關砧杵報秋聲。", "子虛何處堪消渴，試向文園問長卿。"]'),
('14f21525-51ba-4647-bbd5-02dc3d13a209','晚坐寄友人','溫庭筠','唐','唐诗','tang','','[]','九枝燈在瑣窗空，希逸無聊恨不同。',64,'全唐诗/poet.tang.32000.json','["九枝燈在瑣窗空，希逸無聊恨不同。", "曉夢未離金夾膝，早寒先到石屏風。", "遺簪可惜三秋白，蠟燭猶殘一寸紅。", "應卷鰕簾看皓齒，鏡中惆悵見梧桐。"]'),
('8f69a26f-024c-4e4f-b56e-dee8856e849c','送渤海王子歸本國','溫庭筠','唐','唐诗','tang','','["\u8d60\u522b", "\u60dc\u522b", "\u53cb\u60c5"]','疆理雖重海，車書本一家。',48,'全唐诗/poet.tang.32000.json','["疆理雖重海，車書本一家。", "盛勳歸舊國，佳句在中華。", "定界分秋漲，開帆到曙霞。", "九門風月好，回首是天涯。"]'),
('f4baa8c3-0669-46e9-859d-2633611a64f5','送北陽袁明府','溫庭筠','唐','唐诗','tang','','[]','楚鄉千里路，君去及良晨。',48,'全唐诗/poet.tang.32000.json','["楚鄉千里路，君去及良晨。", "葦浦迎船火，茶山候吏塵。", "桑濃蠶臥晚，麥秀雉聲春。", "莫作東籬興，青雲有故人。"]'),
('3d64a360-20a5-46c6-a12d-c82b501ef489','送李生歸舊居','溫庭筠','唐','唐诗','tang','','[]','一從征戰後，故社幾人歸。',48,'全唐诗/poet.tang.32000.json','["一從征戰後，故社幾人歸。", "薄宦離山久，高談與世稀。", "夕陽當板檻，春日入柴扉。", "莫却嚴灘意，西溪有釣磯。"]'),
('3f2691fb-476e-4196-9386-4d5a96b0fd77','早春滻水送友人','溫庭筠','唐','唐诗','tang','','[]','青門煙野外，渡滻送行人。',48,'全唐诗/poet.tang.32000.json','["青門煙野外，渡滻送行人。", "鴨臥溪沙暖，鳩鳴社樹春。", "殘波青有石，幽草綠無塵。", "楊柳東風裏，相看淚滿巾。"]'),
('03917a86-15d2-4079-97f3-64c7a551309c','送襄州李中丞赴從事','溫庭筠','唐','唐诗','tang','','[]','漢庭文采有相如，天子通宵愛子虛。',64,'全唐诗/poet.tang.32000.json','["漢庭文采有相如，天子通宵愛子虛。", "把釣看棊高興盡，焚香起草宦情疎。", "楚山重疊當歸路，溪月分明到直廬。", "江雨瀟瀟帆一片，此行誰道爲鱸魚。"]'),
('8b873a38-bd0c-4ef0-bc59-22e6e48ca9fb','江上別友人','溫庭筠','唐','唐诗','tang','','[]','秋色滿葭菼，離人西復東。',48,'全唐诗/poet.tang.32000.json','["秋色滿葭菼，離人西復東。", "幾年方暫見，一笑又難同。", "地勢蕭陵歇，江聲禹廟空。", "如何暮灘上，千里逐征鴻。"]'),
('2f236e58-0f26-4c27-ad5f-112c7368d6e1','與友人別','溫庭筠','唐','唐诗','tang','','[]','半醉別都門，含悽上古原。',48,'全唐诗/poet.tang.32000.json','["半醉別都門，含悽上古原。", "晚風楊葉社，寒食杏花村。", "薄暮牽離緒，傷春憶晤言。", "年芳本無限，何況有蘭孫。"]'),
('37ab3386-92d1-4156-be01-3c69ed11cec1','鴻臚寺有開元中錫宴堂樓臺池沼雅爲勝絕荒涼遺址僅有存者偶成四十韻','溫庭筠','唐','唐诗','tang','','[]','明皇昔御極，神聖垂耿光。',288,'全唐诗/poet.tang.32000.json','["明皇昔御極，神聖垂耿光。", "沈機發雷電，逸躅陵堯湯。", "西覃積石山，北至窮髮鄉。", "四凶有獬豸，一臂無螳螂。", "嬋娟得神豔，郁烈聞國香。", "紫縧鳴羯鼓，玉管吹霓裳。", "祿山未封侯，林甫才爲郎。", "昭融廓日月，妥帖安紀綱。", "羣生到壽域，百辟趨明堂。", "四海正夷宴，一塵不飛揚。", "天子自猶豫，侍臣宜樂康。", "軋然閶闔開，赤日生扶桑。", "玉砌露盤紆，金壺漏丁當。", "劒佩相擊觸，左右隨趨蹌。", "玄珠十二旒，紅粉三千行。", "顧盻生羽翼，叱嗟廻雪霜。", "神霞凌雲閣，春水驪山陽。", "盤鬬九子糭，甌擎五雲漿。", "雙瓊京兆博，七鼓邯鄲娼。", "毰毸碧雞鬬，蘢葱翠雉場。", "杖官繡蔽膝，寶馬金鏤錫。", "椒塗隔鸚鵡，柘彈驚鴛鴦。", "猗歟華國臣，鬢髪俱蒼蒼。", "錫宴得幽致，車從真煒煌。"]'),
('e8c89cff-2211-4098-a95a-ab1393babc17','訪知玄上人遇暴經因有贈','溫庭筠','唐','唐诗','tang','','[]','縹帙無塵滿畫廊，鍾山弟子靜焚香。',64,'全唐诗/poet.tang.32000.json','["縹帙無塵滿畫廊，鍾山弟子靜焚香。", "惠能未肯傳心法，張湛徒勞與眼方。", "風颺檀煙銷篆印，日移松影過禪牀。", "客兒自有翻經處，江上秋來蕙草荒。"]');
